(3, 'RBI Assistant', 'rbi-assistant', 'assets/img/others/exam_695db18f66aa8.png', 'Target RBI Grade B and Assistant exams with our specialized study plans.', '<p>Reserve Bank of India (RBI) recruitment is highly prestigious. We offer comprehensive coaching for RBI Grade B Officer and RBI Assistant posts.</p>', '', '', '', 2, 1, '2026-01-07 00:55:19', '2026-01-07 06:34:02'),
(6, 'SSC CGL', 'best-coaching-for-bank-ssc-cgl', 'assets/img/others/exam_695db35763d78.png', 'Excel in SSC CGL, CHSL, and other government service exams.', '<p>Staff Selection Commission (SSC) recruits for various Group B and Group C posts. Our course focuses on CGL (Combined Graduate Level) and CHSL (Combined Higher Secondary Level).</p>', '', '', '', 5, 1, '2026-01-07 00:55:19', '2026-01-07 07:22:21'),
(7, 'SBI Clerk', 'sbi-clerk', 'assets/img/others/exam_695e19fec517a.png', 'Recruitment of Junior Associates (Customer Support & Sales) in State Bank of India.', '<p>The SBI Clerk exam is conducted annually by the State Bank of India to recruit Junior Associates (Customer Support and Sales) in its various branches across the country.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-07 08:31:58'),
(8, 'SBI SO', 'sbi-so', 'assets/img/others/exam_695e19f3beabf.png', 'State Bank of India Specialist Officer.', '<p>Recruitment for Specialist Officers in various domains.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-22 11:59:54'),
(9, 'RBI Grade \'B\' Officer', 'rbi-grade-b-officer', 'assets/img/others/exam_695e263607043.png', 'Direct recruitment of Officers in Grade B (General).', '<p>RBI Grade B is a highly prestigious exam conducted by the Reserve Bank of India.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-07 09:24:06'),
(10, 'IBPS Clerk', 'ibps-bank-clerk-coaching-in-chandigarh', 'assets/img/others/exam_695e29d21d7c8.png', 'Common Recruitment Process for Clerical Cadre in Participating Banks.', '<p>IBPS Clerk exam is conducted for recruitment of clerks in public sector banks.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-07 09:40:09'),
(11, 'IBPS PO', 'ibps-po', 'assets/img/others/exam_695e2e15aa087.png', 'Common Recruitment Process for Probationary Officers/Management Trainees.', '<p>IBPS PO is a gateway to a career as a Probationary Officer in public sector banks.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-07 09:57:41'),
(12, 'IBPS SO', 'ibps-so', 'assets/img/others/exam_695f9c68742f7.png', 'Common Recruitment Process for Specialist Officers.', '<p>Recruitment of Specialist Officers (IT, Agriculture, Law, HR, Marketing, etc.).</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-08 12:00:40'),
(15, 'SSC CHSL', 'ssc-chsl', 'assets/img/others/exam_697b1e2ba4b62.png', 'Combined Higher Secondary (10+2) Level Examination.', '<p>Recruitment for lower division clerks, postal assistants, etc.</p>', '', '', '', 0, 1, '2026-01-07 07:41:20', '2026-01-29 08:45:31'),
(17, 'IBPS RRBs (REGIONAL RURAL BANKS)', 'ibps-rrbs-regional-rural-banks', 'assets/img/others/exam_695fac76cfc4a.png', '', '', '', '', '', 0, 1, '2026-01-08 13:09:10', '2026-01-09 03:26:29'),
(19, 'SBI PO', 'sbi-po', 'assets/img/others/exam_69721454dba28.png', 'State Bank of India Probationary  Officer.', '<p>Recruitment for Probationary&nbsp; Officers in various domains.</p>', '', '', '', 0, 1, '2026-01-22 12:05:08', '2026-01-22 12:15:42');

