kground-color: rgb(250, 250, 250);\">Nationality</h3><h5 class=\"bluc pb20\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-bottom: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">A candidate must be a citizen/subject of either India/Nepal/Bhutan/a person of Indian origin who has migrated from Pakistan, Burma, Sri Lanka, East African Countries of Kenya, Uganda, the United Republic of Tanzania (Formerly Tanganyika and Zanzibar), Zambia, Malawi, Zaire, Ethiopia and Vietnam to permanently settle in India.</p></h5><br>', 2, '2026-01-07 07:13:16', '2026-02-18 07:49:25');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(17, 6, 'Exam Pattern', '<h2 id=\"C4NNBK6J6YGNTMRJUPN3JRQXM4PAO3NL\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">SSC CGL&nbsp; Exam Pattern</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The Staff Selection Commission (SSC) has revised the Combined Graduate Level (CGL) Exam pattern. The Examination will be conducted in 2 tiers as indicated below:</p><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><table style=\"width: 892px;\"><tbody><tr><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 131.825px;\"><span style=\"font-weight: bolder;\">Tier</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 632.537px;\"><span style=\"font-weight: bolder;\">Type</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 126.838px;\"><span style=\"font-weight: bolder;\">Mode</span></td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 131.825px;\">Tier – I (Qualifying)</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 632.537px;\">Objective Multiple Choice</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 126.838px;\">Computer-Based (online)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 131.825px;\">Tier – II (Paper I, II)</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 632.537px;\">Paper I (Compulsory for all posts),<br>Paper II for candidates who apply for the posts of Junior Statistical Officer (JSO) in the Ministry of Statistics and Programme Implementation</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 126.838px;\">Computer-Based (online)</td></tr></tbody></table></figure><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">Before beginning the Staff Selection Commission Combined Graduate Level preparation, it is important to make note of changes in the exam pattern and syllabus. The modifications to the SSC CGL Exam Pattern for Tier 1 &amp; 2 are given below:</p></h5><h2 id=\"IVULPPB4C2V6FUQD92PRAA74YF80ANCJ\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">SSC CGL&nbsp; Exam Centres</h2><h2 id=\"E0WAUARINFAGVV5ETU2IDXEPNHCJX70K\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify;\">SSC will be conducting the SSC CGL exam across the country in different centers. You can choose your nearest exam centre while filling out the application form. The examination center of a candidate will be mentioned on the admit card, which will be released one week before the examination. The list of online examination centres is given below:</p><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-size: 16px;\"><table style=\"width: 892px;\"><tbody><tr><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">Examination Centers</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">SSC Regions and States</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">Address of the Regional Offices/ Website</span></td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Agra, Allahabad, Bareilly, Gorakhpur, Kanpur, Lucknow, Meerut, Varanasi, Bhagalpur, Muzaffarpur, Patna</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Central Region (CR)/ Bihar and Uttar Pradesh</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (CR), Staff Selection Commission, 21-23, Lowther Road, Allahabad, Uttar Pradesh-211002. (http://www.ssc-cr.org)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Gangtok, Ranchi, Barasat, Berhampore (WB), Chinsurah, Jalpaiguri, Kolkata, Malda, Midnapur, Siliguri, Berhampore(Odisha), Bhubaneshwar, Cuttack, Keonjhargarh, Sambalpur, Port Blair</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Eastern Region (ER)/ Andaman &amp; Nicobar Islands, Jharkhand, Odisha, Sikkim and West Bengal</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (ER), Staff Selection Commission, 1st MSO Building,(8th Floor), 234/4, Acharya Jagadish Chandra Bose Road, Kolkata, West Bengal-700020 (www.sscer.org)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; text-align: justify;\">Bangalore, Dharwar, Gulbarga, Mangalore, Mysore, Kochi, Kozhikode(Calicut),</p><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; text-align: justify;\">Thiruvananthapuram, Thrissur</p></td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Karnataka, Kerala Region (KKR)/ Lakshadweep, Karnataka and Kerala</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (KKR), Staff Selection Commission, 1st Floor, “E” Wing, Kendriya Sadan, Koramangala, Bengaluru, Karnataka-560034 (www.ssckkr.kar.nic.in)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Bhopal, Chindwara, Guna, Gwalior, Indore, Jabalpur, Khandwa, Ratlam, Satna, Sagar, Ambikapur, Bilaspur Jagdalpur, Raipur, Durg</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Madhya Pradesh Sub-Region (MPR)/ Chhattisgarh and Madhya Pradesh</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Dy. Director (MPR), Staff Selection Commission, J-5, Anupam Nagar, Raipur, Chhattisgarh-492007 (www.sscmpr.org)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; text-align: justify;\">Almora, Dehradun, Haldwani, Srinagar</p><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; text-align: justify;\">(Uttarakhand), Haridwar, Delhi, Ajmer, Alwar, Bharatpur, Bikaner, Jaipur, Jodhpur, Kota, Sriganganagar, Udaipur</p></td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Northern Region (NR)/ NCT of Delhi, Rajasthan and Uttarakhand</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (NR), Staff Selection Commission, Block No. 12, CGO Complex, Lodhi Road, New Delhi-110003 (www.sscnr.net.in)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Anantnag, Baramulla, Jammu, Leh, Rajouri, Srinagar(J&amp;K), Kargil, Dodda, Hamirpur, Shimla, Bhathinda, Jalandhar, Patiala, Amritsar, Chandigarh</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">North Western Sub-Region (NWR)/ Chandigarh, Haryana, Himachal Pradesh, Jammu and Kashmir and Punjab</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Dy. Director (NWR), Staff Selection Commission, Block No. 3, Ground Floor, Kendriya Sadan, Sector-9, Chandigarh 160009 (www.sscnwr.org)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Guntur, Kurnool, Rajahmundry, Tirupati, Vishakhapatnam, Vijaywada, Chennai, Coimbatore, Madurai, Tiruchirapalli, Tirunelveli, Puducherry, Hyderabad, Nizamabad, Warangal</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Southern Region (SR)/ Andhra Pradesh, Puducherry, Tamil Nadu and Telangana.</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (SR), Staff Selection Commission, 2nd Floor, EVK Sampath Building, DPI Campus, College Road, Chennai, Tamil Nadu-600006 (www.sscsr.gov.in)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Ahmedabad, Vadodara, Rajkot, Surat, Bhavnagar, Kutch, Amravati, Aurangabad, Kolhapur, Mumbai, Nagpur, Nanded, Nashik, Pune, Thane, Bhandara, Chandrapur, Akola, Jalgaon, Ahmednagar, Alibaug, Panaji</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Western Region (WR)/ Dadra and Nagar Haveli, Daman and Diu, Goa, Gujarat and Maharashtra</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (WR), Staff Selection Commission,1st Floor, South Wing, Pratishtha Bhawan, 101, Maharshi Karve Road, Mumbai, Maharashtra-400020 (www.sscwr.net)</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Itanagar, Dibrugarh, Guwahati(Dispur), Jorhat, Silchar, Kohima, Shillong, Imphal, Churachandpur, Ukhrul, Agartala, Aizwal</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">North Eastern Region (NER)/ Arunachal Pradesh, Assam, Manipur, Meghalaya, Mizoram, Nagaland and Tripura.</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Regional Director (NER), Staff Selection Commission, Housefed Complex, Last Gate-Basistha Road, P. O. Assam Sachivalaya, Dispur, Guwahati, Assam781006 (www.sscner.org.in)</td></tr></tbody></table></figure></h2><br><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"></h5>', 4, '2026-01-07 07:19:56', '2026-02-18 07:49:45');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(18, 6, 'Exam Syllabus', '<h2 id=\"E0WAUARINFAGVV5ETU2IDXEPNHCJX70K\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">SSC CGL&nbsp; Syllabus</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The major sections asked in the SSC CGL Preliminary Exam are General Awareness, Reasoning, Quantitative Aptitude and English Language. The syllabus overview of the SSC CGL Tier-1 exam is given below.</p><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><table style=\"width: 892px;\"><tbody><tr><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 278.413px;\"><span style=\"font-weight: bolder;\">General Intelligence and Reasoning</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 225.212px;\"><span style=\"font-weight: bolder;\">General Awareness/ GK</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 185.962px;\"><span style=\"font-weight: bolder;\">Quantitative Aptitude</span></td><td style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 201.613px;\"><span style=\"font-weight: bolder;\">English Comprehension</span></td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 278.413px;\">Classification</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 225.212px;\">Static General Knowledge<br>(Indian History, Culture etc.)</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 185.962px;\">Simplification</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 201.613px;\">Reading Comprehension</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 278.413px;\">Analogy</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 225.212px;\">Science</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; pa