INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(37, 9, 'Exam Syllabus', '<h2 id=\"S6KN38L8TVQGNS599O05WY7DCY7SX6TA\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; font-family: Lato, sans-serif; color: rgb(0, 0, 0); display: inline-block; width: 892px; background-color: rgb(250, 250, 250);\">RBI Grade B&nbsp; Syllabus</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; color: rgb(0, 0, 0); font-size: 16px; line-height: 24px; text-align: justify; font-family: Lato, sans-serif;\">The&nbsp;<span style=\"text-align: center;\">RBI Grade B Syllabus</span>&nbsp;for the prelims exam is similar to the other Bank Exams. The major sections from which the questions are asked are:</p><ol style=\"color: rgb(68, 68, 68); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><li>Reasoning</li><li>Quantitative Aptitude</li><li>General Awareness and</li><li>English Language</li></ol><figure class=\"table\" style=\"--bs-table-color: #212529; --bs-table-bg: transparent; --bs-table-border-color: #dee2e6; --bs-table-accent-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); margin-bottom: 1rem; font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><table style=\"width: 892px;\"><tbody><tr><td colspan=\"4\" style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(99, 97, 107); background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">RBI Grade B Exam Syllabus</span></td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><span style=\"font-weight: bolder;\">English</span></td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><span style=\"font-weight: bolder;\">Quantitative Aptitude</span></td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><span style=\"font-weight: bolder;\">Reasoning</span></td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\"><span style=\"font-weight: bolder;\">General Awareness</span></td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Grammar</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Mensuration</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Puzzles</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Banking &amp; Financial Awareness</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Vocabulary</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Time and Work</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Seating Arrangement</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Monetary Policies</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Error Spotting</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Average, Ratio, Percentages</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Directions and Distance</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Economic Terms</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Comprehension</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Speed, Distance and Time</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Data Sufficiency</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); font-size: 14px; line-height: 22px;\"><font color=\"#000000\"><span style=\"background-color: rgb(255, 255, 255);\">Current Affairs</span></font></td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Passage Making</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Mixture and Allegations</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Blood Relations</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Financial &amp; Economics News</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Jumble Words</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Permutation and Combination</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Syllogism</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Static GK</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Fill in the Blanks</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Data Interpretation</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Coding-Decoding</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Government Schemes, Agreement &amp; Deals</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Sentence Framing</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Probability</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Inequality</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Banking terms, rates, processes</td></tr></tbody></table></figure></h5><h2 id=\"F12LKO1O0X9E0WU20WH528KLS662PFC9\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; font-family: Lato, sans-serif; color: rgb(0, 0, 0); display: inline-block; width: 892px; background-color: rgb(250, 250, 250);\">RBI Grade B&nbsp; Salary Structure</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The Pay Scale for the RBI Grade B Officer is&nbsp;<span style=\"font-weight: bolder;\">Rs. 78450-4050(9)-114900-EB 4050(2)-123000-4650(4)- 141600 (16years).</span>&nbsp;This means that you will be having basic pay of Rs. 78,450/- in which you will get an increment of Rs. 4050/- up to nine years of your service. After the completion of nine years, you will get into the executive band wherein the basic pay will be Rs. 114900/- and then again for the next two years you will get an increment of Rs. 4050/- and further an increment of Rs. 4650/- for the following 4 years thus ending up with the basic pay of Rs. 141600/- and this is when you don\'t get any promotion.&nbsp;<span style=\"font-weight: bolder;\">Apart from the Basic Pay, multiple emoluments such as Dearness Allowance, House Rent Allowance, Family Allowance, Telephone Allowance, Conveyance Allowance etc. will also be provided.</span></p><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\"><br></p><ul style=\"padding-left: 2rem; margin-bottom: 1rem; color: rgb(68, 68, 68); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><li><span style=\"font-weight: bolder;\">Which pays more, SBI or RBI?</span><br>The RBI Grade B salary is significantly higher than the SBI PO salary. SBI PO\'s gross salary is around Rs. 94,000–Rs. 98,000 monthly, while a Grade B officer\'s is approximately Rs. 1,50,374/- per month.</li></ul></h5><h2 id=\"YNEANY2TU55YUX0UQ2UC9IU97KS6TD9A\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; font-family: Lato, sans-serif; color: rgb(0, 0, 0); display: inline-block; width: 892px; background-color: rgb(250, 250, 250);\">RBI Grade B&nbsp; Application Form</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; margin-block-end: 1em; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The online application process for the RBI Grade B&nbsp; Exam will begin after the release of the official notification. The candidates must submit their online application forms to register themselves by visiting https://opportunities.rbi.org.in within the stipulated time period.&nbsp;</p></h5><h2 id=\"MOY1R0T68GLUGQCAA0POU4CWIABP85RN\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; font-family: Lato, sans-serif; color: rgb(0, 0, 0); display: inline-block; width: 892px; background-color: rgb(250, 250, 250);\">RBI Grade B Application Fees</h2><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">A total of Rs. 850/- is the application fee to be paid by candidates belonging to the General and OBC Categories. The same amount is reduced to Rs. 100/- for candidates belonging to SC/ST/PWD Category.</p><figure class=\"table\" style=\"--bs-table-color: #212529; --bs-table-bg: transparent; --bs-table-border-color: #dee2e6; --bs-table-accent-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); margin-bottom: 1rem; font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><table style=\"width: 892px;\"><tbody><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(99, 97, 107); background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">Category</span></td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(99, 97, 107); background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px;\"><span style=\"font-weight: bolder;\">Application Fee</span></td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">General/OBC</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Rs. 850/- + 18% GST</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">SC/ST/PWD</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Rs. 100/- + 18% GST</td></tr><tr><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Staff@RBI</td><td style=\"padding-right: 5px; padding-left: 5px; border-color: rgb(64, 64, 64); background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">Nil</td></tr></tbody></table></figure></h5><h3 style=\"line-height: 1.2; font-size: 1.75rem; font-family: Lato, sans-serif; color: rgb(68, 68, 68); background-color: rgb(250, 250, 250);\">Steps to Apply for RBI Grade B Recruitment&nbsp;</h3><h5 class=\"pt20 bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; color: rgb(0, 39, 87); font-size: 1.25rem; padding-top: 20px;\"><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">Candidates have to submit their application forms online at www.rbi.org.in along with the required educational documents, experience proof and photographs. Follow the below easy steps to apply for the RBI Grade B&nbsp; Exam-</p><ol style=\"color: rgb(68, 68, 68); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><li>Visit the official page of the Reserve Bank of India (RBI) at https://www.rbi.org.in/.</li><li>Scroll down and click on “Opportunities@RBI”, then a new page with url https://opportunities.rbi.org.in opens.</li><li>Now click on “Current Vacancies” &gt;&gt; “Vacancies”.</li><li>Search for “Direct Recruitment for the post of Officers in Grade ‘B’ (Direct Recruit-DR) (General/DEPR/DSIM) Streams- Panel Year ”.</li><li>Now click on “Online Application” and start with the registration process by filling out the application.</li><li>Afterwards, attach the required documents and pay the requisite application fee.</li><li>Download and keep the application form safe for future reference.</li></ol></h5>', 4, '2026-01-07 07:41:20', '2026-01-29 11:18:43');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(40, 3, 'HOME', '<p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The RBI Assistant Exam is conducted by the Reserve Bank of India (RBI) to fill the vacancies for the posts of Assistants in various branches of the RBI across India. RBI Assistant is responsible for maintaining records/files, document verification, ensuring financial stability, issuing &amp; circulating new currency, day-to-day transactions, attending Government Treasury Work, replying to emails and more.&nbsp;</p><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\"><span style=\"font-weight: bolder;\">For the year, the Reserve Bank of India is expected to announce more than 540 vacancies through the RBI Assistant Notification , and complete details can be released in January .&nbsp;</span></p><h2 id=\"AXHYBLB90C6EL3GYUMI9H5FEVQIB4VNH\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">RBI Assistant Recruitment&nbsp;</h2><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The selection process followed by RBI to select candidates for the post of Assistant is carried out through&nbsp;three stages, namely- Prelims, Mains and Language Proficiency Tests.&nbsp;The final result will be based on the marks scored in the Mains Exam and Language test. In this article, we have covered all the necessary information regarding the RBI Assistant Exam. Lakhs of graduate candidates who were waiting for the RBI Assistant Exam&nbsp; must go through the complete article to know more about RBI Assistant Recruitment , eligibility, salary, exam pattern, selection process, and other details.</p><h2 id=\"C95IJBN0QF4XJ7X45T3FBY347MY5AC09\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">RBI Assistant Notification</h2><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The official<span style=\"font-weight: bolder;\">&nbsp;RBI Assistant Notification&nbsp; for various Assistant posts will be released in January </span>&nbsp;on the official website www.rbi.org.in.<span style=\"font-weight: bolder;\">&nbsp;</span>The official notification PDF<span style=\"font-weight: bolder;\">&nbsp;</span>with complete details for the posts, including category-wise vacancies, eligibility criteria, exam pattern, syllabus, and the selection process, will be released on the official website of RBI.</p><h2 id=\"MGQ914NW1P6BXKXX5X68QGVK80CLV8QK\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">RBI Assistant Recruitment - Summary</h2><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The Reserve Bank of India (RBI) is responsible for recruiting eligible candidates at the national level for the post of RBI Assistant. For the candidates who are not clear about the RBI Assistant Recruitment process, we have provided a brief about the RBI Assistant&nbsp; in the table below.</p><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-stripe