; line-height: 22px;\">583</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">PwD – Other</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">72.53530</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px;\">401</td></tr></tbody></table></figure><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"></figure><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"></figure>', 1, '2026-01-07 07:41:20', '2026-01-29 07:33:48');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(75, 15, 'Eligibility Criteria', '<h3 data-path-to-node=\"2\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"2\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">SSC CHSL Eligibility Criteria&nbsp;</b></h3><p data-path-to-node=\"3\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">Candidates preparing for the SSC Combined Higher Secondary Level (CHSL) exam must verify eligibility conditions such as age, educational qualification, age relaxations, citizenship requirements, and recommendations for physically impaired candidates before applying for the SSC CHSL&nbsp; exam.</p><p data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">The commission sets the eligibility for selecting candidates for 3,131 vacancies for Lower Division Clerk (LDC), Junior Secretariat Assistant (JSA), and Data Entry Operator (DEO) posts.</p><h4 data-path-to-node=\"5\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"5\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">Key Parameters:</b></h4><ul data-path-to-node=\"6\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"6,0,0\" style=\"line-height: 1.15 !important;\">Age Limit</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"6,1,0\" style=\"line-height: 1.15 !important;\">Nationality</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"6,2,0\" style=\"line-height: 1.15 !important;\">Educational Qualification</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"6,3,0\" style=\"line-height: 1.15 !important;\">Physical Disabilities</p></li></ul><hr data-path-to-node=\"7\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h3 data-path-to-node=\"8\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"8\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">SSC CHSL Age Limit&nbsp;</b></h3><p data-path-to-node=\"9\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">To be eligible to apply online for SSC CHSL , candidates must fall between <b data-path-to-node=\"9\" data-index-in-node=\"79\" style=\"line-height: 1.15 !important;\">18 to 27 years</b> of age.</p><ul data-path-to-node=\"10\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"10,0,0\" style=\"line-height: 1.15 !important;\">The age will be determined using the date of birth provided in the online application form and the Matriculation/Secondary Examination Certificate.</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"10,1,0\" style=\"line-height: 1.15 !important;\">Candidates born <b data-path-to-node=\"10,1,0\" data-index-in-node=\"16\" style=\"line-height: 1.15 !important;\">not before 02-08-1998</b> and <b data-path-to-node=\"10,1,0\" data-index-in-node=\"42\" style=\"line-height: 1.15 !important;\">not later than 01-08-2007</b> are eligible to apply.</p></li></ul><table data-path-to-node=\"11\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><thead style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Particulars</strong></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Age</strong></td></tr></thead><tbody style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"11,1,0,0\" style=\"line-height: 1.15 !important;\">Minimum Age</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"11,1,1,0\" style=\"line-height: 1.15 !important;\">18 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"11,2,0,0\" style=\"line-height: 1.15 !important;\">Maximum Age</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"11,2,1,0\" style=\"line-height: 1.15 !important;\">27 years</span></td></tr></tbody></table><hr data-path-to-node=\"12\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h3 data-path-to-node=\"13\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"13\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">SSC CHSL Age Relaxation&nbsp;</b></h3><p data-path-to-node=\"14\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">The table below gives the age relaxations for various categories:</p><table data-path-to-node=\"15\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><thead style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Categories</strong></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Age relaxation beyond the upper age limit</strong></td></tr></thead><tbody style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,1,0,0\" style=\"line-height: 1.15 !important;\">SC/ ST</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,1,1,0\" style=\"line-height: 1.15 !important;\">5 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,2,0,0\" style=\"line-height: 1.15 !important;\">OBC</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,2,1,0\" style=\"line-height: 1.15 !important;\">3 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,3,0,0\" style=\"line-height: 1.15 !important;\">PwBD + Unreserved</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,3,1,0\" style=\"line-height: 1.15 !important;\">10 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,4,0,0\" style=\"line-height: 1.15 !important;\">PwBD + OBC</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,4,1,0\" style=\"line-height: 1.15 !important;\">13 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,5,0,0\" style=\"line-height: 1.15 !important;\">PwBD + SC/ ST</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,5,1,0\" style=\"line-height: 1.15 !important;\">15 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,6,0,0\" style=\"line-height: 1.15 !important;\">Ex-Servicemen</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,6,1,0\" style=\"line-height: 1.15 !important;\">03 years after deducting military service rendered from actual age.</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,7,0,0\" style=\"line-height: 1.15 !important;\">Candidates resident in J&amp;K (Jan 1, 1980 to Dec 31, 1989)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,7,1,0\" style=\"line-height: 1.15 !important;\">5 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,8,0,0\" style=\"line-height: 1.15 !important;\">Defence personnel handicapped during hostilities (Foreign country/disturbed area)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,8,1,0\" style=\"line-height: 1.15 !important;\">3 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,9,0,0\" style=\"line-height: 1.15 !important;\">Defence personnel handicapped (SC/ST)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,9,1,0\" style=\"line-height: 1.15 !important;\">8 years</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,10,0,0\" style=\"line-height: 1.15 !important;\">Central Govt. Civilian Employees (min 3 years service)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,10,1,0\" style=\"line-height: 1.15 !important;\">Up to 40 years of age</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,11,0,0\" style=\"line-height: 1.15 !important;\">Central Govt. Civilian Employees (SC/ST)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,11,1,0\" style=\"line-height: 1.15 !important;\">Up to 45 years of age</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,12,0,0\" style=\"line-height: 1.15 !important;\">Women (Widowed/Divorced/Judicially Separated and not remarried)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,12,1,0\" style=\"line-height: 1.15 !important;\">Up to 35 years of age</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,13,0,0\" style=\"line-height: 1.15 !important;\">Women (Widowed/Divorced/Judicially Separated - SC/ST)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"15,13,1,0\" style=\"line-height: 1.15 !important;\">Up to 40 years of age</span></td></tr></tbody></table><hr data-path-to-node=\"16\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h3 data-path-to-node=\"17\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"17\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">SSC CHSL Education Qualification&nbsp;</b></h3><table data-path-to-node=\"18\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><thead style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Posts</strong></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Educational Qualifications</strong></td></tr></thead><tbody style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"18,1,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"18,1,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important;\">Data Entry Operator (DEO)/ DEO Grade \'A\'</b> (Ministry of Consumer Affairs, Food &amp; Public Distribution and Ministry of Culture)</span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"18,1,1,0\" style=\"line-height: 1.15 !important;\">Must have cleared or appeared <b data-path-to-node=\"18,1,1,0\" data-index-in-node=\"30\" style=\"line-height: 1.15 !important;\">10+2</b> or its equivalent from any recognized board.</span></td></tr><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"18,2,0,0\" style=\"line-height: 1.15 !important;\"><span class=\"citation-95\" style=\"line-height: 1.15 !important;\"></span><b data-path-to-node=\"18,2,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important;\"><span class=\"citation-95\" style=\"line-height: 1.15 !important;\">LDC/JSA and DEO/DEO Grade \'A\'</span></b><span class=\"citation-95 citation-end-95\" style=\"line-height: 1.15 !important;\"> (Except DEOs in Department/ Ministry)<source-footnote ng-version=\"0.0.0-PLACEHOLDER\" _nghost-ng-c1831576998=\"\" style=\"line-height: 1.15 !important;\"><sup _ngcontent-ng-c1831576998=\"\" class=\"superscript\" data-turn-source-index=\"1\" style=\"line-height: 1.15 !important; font-size: 16px !important; background-color: transparent !important;\"><!----></sup></source-footnote></span></span></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"18,2,1,0\" style=\"line-height: 1.15 !important;\"><span class=\"citation-94\" style=\"line-height: 1.15 !important;\">Qualified: </span><b data-path-to-node=\"18,2,1,0\" data-index-in-node=\"11\" style=\"line-height: 1.15 !important;\"><span class=\"citation-94\" style=\"line-height: 1.15 !important;\">10+2 Possessing Science Stream with Mathematics</span></b><span class=\"citation-94 citation-end-94\" style=\"line-height: 1.15 !important;\"> as a compulsory subject, or its equivalent from any recognized board.<source-footnote ng-version=\"0.0.0-PLACEHOLDER\" _nghost-ng-c1831576998=\"\" style=\"line-height: 1.15 !important;\"><sup _ngcontent-ng-c1831576998=\"\" class=\"superscript\" data-turn-source-index=\"2\" style=\"line-height: 1.15 !important; font-size: 16px !important; background-color: transparent !important;\"><!----></sup></source-footnote></span></span></td></tr></tbody></table><hr data-path-to-node=\"19\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h3 data-path-to-node=\"20\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"20\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><span class=\"citation-93 citation-end-93\" style=\"line-height: 1.15 !important;\">SSC CHSL Nationality<source-footnote ng-version=\"0.0.0-PLACEHOLDER\" _nghost-ng-c1831576998=\"\" style=\"line-height: 1.15 !important;\"><sup _ngcontent-ng-c1831576998=\"\" class=\"superscript\" data-turn-source-index=\"3\" style=\"line-height: 1.15 !important; font-size: 16px !important; background-color: transparent !important;\"><!----></sup></source-footnote></span>&nbsp;</b></h3><p data-path-to-node=\"21\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">A candidate must be either:</p><ol start=\"1\" data-path-to-node=\"22\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"22,0,0\" style=\"line-height: 1.15 !important;\">A citizen of India, or</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"22,1,0\" style=\"line-height: 1.15 !important;\">A subject of Nepal, or</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"22,2,0\" style=\"line-height: 1.15 !important;\">A subject of Bhutan, or</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"22,3,0\" style=\"line-height: 1.15 !important;\">A Tibetan refugee who moved over to India before January 1, 1962, to be permanently settled in India.</p></li><li style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"22,4,0\" style=\"line-height: 1.15 !important;\">A person of Indian heritage who has migrated from Burma, Pakistan, Sri Lanka, the East African republics of Kenya, Uganda, Tanzania, Zaire, Ethiopia, Zambia, Malawi, and Vietnam to permanently settle in India.</p></li></ol><hr data-path-to-node=\"23\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h3 data-path-to-node=\"24\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"24\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">SSC CHSL Physical Disability&nbsp;</b></h3><table data-path-to-node=\"25\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><thead style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Posts</strong></td><td style=\"border-color: initial; line-height: 1.15 !important;\"><strong style=\"line-height: 1.15 !important;\">Physical Disability Criteria</strong></td></tr></thead><tbody style=\"line-height: 1.15 !important;\"><tr style=\"line-height: 1.15 !important;\"><td style=\"border-color: initial; line-height: 1.15 !important;\"><span data-path-to-node=\"25,1,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"25,1,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important;\"><span class=\"citation-86\" style=\"line-height: 1.15 !important;\"></span><span class=\"citation-85 citation-86\" style=\"line-height: 1.15 !important;\"></span><span class=\"citation-84 citation-85 citation-86 citation-end-86\" style=\"line-height: 1.15 !important;\">Lower Division Clerk/Junior Secret Assistant<source-footnote ng-version=\"0.0.0-PLACEHOLDER\" _nghost-ng-c1831576998=\"\" style=\"line-height: 1.15 !important;\"><sup _ngcontent-ng-c1831576998=\"\" class=\"superscript\" data-turn-source-index=\"10\" style=\"line-height: 1.15 !important; font-size: 16px !important; background-color: transparent !important;\"><!----></s