d><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Punjab National Bank</td><td>15</td><td>07</td><td>27</td><td>10</td><td>41</td><td>100</td></tr>\r\n        <tr><td>UCO Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Union Bank of India</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><th>Total</th><th>30</th><th>14</th><th>53</th><th>20</th><th>86</th><th>203</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Marketing Officer Vacancy (Last Year) - Bank-wise</h2>\r\n      <table>\r\n        <tbody><tr><th>Participating Banks</th><th>SC</th><th>ST</th><th>OBC</th><th>EWS</th><th>General</th><th>Total</th></tr>\r\n        <tr><td>Canara Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Indian Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Punjab &amp; Sind Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Punjab National Bank</td><td>52</td><td>26</td><td>94</td><td>35</td><td>143</td><td>350</td></tr>\r\n        <tr><td>UCO Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Union Bank of India</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><th>Total</th><th>52</th><th>26</th><th>94</th><th>35</th><th>143</th><th>350</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Rajbhasha Adhikari Vacancy (Last Year) - Bank-wise</h2>\r\n      <table>\r\n        <tbody><tr><th>Participating Banks</th><th>SC</th><th>ST</th><th>OBC</th><th>EWS</th><th>General</th><th>Total</th></tr>\r\n        <tr><td>Bank of Baroda</td><td>03</td><td>01</td><td>06</td><td>02</td><td>11</td><td>23</td></tr>\r\n        <tr><td>Bank of India</td><td>--</td><td>--</td><td>01</td><td>--</td><td>--</td><td>01</td></tr>\r\n        <tr><td>Bank of Maharashtra</td><td>01</td><td>--</td><td>02</td><td>01</td><td>06</td><td>10</td></tr>\r\n        <tr><td>Canara Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Central Bank of India</td><td>03</td><td>01</td><td>05</td><td>02</td><td>09</td><td>20</td></tr>\r\n        <tr><td>Indian Overseas Bank</td><td>02</td><td>01</td><td>03</td><td>01</td><td>07</td><td>14</td></tr>\r\n        <tr><td>Indian Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Punjab &amp; Sind Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Punjab National Bank</td><td>01</td><td>--</td><td>02</td><td>01</td><td>06</td><td>10</td></tr>\r\n        <tr><td>UCO Bank</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><td>Union Bank of India</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td><td>NR</td></tr>\r\n        <tr><th>Total</th><th>30</th><th>14</th><th>53</th><th>20</th><th>86</th><th>203</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>IBPS SO - Eligibility, Fee, Selection &amp; Exam Pattern</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    .small{font-size:14px;color:#333}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>IBPS SO Eligibility Criteria</h1>\r\n      <p>\r\n        The IBPS SO eligibility criteria are different for recruiting candidates to different positions.\r\n        There are three parameters: <b>citizenship</b>, <b>age limit</b>, and <b>educational qualification</b>.\r\n      </p>\r\n\r\n      <h3>Citizenship Criteria</h3>\r\n      <ul>\r\n        <li>A resident of India</li>\r\n        <li>A subject of Nepal</li>\r\n        <li>Tibetan refugees who came to India before 1st January 1962 and have planned to settle in India permanently</li>\r\n        <li>\r\n          A subject of Indian origin migrated from Burma, Nepal, Sri Lanka, Pakistan, Uganda, Kenya,\r\n          United Republic of Tanzania, Namibia, Ethiopia, Zambia, Malawi, Zaire and Vietnam\r\n        </li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Educational Qualifications</h2>\r\n      <p>IBPS SO recruits candidates for various posts such as IT Officer, AFO, Rajbhasha Adhikari, Law Officer, HR/Personnel Officer, Marketing Officer, etc.</p>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Name of the Post</th>\r\n          <th>Educational Qualification</th>\r\n        </tr>\r\n        <tr>\r\n          <td>1</td>\r\n          <td>IT Officer (Scale I)</td>\r\n          <td>\r\n            1) Four years Engineering/Technology degree in Computer Science/IT/Computer Application/\r\n            Electronics &amp; Communication Engineering/Electronics &amp; Telecommunication/\r\n            Electronics &amp; Instrumentation <b>OR</b><br>\r\n            2) Post Graduate Degree in the above fields <b>OR</b><br>\r\n            Graduates having passed DOEACC ‘B’ level exam\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td>2</td>\r\n          <td>Agricultural Field Officer (Scale I)</td>\r\n          <td>\r\n            4 years graduation degree in Agriculture/Horticulture/Animal Husbandry/Veterinary Science/Dairy Science/\r\n            Agricultural Engineering/Fishery Science/Pisciculture/Agri Marketing &amp; Cooperation/Co-Operation &amp; Banking/Agro-Forestry\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td>3</td>\r\n          <td>Rajbhasha Adhikari (Scale I)</td>\r\n          <td>\r\n            Post Graduate in Hindi with English as a subject at graduation/degree level <b>OR</b><br>\r\n            Post Graduate Degree in Sanskrit with English and Hindi as subjects at graduation level\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td>4</td>\r\n          <td>Law Officer (Scale I)</td>\r\n          <td>A bachelor’s degree in Law and enrolled as an advocate with Bar Council</td>\r\n        </tr>\r\n        <tr>\r\n          <td>5</td>\r\n          <td>HR/Personnel Officer (Scale I)</td>\r\n          <td>\r\n            Graduate and Full-Time Post Graduate Degree or Full-Time Diploma in Personnel Management/\r\n            Industrial Relation/HR/HRD/Social Work/Labour Law\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td>6</td>\r\n          <td>Marketing Officer (Scale I)</td>\r\n          <td>\r\n            Graduate and Full-Time MMS (Marketing)/MBA (Marketing)/Full-Time PGDBA/PGDBM with specialization in Marketing\r\n          </td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Age Limit</h2>\r\n      <p>Minimum age: <b>20 years</b> | Maximum age: <b>30 years</b></p>\r\n\r\n      <h3>Category-wise Age Relaxation</h3>\r\n      <table>\r\n        <tbody><tr><th>S. No.</th><th>Category</th><th>Age Relaxation</th></tr>\r\n        <tr><td>1</td><td>SC/ST</td><td>5 years</td></tr>\r\n        <tr><td>2</td><td>OBC</td><td>3 years</td></tr>\r\n        <tr><td>3</td><td>PWD</td><td>10 years</td></tr>\r\n        <tr>\r\n          <td>4</td>\r\n          <td>\r\n            Ex-Servicemen/Commissioned Officers (ECOS/SSCOs) who have rendered at least 5 years military service and\r\n            have been released on completion of assignment (as applicable)\r\n          </td>\r\n          <td>5 years</td>\r\n        </tr>\r\n        <tr>\r\n          <td>5</td>\r\n          <td>Person ordinarily domiciled in Jammu and Kashmir during 1.01.1980 to 31.12.1989</td>\r\n          <td>5 years</td>\r\n        </tr>\r\n        <tr><td>6</td><td>Person affected by 1984 riots</td><td>5 years</td></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Online Application</h2>\r\n      <p>\r\n        The online application process for the IBPS SO exam will start after the release of the notification at\r\n        <b>www.ibps.in</b>. Interested and eligible candidates can apply through the official website.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Application Fee</h2>\r\n      <table>\r\n        <tbody><tr><th>S. No.</th><th>Category</th><th>Application Fee</th></tr>\r\n        <tr><td>1</td><td>SC/ST/PWD</td><td>Rs. 175/- (Intimation Charges only)</td></tr>\r\n        <tr><td>2</td><td>General and Others</td><td>Rs. 850/- (App. fee including intimation charges)</td></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Selection Process</h2>\r\n      <ol>\r\n        <li>Online Preliminary Exam</li>\r\n        <li>Online Mains Exam</li>\r\n        <li>Interview Process</li>\r\n      </ol>\r\n      <p>\r\n        A candidate must qualify for both the preliminary and mains exams to proceed to the interview round.\r\n        Candidates selected after the interview round are given the appointment letter.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Exam Pattern (Prelims)</h2>\r\n      <p class=\"small\">\r\n        The preliminary exam is qualifying for the mains. There is a sectional cut-off and candidates must clear all sections.\r\n      </p>\r\n\r\n      <h3>For IT Officer, Agriculture Field Officer, HR/Personnel Officer &amp; Marketing Officer</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th><th>Name of Tests</th><th>No. of Questions</th><th>Maximum Marks</th><th>Medium of Exam</th><th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>English Language</td><td>50</td><td>25</td><td>English</td><td>40 minutes</td></tr>\r\n        <tr><td>2</td><td>Reasoning</td><td>50</td><td>50</td><td>English and Hindi</td><td>40 minutes</td></tr>\r\n        <tr><td>3</td><td>Quantitative Aptitude</td><td>50</td><td>50</td><td>English and Hindi</td><td>40 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>150</th><th>125</th><th></th><th>120 minutes</th></tr>\r\n      </tbody></table>\r\n\r\n      <h3>For Law Officer &amp; Rajbhasha Adhikari</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th><th>Name of Tests</th><th>No. of Questions</th><th>Maximum Marks</th><th>Medium of Exam</th><th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>English Language</td><td>50</td><td>25</td><td>English</td><td>40 minutes</td></tr>\r\n        <tr><td>2</td><td>Reasoning</td><td>50</td><td>50</td><td>English and Hindi</td><td>40 minutes</td></tr>\r\n        <tr><td>3</td><td>General Awareness (Banking Industry)</td><td>50</td><td>50</td><td>English and Hindi</td><td>40 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>150</th><th>125</th><th></th><th>120 minutes</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>IBPS SO Syllabus</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:10px;padding:12px}\r\n    .box h4{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>IBPS SO Syllabus</h1>\r\n      <p>\r\n        IBPS SO syllabus is designed separately for Rajbhasha Adhikari and other Specialist Officer posts.\r\n        The syllabus is different for the Preliminary Exam and the Mains Exam. Along with the major sections\r\n        (English Language, Quantitative Aptitude, and Reasoning), candidates must also prepare their\r\n        <b>Professional Knowledge</b> (specialization subject) based on the post.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Prelims Syllabus (Section-wise)</h2>\r\n\r\n      <div class=\"grid\">\r\n        <div class=\"box\">\r\n          <h4>Reasoning Ability</h4>\r\n          <ul>\r\n            <li>Seating Arrangements</li>\r\n            <li>Puzzles</li>\r\n            <li>Inequalities</li>\r\n            <li>Syllogism</li>\r\n            <li>Input-Output</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Blood Relations</li>\r\n            <li>Order and Ranking</li>\r\n            <li>Alphanumeric Series</li>\r\n            <li>Distance and Direction</li>\r\n            <li>Verbal Reasoning</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>English Language</h4>\r\n          <ul>\r\n            <li>Cloze Test</li>\r\n            <li>Reading Comprehension</li>\r\n            <li>Spotting Errors</li>\r\n            <li>Sentence Improvement</li>\r\n            <li>Sentence Correction</li>\r\n            <li>Para Jumbles</li>\r\n            <li>Fill in the Blanks</li>\r\n            <li>Para/Sentence Completion</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Quantitative Aptitude</h4>\r\n          <ul>\r\n            <li>Number Series</li>\r\n            <li>Data Interpretation</li>\r\n            <li>Simplification / Approximation</li>\r\n            <li>Quadratic Equation</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Mensuration</li>\r\n            <li>Average</li>\r\n            <li>Profit and Loss</li>\r\n            <li>Ratio and Proportion</li>\r\n            <li>Work, Time and Energy</li>\r\n            <li>Time and Distance</li>\r\n            <li>Probability</li>\r\n            <li>Relations</li>\r\n            <li>Simple &amp; Compound Interest</li>\r\n            <li>Permutation and Combination</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>General Awareness</h4>\r\n          <ul>\r\n            <li>Current Affairs</li>\r\n            <li>Banking Awareness</li>\r\n            <li>GK Updates</li>\r\n            <li>Currencies</li>\r\n            <li>Important Places</li>\r\n            <li>Books and Authors</li>\r\n            <li>Awards</li>\r\n            <li>Headquarters</li>\r\n            <li>Prime Minister Schemes</li>\r\n            <li>Important Days</li>\r\n          </ul>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Professional Knowledge Syllabus (Post-wise)</h2>\r\n      <p>Apart from the above subjects, candidates are required to have Professional Knowledge in their area of expertise.</p>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Post</th>\r\n          <th>Syllabus Topics</th>\r\n        </tr>\r\n\r\n        <tr>\r\n          <td><b>IT Officer (Scale I)</b></td>\r\n          <td>\r\n            <ul>\r\n              <li>Database Management System</li>\r\n              <li>Data Communication and Networking</li>\r\n              <li>Operating System</li>\r\n              <li>Software Engineering</li>\r\n              <li>Data Structure</li>\r\n              <li>Computer Organization and Microprocessor</li>\r\n              <li>Object-Oriented Programming</li>\r\n            </ul>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr>\r\n          <td><b>Agricultural Field Officer (Scale I)</b></td>\r\n          <td>\r\n            <ul>\r\n              <li>Basics of Crop Production</li>\r\n              <li>Horticulture</li>\r\n              <li>Seed Science</li>\r\n              <li>Agronomy and Irrigation</li>\r\n              <li>Agricultural Economics</li>\r\n              <li>Agricultural Practices</li>\r\n              <li>Soil Resources</li>\r\n              <li>Animal Husbandry</li>\r\n              <li>Agroforestry</li>\r\n              <li>Ecology</li>\r\n              <li>Government Schemes</li>\r\n            </ul>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr>\r\n          <td><b>Marketing Officer (Scale I)</b></td>\r\n          <td>\r\n            <ul>\r\n              <li>Basics of Marketing Management</li>\r\n              <li>Brand Management</li>\r\n              <li>Advertising</li>\r\n              <li>PR</li>\r\n              <li>Sales</li>\r\n              <li>Retail</li>\r\n              <li>Business Ethics</li>\r\n              <li>Market Segmentation</li>\r\n              <li>Market Research and Forecasting Demand</li>\r\n              <li>Product Life Cycle</li>\r\n              <li>Corporate Social Responsibility</li>\r\n              <li>Service Marketing</li>\r\n              <li>Marketing Strategies</li>\r\n            </ul>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr>\r\n          <td><b>Law Officer (Scale I)</b></td>\r\n          <td>\r\n            <ul>\r\n              <li>Banking Regulations</li>\r\n              <li>Compliance and Legal Aspects</li>\r\n              <li>Relevant laws related to negotiable instruments, securities, foreign exchange</li>\r\n              <li>Prevention of Money-laundering, Limitation Act</li>\r\n              <li>Consumer Protection Act</li>\r\n              <li>SARFAESI</li>\r\n              <li>Banking Ombudsman Scheme</li>\r\n              <li>Laws/actions with direct link to Banking Sector</li>\r\n              <li>Bankers Book Evidence Act</li>\r\n              <li>DRT Act</li>\r\n            </ul>\r\n          </td>\r\n        </tr>\r\n\r\n        <tr>\r\n          <td><b>HR/Personnel Officer (Scale I)</b></td>\r\n          <td>\r\n            <ul>\r\n              <li>Human Resource Development</li>\r\n              <li>Business Policy and Strategic Analysis</li>\r\n              <li>Transnational Analysis</li>\r\n              <li>Training and Development</li>\r\n              <li>Recruitment and Selection</li>\r\n              <li>Rewards and Recognition</li>\r\n              <li>Industrial Relations</li>\r\n              <li>Grievance and Conflict Management</li>\r\n              <li>Performance Management and Appraisal</li>\r\n            </ul>\r\n          </td>\r\n        </tr>\r\n\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>IBPS SO - Admit Card, Result &amp; Cut-Off</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>IBPS SO Admit Card</h1>\r\n      <p>\r\n        The IBPS SO admit card will be released <b>10 to 15 days</b> before the exam date.\r\n        The admit cards for <b>Prelims</b>, <b>Mains</b>, and <b>Interview</b> will be released separately at\r\n        <a href=\"https://www.ibps.in\" target=\"_blank\" rel=\"noopener\">www.ibps.in</a>.\r\n      </p>\r\n      <p>\r\n        The admit card for the Preliminary Exam will be released for candidates who have applied.\r\n        The Mains admit card will be released for candidates who have qualified the preliminary test.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>IBPS SO Exam Result</h2>\r\n      <p>\r\n        The IBPS SO result will be released after each phase of the exam is successfully conducted.\r\n        A cumulative score of the <b>Mains exam</b> and the <b>Interview</b> is considered to prepare the final merit list.\r\n        The Prelims exam is qualifying to shortlist candidates for the Mains exam.\r\n      </p>\r\n      <p>\r\n        The merit list is prepared in descending order of marks obtained by candidates. Candidates who make it to the\r\n        merit list will be given the appointment letter by the bank of the candidate’s choice.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>IBPS SO Exam Cut-Off</h2>\r\n      <p>\r\n        The IBPS SO cut-off will be released after each phase of the examination is conducted.\r\n        The cut-off for the preliminary exam will be released first, followed by the cut-off for the main exam.\r\n        Candidates can evaluate their selection chances by matching their score with the cut-off marks.\r\n      </p>\r\n\r\n      <h3>IBPS SO Prelims Cut-Off (2025)</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Posts</th>\r\n          <th>SC</th>\r\n          <th>ST</th>\r\n          <th>OBC</th>\r\n          <th>EWS</th>\r\n          <th>UR</th>\r\n          <th>HI</th>\r\n          <th>OC</th>\r\n          <th>VI</th>\r\n          <th>ID</th>\r\n        </tr>\r\n        <tr>\r\n          <td>I.T. Officer</td>\r\n          <td>58.25</td><td>48.63</td><td>58.25</td><td>55</td><td>58.25</td>\r\n          <td>21.63</td><td>46.38</td><td>42.63</td><td>36.13</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Agricultural Field Officer</td>\r\n          <td>50.13</td><td>45.63</td><td>50.13</td><td>50.13</td><td>50.13</td>\r\n          <td>25.88</td><td>37.75</td><td>39.63</td><td>23.88</td>\r\n        </tr>\r\n        <tr>\r\n          <td>HR/Personnel</td>\r\n          <td>62.63</td><td>62.63</td><td>62.63</td><td>62.63</td><td>62.63</td>\r\n          <td>31.38</td><td>19.75</td><td>25.13</td><td>NA</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Marketing Officer</td>\r\n          <td>21.75</td><td>17.25</td><td>18.13</td><td>27.63</td><td>27.63</td>\r\n          <td>21.75</td><td>20.50</td><td>23.38</td><td>35.18</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Rajbhasha Adhikari</td>\r\n          <td>16.63</td><td>11</td><td>16.63</td><td>16.63</td><td>16.63</td>\r\n          <td>25.75</td><td>18.88</td><td>42.25</td><td>13.75</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Law Officer</td>\r\n          <td>42.63</td><td>34.75</td><td>43.25</td><td>44.63</td><td>46.88</td>\r\n          <td>20.25</td><td>25</td><td>23.13</td><td>23</td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>IBPS SO Participating Banks</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;max-width:900px}\r\n    h1{margin:0 0 10px}\r\n    ul{margin:6px 0 0 18px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"card\">\r\n    <h1>IBPS SO Participating Banks</h1>\r\n    <p>A total of 11 banks will be participating in the IBPS SO recruitment process:</p>\r\n\r\n    <ul>\r\n      <li>Bank of Baroda</li>\r\n      <li>Bank of India</li>\r\n      <li>Bank of Maharashtra</li>\r\n      <li>Canara Bank</li>\r\n      <li>Central Bank of India</li>\r\n      <li>Indian Bank</li>\r\n      <li>Indian Overseas Bank</li>\r\n      <li>Punjab National Bank</li>\r\n      <li>Punjab &amp; Sind Bank</li>\r\n      <li>UCO Bank</li>\r\n      <li>Union Bank of India</li>\r\n    </ul>\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 0, '2026-01-22 07:57:04', '2026-01-22 07:57:04');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(85, 7, 'HOME', '  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk 2026 - Overview</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1000px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk Exam</h1>\r\n      <p>\r\n        The SBI Clerk Exam is held annually by the State Bank of India to recruit candidates for the position of\r\n        <b>Junior Associate (Customer Support and Sales)</b> in its branches across the country.\r\n        The SBI Clerk exam is highly sought after and attracts a large number of candidates each year.\r\n      </p>\r\n      <p>the State Bank of India will conduct <b>Prelims</b>, <b>Mains</b>, and <b>LPT</b>\r\n        (Language Proficiency Test) to shortlist candidates for Junior Associate vacancies.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>What is the SBI Clerk Exam?</h2>\r\n      <p>\r\n        Through the SBI Clerk Exam, the State Bank of India recruits thousands of candidates every year for the post of\r\n        Junior Associate (Customer Support and Sales). Candidates recruited as SBI clerks are designated as cashiers,\r\n        depositors, and other roles that form the face of a particular SBI branch.\r\n      </p>\r\n      <p>\r\n        The SBI Clerk (Junior Associate) is responsible for client interactions and related operations. This page covers\r\n        SBI Clerk 2026 exam details such as important dates, online form, exam pattern, syllabus, salary, and more.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk&nbsp; Notification</h2>\r\n      <p>\r\n        SBI Clerk Notification&nbsp; PDF for Junior Associates (Customer Support and Sales) vacancies will be released\r\n        by the State Bank of India (SBI) on its career page in <b>July/August </b>.\r\n        Candidates interested in Junior Associate posts in the clerical cadre should review the notification before applying.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk&nbsp; Exam Overview</h2>\r\n      <p>\r\n        Eligible candidates will be selected through a two-stage selection process: <b>Preliminary Exam</b> and\r\n        <b>Mains Exam</b>. SBI will announce a large number of vacancies for Clerk (Junior Associate) posts for the\r\n        recruitment year&nbsp;</p>\r\n\r\n      <h3>SBI Clerk&nbsp; Exam Summary</h3>\r\n      <table>\r\n        <tbody><tr><th>Organisation</th><td>State Bank of India (SBI)</td></tr>\r\n        <tr><th>Post Name</th><td>Clerk (Junior Associates)</td></tr>\r\n        <tr><th>Vacancy</th><td>To be notified</td></tr>\r\n        <tr><th>Advt. No.</th><td>To be notified</td></tr>\r\n        <tr><th>Category</th><td>Govt Jobs</td></tr>\r\n        <tr><th>Exam Mode</th><td>Online</td></tr>\r\n        <tr><th>Recruitment Process</th><td>Prelims - Mains - Language Proficiency Test</td></tr>\r\n        <tr><th>Education Qualification</th><td>Graduation</td></tr>\r\n        <tr><th>Age Limit</th><td>20 to 28 years</td></tr>\r\n        <tr><th>Salary</th><td>Rs. 46,000 (approx.)</td></tr>\r\n        <tr>\r\n          <th>Official Website</th>\r\n          <td>\r\n            <a href=\"https://sbi.co.in\" target=\"_blank\" rel=\"noopener\">https://sbi.co.in</a>,\r\n            <a href=\"https://sbi.co.in/web/careers\" target=\"_blank\" rel=\"noopener\">https://sbi.co.in/web/careers</a>\r\n          </td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk Vacancy 2026</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk Vacancy&nbsp;</h1>\r\n      <p>\r\n        The State Bank of India (SBI) will release the number of vacancies for Clerk / Junior Associate\r\n        (Customer Support &amp; Sales) posts in the clerical cadre through the SBI Clerk Notification .\r\n        Last year, SBI announced <b>6589</b> vacancies across the country. Out of the total vacancies,\r\n        <b>1409</b> were backlog vacancies.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Junior Associates 2025 - Regular Vacancies</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>State/UT</th><th>Total</th><th>General</th><th>SC</th><th>ST</th><th>OBC</th><th>EWS</th>\r\n        </tr>\r\n        <tr><td>Gujarat</td><td>220</td><td>91</td><td>15</td><td>33</td><td>59</td><td>22</td></tr>\r\n        <tr><td>Andhra Pradesh</td><td>310</td><td>126</td><td>49</td><td>21</td><td>83</td><td>31</td></tr>\r\n        <tr><td>Karnataka</td><td>270</td><td>110</td><td>43</td><td>18</td><td>7