2</td><td>3</td><td>16</td><td>12</td></tr>\r\n        <tr><td>Arunachal Pradesh</td><td>20</td><td>9</td><td>--</td><td>9</td><td>--</td><td>2</td></tr>\r\n        <tr><td>Assam</td><td>145</td><td>65</td><td>10</td><td>17</td><td>39</td><td>14</td></tr>\r\n        <tr><td>Manipur</td><td>16</td><td>8</td><td>--</td><td>5</td><td>2</td><td>1</td></tr>\r\n        <tr><td>Meghalaya</td><td>32</td><td>14</td><td>--</td><td>14</td><td>1</td><td>3</td></tr>\r\n        <tr><td>Mizoram</td><td>13</td><td>7</td><td>--</td><td>5</td><td>--</td><td>1</td></tr>\r\n        <tr><td>Nagaland</td><td>22</td><td>11</td><td>--</td><td>9</td><td>--</td><td>2</td></tr>\r\n        <tr><td>Tripura</td><td>22</td><td>11</td><td>03</td><td>6</td><td>--</td><td>2</td></tr>\r\n        <tr><td>Bihar</td><td>260</td><td>121</td><td>41</td><td>2</td><td>70</td><td>26</td></tr>\r\n        <tr><td>Jharkhand</td><td>130</td><td>54</td><td>15</td><td>33</td><td>15</td><td>13</td></tr>\r\n        <tr><td>Kerala</td><td>247</td><td>131</td><td>24</td><td>2</td><td>66</td><td>24</td></tr>\r\n        <tr><td>Lakshadweep</td><td>03</td><td>02</td><td>--</td><td>1</td><td>--</td><td>--</td></tr>\r\n        <tr><th>Total</th><th>5180</th><th>2255</th><th>788</th><th>450</th><th>1179</th><th>508</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Junior Associates 2025 - Backlog Vacancies</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>State/UT</th><th>Total</th><th>SC</th><th>ST</th><th>OBC</th><th>PwBD</th><th>XS</th>\r\n        </tr>\r\n        <tr><td>Andhra Pradesh</td><td>5</td><td>--</td><td>3</td><td>--</td><td>2</td><td>--</td></tr>\r\n        <tr><td>Karnataka</td><td>229</td><td>1</td><td>10</td><td>--</td><td>20</td><td>198</td></tr>\r\n        <tr><td>Madhya Pradesh</td><td>99</td><td>8</td><td>46</td><td>--</td><td>8</td><td>37</td></tr>\r\n        <tr><td>Chhattisgarh</td><td>86</td><td>--</td><td>45</td><td>--</td><td>9</td><td>32</td></tr>\r\n        <tr><td>Haryana</td><td>8</td><td>5</td><td>--</td><td>--</td><td>3</td><td>--</td></tr>\r\n        <tr><td>Telangana</td><td>70</td><td>--</td><td>--</td><td>--</td><td>12</td><td>58</td></tr>\r\n        <tr><td>Rajasthan</td><td>43</td><td>--</td><td>--</td><td>--</td><td>16</td><td>27</td></tr>\r\n        <tr><td>West Bengal</td><td>16</td><td>5</td><td>--</td><td>2</td><td>5</td><td>4</td></tr>\r\n        <tr><td>A &amp; N Islands</td><td>5</td><td>--</td><td>1</td><td>1</td><td>1</td><td>2</td></tr>\r\n        <tr><td>Sikkim</td><td>1</td><td>--</td><td>--</td><td>--</td><td>1</td><td>--</td></tr>\r\n        <tr><td>Uttar Pradesh</td><td>37</td><td>--</td><td>2</td><td>--</td><td>17</td><td>18</td></tr>\r\n        <tr><td>Maharashtra</td><td>242</td><td>59</td><td>37</td><td>72</td><td>--</td><td>74</td></tr>\r\n        <tr><td>Goa</td><td>3</td><td>--</td><td>3</td><td>--</td><td>--</td><td>--</td></tr>\r\n        <tr><td>Delhi</td><td>44</td><td>4</td><td>23</td><td>--</td><td>12</td><td>5</td></tr>\r\n        <tr><td>Uttarakhand</td><td>12</td><td>4</td><td>1</td><td>2</td><td>5</td><td>--</td></tr>\r\n        <tr><td>Arunachal Pradesh</td><td>48</td><td>--</td><td>3</td><td>--</td><td>9</td><td>36</td></tr>\r\n        <tr><td>Assam</td><td>235</td><td>--</td><td>31</td><td>--</td><td>34</td><td>170</td></tr>\r\n        <tr><td>Manipur</td><td>26</td><td>1</td><td>3</td><td>--</td><td>5</td><td>17</td></tr>\r\n        <tr><td>Meghalaya</td><td>60</td><td>2</td><td>--</td><td>1</td><td>11</td><td>46</td></tr>\r\n        <tr><td>Mizoram</td><td>22</td><td>--</td><td>--</td><td>2</td><td>5</td><td>15</td></tr>\r\n        <tr><td>Nagaland</td><td>39</td><td>--</td><td>--</td><td>--</td><td>8</td><td>31</td></tr>\r\n        <tr><td>Tripura</td><td>51</td><td>--</td><td>16</td><td>--</td><td>7</td><td>28</td></tr>\r\n        <tr><td>Kerala</td><td>25</td><td>2</td><td>--</td><td>6</td><td>5</td><td>12</td></tr>\r\n        <tr><td>Lakshadweep</td><td>3</td><td>--</td><td>2</td><td>--</td><td>1</td><td>--</td></tr>\r\n        <tr><th>Total</th><th>1409</th><th>91</th><th>226</th><th>86</th><th>196</th><th>810</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Vacancy Trend (Past Years)</h2>\r\n      <table>\r\n        <tbody><tr><th>Year</th><th>Vacancies</th></tr>\r\n        <tr><td>2026</td><td>TBA</td></tr>\r\n        <tr><td>2025</td><td>6589</td></tr>\r\n        <tr><td>2024</td><td>14191</td></tr>\r\n        <tr><td>2023</td><td>8773</td></tr>\r\n        <tr><td>2022</td><td>5486</td></tr>\r\n        <tr><td>2021</td><td>5454</td></tr>\r\n        <tr><td>2020</td><td>7870</td></tr>\r\n        <tr><td>2019</td><td>8593</td></tr>\r\n        <tr><td>2018</td><td>7200</td></tr>\r\n        <tr><td>2017</td><td>2043</td></tr>\r\n      </tbody></table></div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk 2026 Application Fee</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:900px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk Application Fee</h1>\r\n      <p>\r\n        The category-wise fee structure for the SBI Clerk online application is given below.\r\n        The application fee for the SBI Clerk exam is <b>Rs. 750/-</b> for the <b>General/OBC/EWS</b> category\r\n        and <b>NIL</b> for candidates belonging to <b>SC/ST/PWD</b> category (as per the notification).\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        Fee/Intimation charges once paid will <b>NOT</b> be refunded on any account, nor can it be held in reserve for\r\n        any other examination or selection. The application fee must be paid <b>online</b>.\r\n      </div>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Category</th>\r\n          <th>Application Fee</th>\r\n        </tr>\r\n        <tr><td>1</td><td>SC/ST/PWD</td><td>NIL</td></tr>\r\n        <tr><td>2</td><td>General/OBC/EWS</td><td>Rs. 750/- (App. fee including intimation charges)</td></tr>\r\n      </tbody></table>\r\n    </div>\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk 2026 - Selection Procedure &amp; Exam Pattern</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px;margin-top:10px}\r\n    .small{font-size:14px;color:#333}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk (Junior Associates) Selection Procedure</h1>\r\n      <p>\r\n        For selection to the Clerical Cadre through the SBI Clerk (Junior Associates) exam, candidates are selected through:\r\n      </p>\r\n      <ol>\r\n        <li>SBI Clerk Prelims</li>\r\n        <li>SBI Clerk Mains</li>\r\n        <li>Local Language Proficiency Test (LLPT)</li>\r\n      </ol>\r\n      <p>\r\n        All candidates must clear both exam phases to secure the appointment letter from SBI.\r\n        There is <b>no provision</b> for Inter Circle Transfer / Inter State Transfer for Junior Associates.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Trained apprentices of SBI may be given weightage in the Main Examination by awarding\r\n        <b>2.5%</b> of the maximum marks (i.e. <b>5 marks out of 200</b>) as bonus marks.</div></div></div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk Salary, Preparation, Result &amp; Cut Off</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px;margin-top:10px}\r\n    ul{margin:6px 0 0 18px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk Salary &amp; Pay Scale</h1>\r\n      <p>\r\n        The starting salary of the SBI Clerk is around <b>Rs. 46,000</b> and the pay scale is:\r\n      </p>\r\n      <p class=\"note\">\r\n        <b>Pay Scale:</b> Rs. 24050-1340/3-28070-1650/3-33020-2000/4-41020-2340/7-57400-4400/1-61800-2680/1-64480\r\n      </p>\r\n      <p>\r\n        The starting <b>Basic Pay</b> is <b>Rs. 26,730/-</b> (Rs. 24,050/- plus two advance increments admissible to graduates).\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Preparation</h2>\r\n      <p>\r\n        The primary resources for SBI Clerk preparation are <b>live online classes</b> and <b>mock tests</b>.\r\n        Attempting more mock tests helps improve speed, accuracy, and exam confidence.\r\n      </p>\r\n      <p>\r\n        SBI Clerk Mock Tests are designed to prepare you for both Prelims and Mains examinations and cover all important\r\n        topics from the syllabus, including:\r\n      </p>\r\n      <ul>\r\n        <li>Quantitative Aptitude</li>\r\n        <li>Reasoning Ability</li>\r\n        <li>English Language</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Result &amp; Cut Off</h2>\r\n      <p>\r\n        SBI releases results separately for both the Preliminary and Main exams. SBI also releases category-wise cut-offs\r\n        for both stages. Aspirants are required to meet the cut-offs for all sections to make it to the merit list.\r\n      </p>\r\n\r\n      <h3>SBI Clerk Prelims Cut-Off (2024) - General</h3>\r\n      <table>\r\n        <tbody><tr><th>States/UT</th><th>General</th></tr>\r\n        <tr><td>Andaman &amp; Nicobar</td><td>--</td></tr>\r\n        <tr><td>Andhra Pradesh</td><td>68.75</td></tr>\r\n        <tr><td>Arunachal Pradesh</td><td>68.75</td></tr>\r\n        <tr><td>Assam</td><td>60.75</td></tr>\r\n        <tr><td>Bihar</td><td>47.25</td></tr>\r\n        <tr><td>Chhattisgarh</td><td>29.5</td></tr>\r\n        <tr><td>Chandigarh</td><td>65.25</td></tr>\r\n        <tr><td>Delhi</td><td>67</td></tr>\r\n        <tr><td>Gujarat</td><td>47</td></tr>\r\n        <tr><td>Haryana</td><td>64</td></tr>\r\n        <tr><td>Himachal Pradesh</td><td>68.50</td></tr>\r\n        <tr><td>Jammu</td><td>66.50</td></tr>\r\n        <tr><td>Jharkhand</td><td>42.25</td></tr>\r\n        <tr><td>Karnataka</td><td>72.5</td></tr>\r\n        <tr><td>Kerala</td><td>64</td></tr>\r\n        <tr><td>Madhya Pradesh</td><td>49.25</td></tr>\r\n        <tr><td>Maharashtra</td><td>44.75</td></tr>\r\n        <tr><td>Meghalaya</td><td>54.75</td></tr>\r\n        <tr><td>Manipur</td><td>37</td></tr>\r\n        <tr><td>Odisha</td><td>64.25</td></tr>\r\n        <tr><td>Punjab</td><td>60.25</td></tr>\r\n        <tr><td>Rajasthan</td><td>59.5</td></tr>\r\n        <tr><td>Sikkim</td><td>39.75</td></tr>\r\n        <tr><td>Tamil Nadu</td><td>55.50</td></tr>\r\n        <tr><td>Telangana</td><td>60</td></tr>\r\n        <tr><td>Tripura</td><td>64</td></tr>\r\n        <tr><td>Uttar Pradesh</td><td>61.75</td></tr>\r\n        <tr><td>Uttarakhand</td><td>64.75</td></tr>\r\n        <tr><td>West Bengal</td><td>61.25</td></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  \r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI Clerk Exam Analysis</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI Clerk Exam Analysis</h1>\r\n      <p>\r\n        State Bank of India (SBI) conducts objective-type exams every year for the recruitment of clerical cadres.\r\n        Students often wait for the analysis and review to prepare for upcoming banking exams.\r\n      </p>\r\n      <p>\r\n        This analysis highlights the types of questions asked, level of difficulty, and whether any changes were introduced\r\n        in the exam. As per last year\'s review summary, the overall difficulty level of SBI Clerk Prelims was\r\n        <b>Easy to Moderate</b>.\r\n      </p>\r\n      <div class=\"note\">\r\n        This section-wise analysis can help you plan your preparation for the upcoming SBI Clerk exam.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Exam Analysis - English Language</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Topics</th>\r\n          <th>No. of Questions</th>\r\n          <th>Level</th>\r\n        </tr>\r\n        <tr><td>Reading Comprehension</td><td>8</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Error Detection</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Word Usage</td><td>3</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Sentence Rearrangement</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Word Swapping</td><td>4</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Cloze Test</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><th>Overall</th><th>30</th><th>Easy to Moderate</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Exam Analysis - Reasoning Ability</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Topics</th>\r\n          <th>No. of Questions</th>\r\n          <th>Level</th>\r\n        </tr>\r\n        <tr><td>Row Based Puzzle</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Circular Puzzle</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Floor/Flat Based Puzzle</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Syllogism (only a few, all, some)</td><td>3</td><td>Easy</td></tr>\r\n        <tr><td>Inequality</td><td>3</td><td>Easy</td></tr>\r\n        <tr><td>Blood Relations</td><td>4</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Order Ranking</td><td>4</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Meaningful Word</td><td>1</td><td>Easy</td></tr>\r\n        <tr><td>Pairing</td><td>1</td><td>Easy</td></tr>\r\n        <tr><td>Alphanumeric Series (letter, number, symbol)</td><td>4</td><td>Easy</td></tr>\r\n        <tr><th>Overall</th><th>35</th><th>Easy</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI Clerk Exam Analysis - Numerical Ability</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Topics</th>\r\n          <th>No. of Questions</th>\r\n          <th>Level</th>\r\n        </tr>\r\n        <tr><td>Data Interpretation (Bar Graph)</td><td>5</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Caselet DI</td><td>6</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Wrong Number Series</td><td>6</td><td>Easy to Moderate</td></tr>\r\n        <tr><td>Simplification</td><td>10</td><td>Easy</td></tr>\r\n        <tr><td>Arithmetic</td><td>8</td><td>Easy to Moderate</td></tr>\r\n        <tr><th>Overall</th><th>35</th><th>Easy to Moderate</th></tr>\r\n      </tbody></table></div>\r\n\r\n  </div>\r\n</div></div>\r\n\r\n\r\n\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>SBI Clerk FAQs</title>\r\n\r\n<style>\r\nbody{\r\n  font-family: Arial, sans-serif;\r\n  background:#f5f7fb;\r\n}\r\n\r\n.faq-section{\r\n  max-width:900px;\r\n  margin:50px auto;\r\n  padding:20px;\r\n}\r\n\r\n.faq-title{\r\n  text-align:center;\r\n  font-size:32px;\r\n  font-weight:700;\r\n  margin-bottom:30px;\r\n  color:#1a237e;\r\n}\r\n\r\n.faq-item{\r\n  background:#fff;\r\n  margin-bottom:12px;\r\n  border-radius:8px;\r\n  box-shadow:0 4px 10px rgba(0,0,0,0.08);\r\n  overflow:hidden;\r\n}\r\n\r\n.faq-question{\r\n  padding:16px 20px;\r\n  cursor:pointer;\r\n  font-weight:600;\r\n  display:flex;\r\n  justify-content:space-between;\r\n  align-items:center;\r\n}\r\n\r\n.faq-question:hover{\r\n  background:#f0f3ff;\r\n}\r\n\r\n.faq-answer{\r\n  padding:0 20px;\r\n  max-height:0;\r\n  overflow:hidden;\r\n  transition:max-height 0.3s ease;\r\n  color:#444;\r\n}\r\n\r\n.faq-item.active .faq-answer{\r\n  padding:15px 20px;\r\n  max-height:200px;\r\n}\r\n\r\n.icon{\r\n  font-size:20px;\r\n  transition:transform 0.3s;\r\n}\r\n\r\n.faq-item.active .icon{\r\n  transform:rotate(45deg);\r\n}\r\n</style>\r\n\r\n\r\n\r\n\r\n<div class=\"faq-section\">\r\n\r\n<h2 class=\"faq-title\">FAQs</h2></div><div class=\"accordion\" id=\"accordion_1770191344443\">\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingOne_accordion_1770191344443\">\r\n                                        <button class=\"accordion-button collapsed\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseOne_accordion_1770191344443\" aria-expanded=\"false\" aria-controls=\"collapseOne_accordion_1770191344443\">\r\n                                            <strong style=\"color: #1C56E1;\">Q1. What is the SBI Clerk exam?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseOne_accordion_1770191344443\" class=\"accordion-collapse collapse\" aria-labelledby=\"headingOne_accordion_1770191344443\" data-bs-parent=\"#accordion_1770191344443\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>The SBI Clerk exam is conducted by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">State Bank of India</span> to recruit Junior Associates (Customer Support &amp; Sales) in branches across India.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingTwo_accordion_1770191344443\">\r\n                                        <button class=\"accordion-button collapsed\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseTwo_accordion_1770191344443\" aria-expanded=\"false\" aria-controls=\"collapseTwo_accordion_1770191344443\">\r\n                                            <strong style=\"color: #1C56E1;\">Q2. What is the post offered in SBI Clerk recruitment?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseTwo_accordion_1770191344443\" class=\"accordion-collapse collapse\" aria-labelledby=\"headingTwo_accordion_1770191344443\" data-bs-parent=\"#accordion_1770191344443\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>The post offered is <strong data-start=\"440\" data-end=\"468\">Junior Associate (Clerk)</strong> in SBI branches.</p></div></div></div></div><div class=\"accordion\" id=\"accordion_1770191418972\">\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingOne_accordion_1770191418972\">\r\n                                        <button class=\"accordion-button collapsed active\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseOne_accordion_1770191418972\" aria-expanded=\"false\" aria-controls=\"collapseOne_accordion_1770191418972\">\r\n                                            <strong style=\"color: #1C56E1;\">Q3. What is the eligibility for SBI Clerk?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseOne_accordion_1770191418972\" class=\"accordion-collapse collapse\" aria-labelledby=\"headingOne_accordion_1770191418972\" data-bs-parent=\"#accordion_1770191418972\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>Candidates must have a <strong data-start=\"559\" data-end=\"580\">graduation degree</strong> from a recognized university and be between <strong data-start=\"625\" data-end=\"640\">20–28 years</strong> of age (age relaxation applies).</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingTwo_accordion_1770191418972\">\r\n                                        <button class=\"accordion-button active\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseTwo_accordion_1770191418972\" aria-expanded=\"true\" aria-controls=\"collapseTwo_accordion_1770191418972\">\r\n                                            <strong style=\"color: #1C56E1;\">Q4. Is there negative marking in SBI Clerk exam?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseTwo_accordion_1770191418972\" class=\"accordion-collapse collapse show\" aria-labelledby=\"headingTwo_accordion_1770191418972\" data-bs-parent=\"#accordion_1770191418972\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>Yes, <strong data-start=\"873\" data-end=\"900\">0.25 marks are deducted</strong> for every wrong answer.</p></div></div></div></div><div class=\"accordion\" id=\"accordion_1770191521681\">\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingOne_accordion_1770191521681\">\r\n                                        <button class=\"accordion-button active collapsed\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseOne_accordion_1770191521681\" aria-expanded=\"false\" aria-controls=\"collapseOne_accordion_1770191521681\">\r\n                                            <strong style=\"color: #1C56E1;\">Q.5 Is there an interview in SBI Clerk selection?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseOne_accordion_1770191521681\" class=\"accordion-collapse collapse\" aria-labelledby=\"headingOne_accordion_1770191521681\" data-bs-parent=\"#accordion_1770191521681\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>No, <strong data-start=\"1303\" data-end=\"1334\">there is no interview round</strong>.</p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"accordion-item\">\r\n                                    <h2 class=\"accordion-header\" id=\"headingTwo_accordion_1770191521681\">\r\n                                        <button class=\"accordion-button active\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#collapseTwo_accordion_1770191521681\" aria-expanded=\"true\" aria-controls=\"collapseTwo_accordion_1770191521681\">\r\n                                            <strong style=\"color: #1C56E1;\">Q.6 what is the salary of an SBI Clerk?</strong>\r\n                                        </button>\r\n                                    </h2>\r\n                                    <div id=\"collapseTwo_accordion_1770191521681\" class=\"accordion-collapse collapse show\" aria-labelledby=\"headingTwo_accordion_1770191521681\" data-bs-parent=\"#accordion_1770191521681\" style=\"\">\r\n                                        <div class=\"accordion-body\">\r\n                                            <p>The starting salary is around <strong data-start=\"1413\" data-end=\"1441\">₹29,000–32,000 per month</strong> including allowances.</p></div></div></div></div><div class=\"accordion\" id=\"accordion_1770191344443\"><div class=\"accordion-item\"><div id=\"collapseTwo_accordion_1770191344443\" class=\"accordion-collapse collapse\" aria-labelledby=\"headingTwo_accordion_1770191344443\" data-bs-parent=\"#accordion_1770191344443\" style=\"\"><div class=\"accordion-body\"><p>\r\n                            <br></p>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div><div class=\"faq-section\"><h2 class=\"faq-title\">\r\n                            <br></h2><div class=\"faq-item active\">\r\n</div>\r\n\r\n</div>\r\n\r\n<script>\r\nconst faqItems = document.querySelectorAll(\".faq-item\");\r\n\r\nfaqItems.forEach(item => {\r\n  item.querySelector(\".faq-question\").addEventListener(\"click\", () => {\r\n    item.classList.toggle(\"active\");\r\n  });\r\n});\r\n</script>\r\n\r\n\r\n\r\n<style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px}\r\n  </style><style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:10px;padding:10px;margin-top:10px}\r\n    .small{font-size:14px;color:#333}\r\n  </style><style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:10px;padding:14px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .small{font-size:14px;color:#333}\r\n  </style>', 0, '2026-01-22 09:50:24', '2026-02-18 07:32:42'),
(86, 8, 'HOME', '<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>SBI Specialist Officer (SO)</title>\r\n<style>\r\n    body {\r\n        font-family: Arial, sans-serif;\r\n        margin: 20px;\r\n        line-height: 1.6;\r\n    }\r\n    h1, h2, h3 {\r\n        color: #0b3d91;\r\n    }\r\n    table {\r\n        width: 100%;\r\n        border-collapse: collapse;\r\n        margin: 15px 0;\r\n    }\r\n    table, th, td {\r\n        border: 1px solid #ccc;\r\n    }\r\n    th, td {\r\n        padding: 10px;\r\n        text-align: left;\r\n    }\r\n    th {\r\n        background-color: #f2f2f2;\r\n    }\r\n    ul {\r\n        margin-left: 20px;\r\n    }\r\n</style>\r\n\r\n\r\n\r\n\r\n<h1>SBI Specialist Officer (SO)</h1>\r\n\r\n<p>\r\nThe SBI SO exam is conducted by the State Bank of India (SBI) to recruit Specialist Officers for\r\ntechnical and professional roles in the bank. The SBI SO notification will be released in June at\r\nwww.ibps.in. Start your journey toward becoming an SBI Specialist Officer with expert preparation,\r\nmock tests, and professional guidance to secure your future in the banking sector.\r\n</p>\r\n\r\n<h2>What is SBI SO?</h2>\r\n<p>SBI SO recruitment is for specialized departments, such as:</p>\r\n\r\n<ul>\r\n<li>IT Officer</li>\r\n<li>Assistant Manager (System)</li>\r\n<li>Deputy Manager</li>\r\n<li>Manager / Senior Manager</li>\r\n<li>Law Officer</li>\r\n<li>Risk Officer</li>\r\n<li>Data Analyst</li>\r\n<li>Security Officer</li>\r\n<li>Finance Officer</li>\r\n</ul>\r\n\r\n<p>Posts vary every year depending on bank requirements.</p>\r\n\r\n<h2>SBI SO Recruitment&nbsp; – Overview</h2>\r\n\r\n<table>\r\n<tbody><tr>\r\n<th>Particular</th>\r\n<th>Details</th>\r\n</tr>\r\n<tr>\r\n<td>Organization</td>\r\n<td>State Bank of India (SBI)</td>\r\n</tr>\r\n<tr>\r\n<td>Cadre</td>\r\n<td>Specialist Cadre Officer (SCO)</td>\r\n</tr>\r\n<tr>\r\n<td>Post Name</td>\r\n<td>VP Wealth (SRM), AVP Wealth (RM), Customer Relationship Executive</td>\r\n</tr>\r\n<tr>\r\n<td>Vacancy</td>\r\n<td>1146</td>\r\n</tr>\r\n<tr>\r\n<td>Advt No.</td>\r\n<td>CRPD/SCO/2025-26/17</td>\r\n</tr>\r\n<tr>\r\n<td>Mode of Application</td>\r\n<td>Online</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>Age Limit</td>\r\n<td>Varies Post wise</td>\r\n</tr>\r\n<tr>\r\n<td>Selection Process</td>\r\n<td>Shortlisting and Interview</td>\r\n</tr>\r\n<tr>\r\n<td>Official Website</td>\r\n<td>www.sbi.co.in</td>\r\n</tr>\r\n</tbody></table>\r\n\r\n<h2>SBI Specialist Officer Vacancy Details</h2>\r\n\r\n<p>\r\nThe State Bank of India (SBI) aims to fill vacancies for VP Wealth (SRM), AVP Wealth (RM),\r\nand Customer Relationship Executive posts. Post-wise and category-wise vacancy distribution\r\nis shown below.\r\n</p>\r\n\r\n<table>\r\n<tbody><tr>\r\n<th>Name of Post</th>\r\n<th>Category</th>\r\n<th>Total</th>\r\n<th>SC</th>\r\n<th>ST</th>\r\n<th>OBC</th>\r\n<th>EWS</th>\r\n<th>UR</th>\r\n</tr>\r\n\r\n<tr>\r\n<td>VP Wealth (SRM)</td>\r\n<td>Regular</td>\r\n<td>582</td>\r\n<td>77</td>\r\n<td>34</td>\r\n<td>119</td>\r\n<td>46</td>\r\n<td>188</td>\r\n</tr>\r\n\r\n<tr>\r\n<td></td>\r\n<td>Backlog</td>\r\n<td>15</td>\r\n<td>10</td>\r\n<td>17</td>\r\n<td>--</td>\r\n<td>--</td>\r\n<td>--</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>AVP Wealth (RM)</td>\r\n<td>Regular</td>\r\n<td>237</td>\r\n<td>33</td>\r\n<td>15</td>\r\n<td>52</td>\r\n<td>20</td>\r\n<td>82</td>\r\n</tr>\r\n\r\n<tr>\r\n<td></td>\r\n<td>Backlog</td>\r\n<td>--</td>\r\n<td>4</td>\r\n<td>--</td>\r\n<td>--</td>\r\n<td>--</td>\r\n<td>--</td>\r\n</tr>\r\n\r\n<tr>\r\n<td>Customer Relationship Executive</td>\r\n<td>Regular</td>\r\n<td>327</td>\r\n<td>47</td>\r\n<td>21</td>\r\n<td>73</td>\r\n<td>28</td>\r\n<td>115</td>\r\n</tr>\r\n\r\n<tr>\r\n<th>Total</th>\r\n<th></th>\r\n<th>1146</th>\r\n<th></th>\r\n<th></th>\r\n<th></th>\r\n<th></th>\r\n<th></th>\r\n</tr>\r\n\r\n</tbody></table>\r\n\r\n\r\n\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>SBI SCO 2025 Application Process</title>\r\n<style>\r\n    body {\r\n        font-family: Arial, sans-serif;\r\n        margin: 20px;\r\n        line-height: 1.6;\r\n    }\r\n    h2, h3 {\r\n        color: #0b3d91;\r\n    }\r\n    table {\r\n        width: 100%;\r\n        border-collapse: collapse;\r\n        margin: 15px 0;\r\n    }\r\n    table, th, td {\r\n        border: 1px solid #ccc;\r\n    }\r\n    th, td {\r\n        padding: 10px;\r\n        text-align: left;\r\n    }\r\n    th {\r\n        background-color: #f2f2f2;\r\n    }\r\n    ul, ol {\r\n        margin-left: 20px;\r\n    }\r\n</style>\r\n\r\n\r\n\r\n\r\n<h2>SBI SCO Application Fee</h2>\r\n\r\n<p>\r\nThe application fee for SBI SCO&nbsp; must be paid through online mode only.\r\nCandidates from the General, EWS, and OBC categories must pay Rs 750/-,\r\nwhile candidates belonging to SC/ST/PWD categories are exempted from payment.\r\n</p>\r\n\r\n<table>\r\n<tbody><tr>\r\n<th>Category</th>\r\n<th>Fee</th>\r\n</tr>\r\n<tr>\r\n<td>General, EWS, OBC</td>\r\n<td>Rs 750/-</td>\r\n</tr>\r\n<tr>\r\n<td>SC / ST / PWD</td>\r\n<td>0</td>\r\n</tr>\r\n</tbody></table>\r\n\r\n<h2>Steps to Apply Online for SBI SCO Exam</h2>\r\n\r\n<ol>\r\n<li>Click on the <strong>NEW REGISTRATION</strong> button on the top-right corner of the application portal.</li>\r\n\r\n<li>Enter basic details such as name, contact number, email ID, address, etc., then click <strong>Save &amp; Next</strong>.</li>\r\n\r\n<li>\r\nUpload photograph and signature in the required format:\r\n<ul>\r\n<li>Photograph size: 4.5 cm × 3.5 cm (passport size)</li>\r\n<li>Photo file size: 20 KB to 50 KB</li>\r\n<li>Signature file size: 10 KB to 20 KB</li>\r\n<li>Both must be clear and legible</li>\r\n</ul>\r\n</li>\r\n\r\n<li>Fill academic and professional qualification details and click <strong>Save &amp; Next</strong>.</li>\r\n\r\n<li>Preview the application form carefully since no changes are allowed afterward, then click <strong>Save &amp; Next</strong>.</li>\r\n\r\n<li>Pay the application fee online via Credit Card, Debit Card, or Net Banking.</li>\r\n\r\n<li>Click <strong>Final Submit</strong>. Registration ID and password will be sent via email and SMS.</li>\r\n</ol>\r\n\r\n<h2>Pre-Requisites for SBI SO Online Application</h2>\r\n\r\n<ul>\r\n<li>Keep photograph and signature ready before starting the application.</li>\r\n<li>Do NOT sign in CAPITAL LETTERS.</li>\r\n<li>Keep necessary documents ready for online payment.</li>\r\n<li>Provide a valid Email ID during registration.</li>\r\n</ul>\r\n\r\n<h2>SBI SO Selection Process</h2>\r\n\r\n<p>\r\nThe final selection is based on shortlisting and interview performance.\r\nCandidates are shortlisted based on qualification and experience as per bank requirements.\r\nThe interview carries <strong>100 marks</strong>, and the final merit list is prepared\r\nsolely on interview performance.\r\n</p>\r\n\r\n<h3>Selection Stages</h3>\r\n<ul>\r\n<li>Shortlisting</li>\r\n<li>Interview</li>\r\n</ul>\r\n\r\n\r\n\r\n\r\n\r\n<title>SBI SCO 2025 FAQs</title>\r\n\r\n<style>\r\nbody{\r\n    font-family: Arial, sans-serif;\r\n    margin: 20px;\r\n}\r\n\r\n\r\n.faq-item{\r\n    border: 1px solid #ccc;\r\n    border-radius: 5px;\r\n    margin-bottom: 10px;\r\n}\r\n\r\n.faq-question{\r\n    background: #f2f2f2;\r\n    padding: 12px;\r\n    cursor: pointer;\r\n    font-weight: bold;\r\n}\r\n\r\n.faq-answer{\r\n    display: none;\r\n    padding: 12px;\r\n    background: #fafafa;\r\n}\r\n</style>\r\n\r\n<script>\r\nfunction toggleFAQ(element){\r\n    var answer = element.nextElementSibling;\r\n\r\n    if(answer.style.display === \"block\"){\r\n        answer.style.display = \"none\";\r\n    } else {\r\n        answer.style.display = \"block\";\r\n    }\r\n}\r\n</script>\r\n\r\n\r\n\r\n\r\n<h2>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;FAQs</h2>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nWhat is SBI SO / SCO recruitment?\r\n</div>\r\n<div class=\"faq-answer\">\r\nSBI SO recruitment is conducted to hire professionals for specialized roles such as IT, Risk, Law, Finance, Data, and Wealth Management in SBI.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nHow can I apply for SBI SCO 2025?\r\n</div>\r\n<div class=\"faq-answer\">\r\nCandidates can apply online through the official SBI website under the careers section.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nWhat is the application fee for SBI SCO 2025?\r\n</div>\r\n<div class=\"faq-answer\">\r\nGeneral, EWS, and OBC candidates must pay Rs 750, while SC, ST, and PWD candidates are exempted from paying the fee.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nWhat is the selection process for SBI SO?\r\n</div>\r\n<div class=\"faq-answer\">\r\nThe selection process includes shortlisting followed by a personal interview.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nIs there a written exam for SBI SCO recruitment?\r\n</div>\r\n<div class=\"faq-answer\">\r\nRecruitment is generally based on shortlisting and interview, though it may vary depending on the post.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nWhat is the age limit for SBI SO posts?\r\n</div>\r\n<div class=\"faq-answer\">\r\nThe age limit varies depending on the post and experience requirements.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nCan final-year students apply?\r\n</div>\r\n<div class=\"faq-answer\">\r\nCandidates usually need required qualifications and experience at the time of application.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nIs work experience required for SBI SO posts?\r\n</div>\r\n<div class=\"faq-answer\">\r\nYes, most Specialist Officer positions require relevant work experience.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nHow will I receive my registration details?\r\n</div>\r\n<div class=\"faq-answer\">\r\nRegistration details are sent via email and SMS after successful submission.\r\n</div>\r\n</div>\r\n\r\n<div class=\"faq-item\">\r\n<div class=\"faq-question\" onclick=\"toggleFAQ(this)\">\r\nCan I edit my application after submission?\r\n</div>\r\n<div class=\"faq-answer\">\r\nNo, changes are not allowed after final submission of the application form.\r\n</div>\r\n</div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 0, '2026-01-22 11:02:00', '2026-02-18 05:18:22');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(87, 19, 'HOME', '  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam - Overview</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    ul{margin:6px 0 0 18px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam</h1>\r\n      <p>\r\n        The State Bank of India (SBI) conducts the <b>SBI PO Exam</b> every year to select eligible candidates for\r\n        <b>Probationary Officer (PO)</b> vacancies in different branches of SBI across India.\r\n        SBI PO is one of the most coveted jobs in the banking industry and is a dream job for millions of aspirants.\r\n      </p>\r\n      <p>\r\n        Last year, around <b>6.5 lakh</b> candidates applied, and it is expected that even more candidates will apply in the upcoming cycle.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Selection Stages:</b> The SBI PO exam is conducted in <b>3 phases</b> — Prelims, Mains, and GD/Interview.\r\n        Candidates must qualify each stage to move to the next. Final selection is based on merit.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Recruitment</h2>\r\n      <p>SBI PO is considered a premium job opportunity in the banking sector because of the following reasons:</p>\r\n      <ul>\r\n        <li>Brand value of SBI and the reputation associated with SBI PO post</li>\r\n        <li>A lucrative pay scale, which is among the highest in PSU Banks</li>\r\n        <li>Strong growth opportunities (a PO can progress to senior leadership levels)</li>\r\n        <li>Job satisfaction and social prestige</li>\r\n      </ul>\r\n      <p>\r\n        Before beginning your preparation, you should have a clear idea about the latest updates,\r\n        selection procedure, eligibility, exam pattern, syllabus, previous year cut-off, and more.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Notification</h2>\r\n      <p>\r\n        The State Bank of India (SBI) will release the official <b>SBI PO Notification PDF</b> with complete details to recruit\r\n        eligible candidates for Probationary Officer (PO) vacancies in different offices of SBI in India.\r\n      </p>\r\n      <p>\r\n        The official notification PDF will be available on the SBI Careers page:\r\n        <a href=\"https://www.sbi.co.in/web/careers\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in/web/careers</a>\r\n      </p>\r\n      <p class=\"note\">\r\n        <b>Tip:</b> Always read the notification carefully for eligibility, important dates, vacancy details,\r\n        exam pattern, syllabus, and category-wise reservations before applying.\r\n      </p>\r\n    </div>\r\n\r\n  \r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 - Exam Summary</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1000px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO&nbsp; - Exam Summary</h1>\r\n      <p>\r\n        The State Bank of India (SBI) has invited online applications from candidates who are within the age limit of\r\n        <b>21 to 30 years</b> and have completed <b>graduation</b> to fill vacant <b>Probationary Officer (PO)</b> posts.\r\n      </p>\r\n      <p>\r\n        The selection procedure includes three stages: <b>Prelims</b>, <b>Mains</b>, and <b>Interview</b>.\r\n        Candidates who clear all stages will be appointed as Probationary Officers and are liable to be posted anywhere in India.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Pay Scale:</b> Rs. 48,480/- (as provided in your text) <br>\r\n        <b>Approx. Salary:</b> Rs. 80,000 to 82,000 per month\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO&nbsp; Exam Summary (Table)</h2>\r\n      <table>\r\n        <tbody><tr><th>Organisation</th><td>State Bank of India (SBI)</td></tr>\r\n        <tr><th>Posts</th><td>Probationary Officers (PO)</td></tr>\r\n        <tr><th>Advt. No.</th><td>To be notified</td></tr>\r\n        <tr><th>Vacancies</th><td>To be notified</td></tr>\r\n        <tr><th>Age Limit</th><td>21 - 30 years</td></tr>\r\n        <tr><th>Education Qualification</th><td>Graduation</td></tr>\r\n        <tr><th>Mode of Application</th><td>Online</td></tr>\r\n        <tr><th>Frequency</th><td>Once in a year</td></tr>\r\n        <tr><th>Salary</th><td>Rs. 80,000 to 82,000 per month</td></tr>\r\n        <tr><th>Selection Process</th><td>Prelims, Mains and Interview</td></tr>\r\n        <tr><th>Probation Period</th><td>2 years</td></tr>\r\n        <tr><th>Job Location</th><td>Across India</td></tr>\r\n        <tr>\r\n          <th>Official Website</th>\r\n          <td><a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a></td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 Online Application</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:900px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    p{margin:8px 0}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n    <div class=\"card\">\r\n      <h1>SBI PO Online Application</h1>\r\n      <p>\r\n        The online application process for the SBI PO exam will begin with the release of the official notification PDF.\r\n        Candidates who have completed their <b>graduation</b> can submit their online applications by visiting the official website:\r\n        <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Tip:</b> Keep your scanned documents (photo, signature, ID proof, and educational certificates) ready before applying.\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n\r\n\r\n</div></div>\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 - Application Fee, How to Apply &amp; Selection Process</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ol,ul{margin:6px 0 0 18px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Application Fee</h1>\r\n      <p>\r\n        The category-wise fee structure for the SBI PO online application is given below.\r\n        Fee/Intimation charges once paid will <b>NOT</b> be refunded on any account, nor can they be held in reserve\r\n        for any other examination or selection. The application fee must be paid <b>online</b>.\r\n      </p>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Category</th>\r\n          <th>Application Fee</th>\r\n        </tr>\r\n        <tr><td>SC/ST/PWD</td><td>Nil</td></tr>\r\n        <tr><td>General and Others</td><td>Rs. 750/- (App. fee including intimation charges)</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Please verify the final fee details in the official notification PDF on the SBI careers page.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>How to Apply for SBI PO Recruitment?</h2>\r\n      <p>\r\n        Candidates willing to appear for SBI PO must submit their online applications at\r\n        <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>\r\n        before the last date to apply.\r\n      </p>\r\n\r\n      <ol>\r\n        <li>\r\n          Visit the official website of SBI:\r\n          <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>.\r\n        </li>\r\n        <li>\r\n          Scroll down and click on <b>Careers</b>, which opens:\r\n          <a href=\"https://sbi.co.in/web/careers\" target=\"_blank\" rel=\"noopener\">https://sbi.co.in/web/careers</a>.\r\n        </li>\r\n        <li>Click on <b>Current Openings</b> to view the list of ongoing recruitments.</li>\r\n        <li>\r\n          Click on <b>Recruitment for Probationary Officer</b>, download the notification PDF and read all details.\r\n        </li>\r\n        <li>Click on <b>Apply Online</b> and complete the registration process.</li>\r\n        <li>Enter personal details, educational qualifications, and other information asked in the form.</li>\r\n        <li>Upload documents, signature, and photograph in the permissible size.</li>\r\n        <li>Pay the application fee through online mode.</li>\r\n        <li>Submit the form and save/print it for future reference.</li>\r\n      </ol>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Recruitment Selection Process</h2>\r\n      <p>\r\n        The SBI PO recruitment exam is considered one of the premier public-sector bank exams in India.\r\n        The recruitment process for Probationary Officers at SBI consists of <b>3 stages</b>:\r\n      </p>\r\n\r\n      <ul>\r\n        <li>Preliminary Examination</li>\r\n        <li>Main Examination</li>\r\n        <li>GD/Interview</li>\r\n      </ul>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam Pattern - Prelims</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .muted{color:#444;font-size:14px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Pattern</h1>\r\n      <p>\r\n        State Bank of India conducts the SBI PO Exam in three phases: <b>Online Prelims</b>, <b>Mains</b> and\r\n        <b>Interview</b> to recruit Probationary Officers. To ace the SBI PO recruitment exam, aspirants must be\r\n        well-versed with the latest exam pattern.\r\n      </p>\r\n      <p>\r\n        As the vacancy has been reduced considerably as compared to last year, clearing the exam may be more competitive.\r\n        Prior knowledge of the SBI PO exam pattern is essential to plan an efficient preparation strategy.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Exam Pattern (Overview)</h2>\r\n      <p>\r\n        Along with the SBI PO notification, the bank revised the exam pattern for both Prelims and Mains.\r\n        The total marks for each phase remain the same, but the marks distribution may vary.\r\n      </p>\r\n      <ul>\r\n        <li>Candidate must qualify in all three stages: <b>Prelims, Mains &amp; Interview</b>.</li>\r\n        <li><b>Prelims</b> is qualifying in nature (marks not counted in final merit list).</li>\r\n        <li><b>Mains &amp; Interview</b> marks are considered for the final merit list.</li>\r\n        <li>Cut-off marks for each stage are decided by SBI.</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Prelims Exam Pattern</h2>\r\n      <p>\r\n        The first stage of SBI PO recruitment is the <b>Preliminary Exam</b>. Candidates must qualify this stage\r\n        to get shortlisted for the SBI PO Mains exam.\r\n      </p>\r\n\r\n      <h3>Important Points</h3>\r\n      <ol>\r\n        <li>There are <b>3 sections</b>: English Language, Quantitative Aptitude, and Reasoning Ability.</li>\r\n        <li>A total of <b>100 objective-type questions</b> are asked in prelims.</li>\r\n        <li>Total duration is <b>1 hour</b> (20 minutes for each section).</li>\r\n        <li>Prelims is <b>qualifying</b>; marks are <b>not</b> counted in the final merit list.</li>\r\n        <li>There is <b>no sectional cut-off</b> in prelims.</li>\r\n      </ol>\r\n\r\n      <div class=\"note\">\r\n        <b>Penalty for wrong answer:</b> 0.25 marks will be deducted for each wrong answer.\r\n        No deduction for unattempted questions.\r\n      </div>\r\n\r\n      <h3>SBI PO Prelims Exam Pattern (Revised)</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Name of Tests (Objective)</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>English Language</td><td>40</td><td>40</td><td>20 minutes</td></tr>\r\n        <tr><td>2</td><td>Quantitative Aptitude</td><td>30</td><td>30</td><td>20 minutes</td></tr>\r\n        <tr><td>3</td><td>Reasoning Ability</td><td>30</td><td>30</td><td>20 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>100</th><th>100</th><th>1 hour</th></tr>\r\n      </tbody></table>\r\n\r\n      <h3>Selection Criteria for Main Examination</h3>\r\n      <p class=\"muted\">\r\n        Category-wise merit list will be drawn on the basis of the <b>aggregate marks</b> scored in the Preliminary Exam.\r\n        There will be no sectional cut-off. Candidates numbering approximately <b>10 times</b> the number of vacancies in each category\r\n        will be shortlisted for the Main Examination from the top of the merit list.\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 Mains Exam Pattern</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .muted{color:#444;font-size:14px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Mains Exam Pattern</h1>\r\n      <p>\r\n        The SBI PO Mains exam consists of <b>Objective</b> and <b>Descriptive</b> sections. The pattern is explained below.\r\n      </p>\r\n\r\n      <h2>Key Highlights</h2>\r\n      <ol>\r\n        <li><b>Duration:</b> Objective test is 3 hours and Descriptive test is 30 minutes.</li>\r\n        <li>\r\n          <b>Objective Sections (4):</b> Reasoning &amp; Computer Aptitude, Data Analysis &amp; Interpretation,\r\n          General/Economy/Banking Awareness, and English Language.\r\n        </li>\r\n        <li><b>Descriptive Paper:</b> Conducted along with the online test with 2 questions.</li>\r\n        <li>\r\n          <b>Negative Marking:</b> 0.25 marks deducted for every wrong answer. No penalty for unattempted questions.\r\n        </li>\r\n        <li>\r\n          <b>Sectional Cut Off:</b> Sectional cut-off marks are applicable in Mains. Candidates must score minimum marks in each section.\r\n        </li>\r\n      </ol>\r\n\r\n      <div class=\"note\">\r\n        <b>Important:</b> The objective test has separate timing for each section.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Mains Exam Pattern (Objective + Descriptive)</h2>\r\n\r\n      <h3>Objective Test</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Name of Tests (Objective)</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>Reasoning &amp; Computer Aptitude</td><td>40</td><td>60</td><td>50 minutes</td></tr>\r\n        <tr><td>2</td><td>Data Analysis &amp; Interpretation</td><td>30</td><td>60</td><td>45 minutes</td></tr>\r\n        <tr><td>3</td><td>General/ Economy/ Banking Awareness</td><td>60</td><td>60</td><td>45 minutes</td></tr>\r\n        <tr><td>4</td><td>English Language</td><td>40</td><td>20</td><td>40 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>170</th><th>200</th><th>3 hours</th></tr>\r\n      </tbody></table>\r\n\r\n      <h3>Descriptive Test</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Test</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>Descriptive Test (Letter Writing &amp; Essay)</td><td>2</td><td>50</td><td>30 minutes</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Grand Total:</b> 250 marks (Objective: 200 + Descriptive: 50)\r\n      </div>\r\n\r\n      <p class=\"muted\">\r\n        (i) <b>Objective Test:</b> 3 hours duration, 4 sections, 170 questions for 200 marks. Separate timing for each section.<br>\r\n        (ii) <b>Descriptive Test:</b> 30 minutes duration, 2 questions for 50 marks (English Language: Letter Writing &amp; Essay).\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Interview Process &amp; Final Selection</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>Interview Process (GD-PI)</h1>\r\n      <p>\r\n        Candidates who clear both the <b>SBI PO Prelims</b> and <b>SBI PO Mains</b> exams will be called for a\r\n        <b>GD-PI session</b>, where they will face a panel of selectors. The discussion generally includes questions\r\n        related to the candidate’s background/experience, <b>General Knowledge</b>, and the <b>Banking Sector</b>.\r\n      </p>\r\n      <p>\r\n        It is essential to clear the Interview Process to ensure final selection in the SBI PO exam.\r\n        The qualifying marks for this round will be decided by SBI.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Marks for this stage:</b><br>\r\n        Group Discussion / Group Exercise: <b>20 marks</b><br>\r\n        Interview: <b>30 marks</b><br>\r\n        <b>Total:</b> 50 marks\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Final Selection</h2>\r\n      <p>\r\n        After the personal interview stage, SBI prepares a merit list in which the candidate’s score from the\r\n        <b>Mains Exam</b> and the <b>Group Exercise &amp; Interview</b> are considered. Based on the scores obtained\r\n        and the number of available vacancies, the final cut-off marks are declared.\r\n      </p>\r\n      <p>\r\n        Candidates who clear the final cut-off will be issued the <b>Appointment Letter</b> by the State Bank of India\r\n        for the post of Probationary Officer.\r\n      </p>\r\n\r\n      <h3>SBI PO Final Selection (Marks Distribution)</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Test</th>\r\n          <th>Main Exam</th>\r\n          <th>Group Exercise &amp; Interview</th>\r\n          <th>Total</th>\r\n        </tr>\r\n        <tr>\r\n          <td><b>Maximum Marks</b></td>\r\n          <td>250</td>\r\n          <td>50</td>\r\n          <td>300</td>\r\n        </tr>\r\n        <tr>\r\n          <td><b>Normalization Marks</b></td>\r\n          <td>75</td>\r\n          <td>25</td>\r\n          <td>100</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Final merit is prepared after applying normalization and considering the final cut-off decided by SBI.\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Syllabus &amp; Exam Pattern - Overview</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    ul{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Syllabus</h1>\r\n      <p>\r\n        The SBI PO syllabus is similar to other bank exams. For the preliminary exam, candidates mainly need to prepare\r\n        three sections: <b>Reasoning</b>, <b>Quantitative Aptitude</b>, and <b>English Language</b>.\r\n        Each section includes a wide range of topics.\r\n      </p>\r\n      <p>\r\n        It is recommended that candidates go through previous year papers to understand the topic-wise weightage\r\n        and prepare accordingly.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Prelims:</b> 100 questions from Reasoning Ability, Quantitative Aptitude &amp; English Language.<br>\r\n        <b>Mains:</b> Reasoning &amp; Computer Aptitude, Data Analysis &amp; Interpretation, General/Economy/Banking Awareness,\r\n        English Language + Descriptive Test.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus and Exam Pattern - Overview</h2>\r\n      <table>\r\n        <tbody><tr><th>Recruitment Body</th><td>State Bank of India (SBI)</td></tr>\r\n        <tr><th>Exam Name</th><td>SBI PO</td></tr>\r\n        <tr><th>Posts</th><td>Probationary Officer</td></tr>\r\n        <tr><th>Category</th><td>Syllabus</td></tr>\r\n        <tr><th>Mode of Exam</th><td>Online</td></tr>\r\n        <tr><th>No. of Questions</th><td>Prelims - 100<br>Mains - 155 (MCQs) + 2 (Descriptive)</td></tr>\r\n        <tr><th>Negative Marking</th><td>0.25</td></tr>\r\n        <tr><th>Selection Process</th><td>Prelims<br>Mains<br>Interview</td></tr>\r\n        <tr>\r\n          <th>Official Website</th>\r\n          <td><a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a></td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam Pattern &amp; Prelims Syllabus</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:12px;padding:12px}\r\n    .box h4{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Pattern</h1>\r\n      <p>\r\n        State Bank of India (SBI) conducts <b>two stages</b> of online examination: <b>Preliminary</b> and <b>Mains</b>.\r\n        Only candidates qualifying in both stages will be eligible to appear for the <b>Interview</b> round.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Negative Marking:</b> For each incorrect answer in the objective test, <b>0.25 marks</b> will be deducted.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Prelims Exam Pattern</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Subjects</th>\r\n          <th>English Language</th>\r\n          <th>Quantitative Aptitude</th>\r\n          <th>Reasoning Ability</th>\r\n        </tr>\r\n        <tr>\r\n          <th>No. of Questions</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>30</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Marks</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>30</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Duration</th>\r\n          <td>20 minutes</td>\r\n          <td>20 minutes</td>\r\n          <td>20 minutes</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Total Time:</b> 60 minutes (1 hour) &nbsp; | &nbsp; <b>Negative Marking:</b> 0.25 marks\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Mains Exam Pattern</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Subjects</th>\r\n          <th>Reasoning &amp; Computer Aptitude</th>\r\n          <th>Data Analysis &amp; Interpretation</th>\r\n          <th>General/ Economy/ Banking Awareness</th>\r\n          <th>English Language</th>\r\n          <th>Descriptive Test</th>\r\n        </tr>\r\n        <tr>\r\n          <th>No. of Questions</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>60</td>\r\n          <td>40</td>\r\n          <td>--</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Marks</th>\r\n          <td>60</td>\r\n          <td>60</td>\r\n          <td>60</td>\r\n          <td>20</td>\r\n          <td>50</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Duration</th>\r\n          <td>50 minutes</td>\r\n          <td>45 minutes</td>\r\n          <td>45 minutes</td>\r\n          <td>40 minutes</td>\r\n          <td>30 minutes</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Total Time:</b> 180 minutes (3 hours) &nbsp; | &nbsp;\r\n        <b>Negative Marking:</b> 0.25 marks (except Descriptive)\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus for Prelims Exam</h2>\r\n      <p>\r\n        Below are the section-wise topics on which SBI may ask questions in the SBI PO Prelims Exam.\r\n      </p>\r\n\r\n      <div class=\"grid\">\r\n        <div class=\"box\">\r\n          <h4>Quantitative Aptitude</h4>\r\n          <ul>\r\n            <li>Simplification / Approximation</li>\r\n            <li>Profit &amp; Loss</li>\r\n            <li>Mixtures &amp; Alligations</li>\r\n            <li>Permutation, Combination &amp; Probability</li>\r\n            <li>Work &amp; Time</li>\r\n            <li>Sequence &amp; Series</li>\r\n            <li>Simple Interest &amp; Compound Interest</li>\r\n            <li>Surds &amp; Indices</li>\r\n            <li>Mensuration (Cylinder, Cone, Sphere)</li>\r\n            <li>Time &amp; Distance</li>\r\n            <li>Data Interpretation</li>\r\n            <li>Ratio &amp; Proportion</li>\r\n            <li>Number Systems</li>\r\n            <li>Percentage</li>\r\n            <li>Quadratic Equation</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Reasoning</h4>\r\n          <ul>\r\n            <li>Alphanumeric Series</li>\r\n            <li>Directions</li>\r\n            <li>Logical Reasoning</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Ranking &amp; Order</li>\r\n            <li>Alphabet Test</li>\r\n            <li>Seating Arrangement</li>\r\n            <li>Coded Inequalities</li>\r\n            <li>Puzzle</li>\r\n            <li>Syllogism</li>\r\n            <li>Blood Relations</li>\r\n            <li>Coding-Decoding</li>\r\n            <li>Input-Output</li>\r\n            <li>Tabulation</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>English</h4>\r\n          <ul>\r\n            <li>Reading Comprehension</li>\r\n            <li>Fill in the Blanks</li>\r\n            <li>Cloze Test</li>\r\n            <li>Para Jumbles</li>\r\n            <li>Vocabulary</li>\r\n            <li>Puzzles &amp; Sentence Rearrangement</li>\r\n            <li>Paragraph Completion</li>\r\n            <li>Multiple Meaning / Error Spotting</li>\r\n            <li>Word Association</li>\r\n            <li>Sentence Improvement</li>\r\n            <li>Sentence Completion</li>\r\n            <li>Tenses Rules</li>\r\n            <li>Double Fillers</li>\r\n            <li>Word Usage</li>\r\n            <li>Inequalities</li>\r\n            <li>Pair Formation</li>\r\n          </ul>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Mains Syllabus</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:12px;padding:12px}\r\n    .box h4{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Mains Syllabus</h1>\r\n      <p>\r\n        The Mains Examination of the SBI PO exam includes 4 major areas:\r\n        <b>Reasoning + Computer Aptitude</b>, <b>English Language</b>,\r\n        <b>Data Analysis &amp; Interpretation</b>, and <b>General/Economy/Banking Awareness</b>.\r\n        The complete subject-wise syllabus is given below.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus for Main Exam (Subject-wise Topics)</h2>\r\n\r\n      <div class=\"grid\">\r\n\r\n        <div class=\"box\">\r\n          <h4>Data Analysis &amp; Interpretation</h4>\r\n          <ul>\r\n            <li>Tabular Graph</li>\r\n            <li>Line Graph</li>\r\n            <li>Bar Graph</li>\r\n            <li>Charts &amp; Tables</li>\r\n            <li>Missing Case DI</li>\r\n            <li>Radar Graph Caselet</li>\r\n            <li>Probability</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Double Line Up</li>\r\n            <li>Caselet DI</li>\r\n            <li>Permutation and Combination</li>\r\n            <li>Pie Charts</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Reasoning</h4>\r\n          <ul>\r\n            <li>Verbal Reasoning</li>\r\n            <li>Syllogism</li>\r\n            <li>Seating Arrangement &amp; Puzzles</li>\r\n            <li>Double Lineup</li>\r\n            <li>Scheduling</li>\r\n            <li>Input Output</li>\r\n            <li>Blood Relations</li>\r\n            <li>Directions and Distances</li>\r\n            <li>Ordering and Ranking</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Coding and Decoding</li>\r\n            <li>Code Inequalities</li>\r\n            <li>Course of Action</li>\r\n            <li>Critical Reasoning</li>\r\n            <li>Analytical and Decision Making</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>General/Economy/Banking Awareness</h4>\r\n          <ul>\r\n            <li>Current Affairs</li>\r\n            <li>Financial Awareness</li>\r\n            <li>General Knowledge</li>\r\n            <li>Static Awareness</li>\r\n            <li>Banking Terminologies Knowledge</li>\r\n            <li>Banking Awareness</li>\r\n            <li>Principles of Insurance</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>English Language</h4>\r\n          <ul>\r\n            <li>Reading Comprehension</li>\r\n            <li>Grammar</li>\r\n            <li>Verbal Ability</li>\r\n            <li>Vocabulary</li>\r\n            <li>Sentence Improvement</li>\r\n            <li>Word Association</li>\r\n            <li>Para Jumbles</li>\r\n            <li>Error Spotting</li>\r\n            <li>Cloze Test</li>\r\n            <li>Fill in the Blanks</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Computer (Computer Aptitude)</h4>\r\n          <ul>\r\n            <li>Internet</li>\r\n            <li>Memory</li>\r\n            <li>Keyboard Shortcuts</li>\r\n            <li>Computer Abbreviation</li>\r\n            <li>Microsoft Office</li>\r\n            <li>Computer Hardware</li>\r\n            <li>Computer Software</li>\r\n            <li>Computer Fundamentals / Terminologies</li>\r\n            <li>Networking</li>\r\n            <li>Number System</li>\r\n            <li>Operating System</li>\r\n            <li>Basic of Logic Gates</li>\r\n          </ul>\r\n        </div>\r\n\r\n      </div>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Reasoning and Computer topics are generally asked together as “Reasoning &amp; Computer Aptitude” in Mains.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Descriptive Test</h2>\r\n      <p>\r\n        The Descriptive Test is of <b>30 minutes</b> duration with <b>2 questions</b> for <b>50 marks</b>.\r\n        It is a Test of English Language and usually includes:\r\n      </p>\r\n      <ul>\r\n        <li>Letter Writing</li>\r\n        <li>Essay Writing</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Interview &amp; Final Merit List</h2>\r\n      <p>\r\n        Besides the preliminary and mains exams, SBI also conducts an <b>interview process</b> for candidates who qualify\r\n        the first two phases.\r\n      </p>\r\n      <p>\r\n        The final merit list is prepared based on the marks obtained by a candidate in the <b>Mains exam</b> and the\r\n        <b>Interview</b>.\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Recruitment - Important Points</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1000px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Recruitment - Important Points</h1>\r\n      <p>\r\n        Candidates should keep the following important points in mind regarding the SBI PO selection process:\r\n      </p>\r\n\r\n      <h2>1) Biometric Verification</h2>\r\n      <p>\r\n        To ensure an error-free and secure selection procedure, SBI may digitally capture the\r\n        <b>thumb impression</b> of the candidate to verify genuineness.\r\n        Any inconsistency in biometric verification may lead to <b>rejection of candidature</b> and\r\n        <b>punitive legal actions</b>.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Important:</b> Do not apply any external material like <b>ink, mehendi, chemicals</b>, etc. on your hands\r\n        during the examination/verification process.\r\n      </div>\r\n\r\n      <h2>2) Number of Attempts</h2>\r\n      <p>\r\n        The maximum number of chances is fixed for each category. Candidates who have used all chances are not eligible to apply.\r\n        <b>Appearing in Prelims is not counted as an attempt</b>, but <b>appearing in Mains is counted</b>.\r\n      </p>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Category</th>\r\n          <th>Number of Chances</th>\r\n        </tr>\r\n        <tr><td>General / EWS</td><td>4</td></tr>\r\n        <tr><td>General / EWS (PWD)</td><td>7</td></tr>\r\n        <tr><td>OBC / OBC (PWD)</td><td>7</td></tr>\r\n        <tr><td>SC / SC (PWD) / ST / ST (PWD)</td><td>No restriction</td></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 Exam Preparation</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:950px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:12px;padding:12px}\r\n    .box h3{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Preparation</h1>\r\n      <p>\r\n        SBI PO preparation must be done systematically, keeping the latest exam pattern in mind. Since the syllabus\r\n        covers a wide range of topics, it is important to choose the right study material and learning platform so you can\r\n        understand concepts clearly and practice a variety of questions.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        Candidates can prepare through <b>SBI PO Online Coaching</b> and <b>SBI PO Mock Tests</b> provided by expert faculty.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>How to Prepare Effectively</h2>\r\n\r\n      <div class=\"grid\">\r\n        <div class=\"box\">\r\n          <h3>1) Know the Exam Pattern</h3>\r\n          <p>\r\n            Understand the structure of Prelims and Mains, time limits for each section, and negative marking.\r\n            This helps you plan speed + accuracy from day one.\r\n          </p>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h3>2) Build Strong Basics</h3>\r\n          <p>\r\n            Start with fundamentals of Quant, Reasoning, and English. Focus on concepts first, then increase\r\n            difficulty level gradually.\r\n          </p>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h3>3) Follow a Daily Schedule</h3>\r\n          <p>\r\n            Study with a fixed routine: concept learning + sectional practice + revision.\r\n            Consistency matters more than long study hours once in a while.\r\n          </p>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h3>4) Practice Topic-wise Questions</h3>\r\n          <p>\r\n            Solve previous year-level questions after each topic. This improves understanding and helps identify weak areas.\r\n          </p>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h3>5) Attempt Mock Tests Regularly</h3>\r\n          <p>\r\n            Mock tests are the best way to improve speed, accuracy, and exam temperament.\r\n            Analyze every mock to reduce mistakes and improve score.\r\n          </p>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h3>6) Focus on Mains + Descriptive</h3>\r\n          <p>\r\n            Along with objective practice, prepare for descriptive (essay/letter) and improve typing speed.\r\n            Also give time to GA/Banking/Economy topics.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"note\">\r\n        <b>Pro Tip:</b> The best strategy is: <b>Learn → Practice → Mock → Analyze → Repeat</b>.\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Salary Structure</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Salary Structure</h1>\r\n      <p>\r\n        The initial in-hand salary of an SBI Probationary Officer (PO) recruited through SBI PO is approximately\r\n        <b>Rs. 80,000 to 82,000</b>. The salary structure below is prepared as per the revised SBI PO salary.\r\n      </p>\r\n      <p>\r\n        Candidates aspiring to become an SBI PO should be aware of the increased salary and allowances.\r\n        The approximate <b>CTC in a metro city like Mumbai</b> is around <b>Rs. 20.43 lakhs</b>.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Salary components like DA, HRA and other allowances may vary depending on posting location and bank rules.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Salary Structure in India</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Parameters</th>\r\n          <th>Amount (INR)</th>\r\n        </tr>\r\n        <tr><td>Basic Pay</td><td>Rs. 56,480 (Rs. 48,480 + advanced increments)</td></tr>\r\n        <tr><td>Special Allowance (SA)</td><td>Rs. 14,967</td></tr>\r\n        <tr><td>House Rent Allowance (HRA)</td><td>Rs. 4,518.40</td></tr>\r\n        <tr><td>Dearness Allowance (DA)</td><td>Rs. 15,327.01</td></tr>\r\n        <tr><td>Location Allowance</td><td>Rs. 1,200</td></tr>\r\n        <tr><td>Learning Allowance</td><td>Rs. 850</td></tr>\r\n        <tr><th>Gross Salary</th><th>Rs. 93,342.61</th></tr>\r\n        <tr><td>Deduction (PF/Income Tax/Professional Tax/Pension)</td><td>Rs. 12,993</td></tr>\r\n        <tr><th>Net Salary</th><th>Rs. 80,350</th></tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam Centres (Prelims &amp; Mains)</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1250px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px;font-size:14px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .scroll{overflow-x:auto}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Centre</h1>\r\n      <p>\r\n        While filling the online application form, applicants must enter their preferred exam centres for SBI PO\r\n        based on convenience. However, the Bank may allot an exam centre other than the choices made by a candidate\r\n        if seats are not available at the preferred venues.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Important:</b> All applicants have to provide <b>1 preference</b> each for the <b>Prelims</b> exam and the <b>Mains</b> exam.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Centres for SBI PO Prelims Exam</h2>\r\n      <div class=\"scroll\">\r\n        <table>\r\n          <tbody><tr>\r\n            <th>State Code</th>\r\n            <th>States/UT</th>\r\n            <th>Exam Centres for Prelims Exam</th>\r\n          </tr>\r\n          <tr><td>11</td><td>Andaman &amp; Nicobar</td><td>Port Blair</td></tr>\r\n          <tr><td>12</td><td>Andhra Pradesh</td><td>Chirala, Chittoor, Guntur, Kakinada, Kurnool, Nellore, Ongole, Puttur, Rajahmundhry, Srikakulam, Tirupati, Vijaywada, Vishakhapatnam, Vizianagaram</td></tr>\r\n          <tr><td>13</td><td>Arunachal Pradesh</td><td>Itanagar, Naharlagun</td></tr>\r\n          <tr><td>14</td><td>Assam</td><td>Dibrugarh, Guwahati, Jorhat, Kokrajhar, Silchar, Tezpur</td></tr>\r\n          <tr><td>15</td><td>Bihar</td><td>Arrah, Aurangabad, Bihar Sharif, Bhagalpur, Darbhanga, Gaya, Hajipur, Muzaffarpur, Patna, Purnea, Samastipur, Siwan</td></tr>\r\n          <tr><td>16</td><td>Chandigarh</td><td>Chandigarh</td></tr>\r\n          <tr><td>17</td><td>Chhattisgarh</td><td>Bhilai, Bilaspur, Raipur</td></tr>\r\n          <tr><td>18</td><td>Goa</td><td>Panaji, Verna</td></tr>\r\n          <tr><td>19</td><td>Gujarat</td><td>Ahmedabad, Anand, Gandhinagar, Himmatnagar, Jamnagar, Mehsana, Rajkot, Surat, Vadodara</td></tr>\r\n          <tr><td>20</td><td>Haryana</td><td>Ambala, Bahadurgarh, Hissar, Karnal, Kurukshetra, Panipat, Palwal, Sonipat, Yamunanagar</td></tr>\r\n          <tr><td>21</td><td>Himachal Pradesh</td><td>Baddi, Bilaspur, Dharamshala, Hamirpur, Kangra, Kullu, Mandi, Shimla, Sirmaur, Solan, Una</td></tr>\r\n          <tr><td>22</td><td>Jammu &amp; Kashmir</td><td>Jammu, Kathua, Samba, Srinagar</td></tr>\r\n          <tr><td>23</td><td>Jharkhand</td><td>Bokaro, Dhanbad, Hazaribag, Jamshedpur, Ranchi</td></tr>\r\n          <tr><td>24</td><td>Karnataka</td><td>Belgaum, Bengaluru, Bidar, Gulbarga, Hubli, Mangalore, Mysore, Shimoga, Udipi</td></tr>\r\n          <tr><td>25</td><td>Kerala</td><td>Alappuzha, Kannur, Kochi, Kollam, Kottayam, Kozhikode, Malappuram, Palakkad, Thrichur, Thiruvananthapuram</td></tr>\r\n          <tr><td>26</td><td>Lakshwadeep</td><td>Kavaratti</td></tr>\r\n          <tr><td>27</td><td>Madhya Pradesh</td><td>Bhopal, Gwalior, Indore, Jabalpur, Satna, Sagar, Ujjain</td></tr>\r\n          <tr><td>28</td><td>Maharashtra</td><td>Amaravati, Aurangabad, Chandrapur, Dhule, Jalgaon, Kolhapur, Latur, Mumbai/Thane/Navi Mumbai, Nagpur, Nanded, Nasik, Pune, Ratnagiri, Sangli, Satara</td></tr>\r\n          <tr><td>29</td><td>Manipur</td><td>Imphal</td></tr>\r\n          <tr><td>30</td><td>Meghalaya</td><td>Ri-Bhoi, Shillong</td></tr>\r\n          <tr><td>31</td><td>Mizoram</td><td>Aizawal</td></tr>\r\n          <tr><td>32</td><td>Nagaland</td><td>Kohima</td></tr>\r\n          <tr><td>33</td><td>Delhi - NCR</td><td>Delhi, Faridabad, Ghaziabad, Greater Noida, Gurgaon</td></tr>\r\n          <tr><td>34</td><td>Odisha</td><td>Angul, Balasore, Bargarh, Baripada, Berhampur (Ganjam), Bhubaneswar, Cuttack, Dhenkanal, Jharsuguda, Rourkela, Sambalpur</td></tr>\r\n          <tr><td>35</td><td>Puducherry</td><td>Puducherry</td></tr>\r\n          <tr><td>36</td><td>Punjab</td><td>Amritsar, Bhatinda, Fatehgarh Sahib, Jalandhar, Ludhiana, Mohali, Pathankot, Patiala, Phagwara, Sangrur</td></tr>\r\n          <tr><td>37</td><td>Rajasthan</td><td>Ajmer, Alwar, Bhilwara, Bikaner, Jaipur, Jodhpur, Kota, Sikar, Udaipur</td></tr>\r\n          <tr><td>38</td><td>Sikkim</td><td>Gangtok</td></tr>\r\n          <tr><td>39</td><td>Tamilnadu</td><td>Chennai, Coimbatore, Dindigul, Krishnagiri, Madurai, Nagercoil, Namakkal, Perambalur, Salem, Thanjavur, Thiruchirapalli, Tirunelvelli, Thoothukodi, Vellore</td></tr>\r\n          <tr><td>40</td><td>Telangana</td><td>Hyderabad, Karimnagar, Khammam, Warangal</td></tr>\r\n          <tr><td>41</td><td>Tripura</td><td>Agartala</td></tr>\r\n          <tr><td>42</td><td>Uttar Pradesh</td><td>Agra, Aligarh, Allahabad, Bareilly, Bulandshahar, Gorakhpur, Jhansi, Kanpur, Lucknow, Mathura, Meerut, Moradabad, Muzaffarnagar, Unnao, Varanasi</td></tr>\r\n          <tr><td>43</td><td>Uttarakhand</td><td>Dehradun, Haldwani, Haridwar, Roorkee</td></tr>\r\n          <tr><td>44</td><td>West Bengal</td><td>Asansol, Berhampur (West Bengal), Bardhaman, Durgapur, Hooghly, Howrah, Kalyani, Greater Kolkata, Siliguri</td></tr>\r\n        </tbody></table>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Centres for SBI PO Mains Exam</h2>\r\n      <div class=\"scroll\">\r\n        <table>\r\n          <tbody><tr>\r\n            <th>State Code</th>\r\n            <th>States/UT</th>\r\n            <th>Exam Centres for Mains Exam</th>\r\n          </tr>\r\n          <tr><td>11</td><td>Andaman &amp; Nicobar</td><td>Port Blair</td></tr>\r\n          <tr><td>12</td><td>Andhra Pradesh</td><td>Guntur, Kurnool, Vijaywada, Vishakhapatnam</td></tr>\r\n          <tr><td>13</td><td>Arunachal Pradesh</td><td>Itanagar</td></tr>\r\n          <tr><td>14</td><td>Assam</td><td>Guwahati</td></tr>\r\n          <tr><td>15</td><td>Bihar</td><td>Arrah, Hajipur, Patna</td></tr>\r\n          <tr><td>16</td><td>Chandigarh</td><td>Chandigarh</td></tr>\r\n          <tr><td>17</td><td>Chhattisgarh</td><td>Raipur</td></tr>\r\n          <tr><td>18</td><td>Goa</td><td>Panaji</td></tr>\r\n          <tr><td>19</td><td>Gujarat</td><td>Ahmedabad, Gandhinagar</td></tr>\r\n          <tr><td>20</td><td>Haryana</td><td>Bahadurgarh, Hissar</td></tr>\r\n          <tr><td>21</td><td>Himachal Pradesh</td><td>Shimla, Solan</td></tr>\r\n          <tr><td>22</td><td>Jammu &amp; Kashmir</td><td>Jammu, Srinagar</td></tr>\r\n          <tr><td>23</td><td>Jharkhand</td><td>Jamshedpur, Ranchi</td></tr>\r\n          <tr><td>24</td><td>Karnataka</td><td>Bengaluru</td></tr>\r\n          <tr><td>25</td><td>Kerala</td><td>Kochi, Thiruvananthapuram</td></tr>\r\n          <tr><td>26</td><td>Lakshwadeep</td><td>Kavaratti</td></tr>\r\n          <tr><td>27</td><td>Madhya Pradesh</td><td>Bhopal, Indore</td></tr>\r\n          <tr><td>28</td><td>Maharashtra</td><td>Aurangabad, Nagpur, Pune, Mumbai/Thane/Navi Mumbai</td></tr>\r\n          <tr><td>29</td><td>Manipur</td><td>Imphal</td></tr>\r\n          <tr><td>30</td><td>Meghalaya</td><td>Shillong</td></tr>\r\n          <tr><td>31</td><td>Mizoram</td><td>Aizawal</td></tr>\r\n          <tr><td>32</td><td>Nagaland</td><td>Kohima</td></tr>\r\n          <tr><td>33</td><td>Delhi - NCR</td><td>Delhi, Faridabad, Ghaziabad, Greater Noida, Gurgaon</td></tr>\r\n          <tr><td>34</td><td>Odisha</td><td>Bhubaneswar</td></tr>\r\n          <tr><td>35</td><td>Puducherry</td><td>Puducherry</td></tr>\r\n          <tr><td>36</td><td>Punjab</td><td>Bhatinda, Jalandhar, Ludhiana, Mohali, Patiala</td></tr>\r\n          <tr><td>37</td><td>Rajasthan</td><td>Jaipur</td></tr>\r\n          <tr><td>38</td><td>Sikkim</td><td>Gangtok</td></tr>\r\n          <tr><td>39</td><td>Tamilnadu</td><td>Chennai, Madurai, Tirunelvelli</td></tr>\r\n          <tr><td>40</td><td>Telangana</td><td>Hyderabad</td></tr>\r\n          <tr><td>41</td><td>Tripura</td><td>Agartala</td></tr>\r\n          <tr><td>42</td><td>Uttar Pradesh</td><td>Agra, Allahabad, Kanpur, Lucknow, Meerut, Varanasi</td></tr>\r\n          <tr><td>43</td><td>Uttarakhand</td><td>Dehradun</td></tr>\r\n          <tr><td>44</td><td>West Bengal</td><td>Hooghly, Kalyani, Greater Kolkata</td></tr>\r\n        </tbody></table>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Pre-Exam Training &amp; Result</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .scroll{overflow-x:auto}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Pre-Exam Training</h1>\r\n      <p>\r\n        State Bank of India may arrange <b>pre-examination training</b> for <b>SC/ST/Religious Minority Community</b>\r\n        candidates at certain centres, as per the guidelines issued by the Government of India. This initiative helps\r\n        aspirants in preparation if they cannot afford to enrol themselves at coaching centres.\r\n      </p>\r\n\r\n      <h2>Highlights of SBI PO Pre-Exam Training</h2>\r\n      <ul>\r\n        <li>Pre-exam training is usually a <b>6-day program</b>.</li>\r\n        <li>It is an <b>orientation program</b> for reserved and minority category candidates.</li>\r\n        <li>During training sessions, candidates are taught important questions and topics.</li>\r\n        <li>The training is conducted across India at different centres.</li>\r\n        <li>\r\n          Eligible candidates can avail the training at their <b>own cost</b> by selecting the relevant option\r\n          while applying online.\r\n        </li>\r\n      </ul>\r\n\r\n      <div class=\"note\">\r\n        SBI may add or remove training centres. Candidates opting for training should download the training call letter\r\n        using their registration number and password/date of birth from the bank’s website. No hard copy will be sent by post.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Indicative List of SBI PO Pre-Exam Training Centres</h2>\r\n      <div class=\"scroll\">\r\n        <table>\r\n          <tbody><tr>\r\n            <th>North India</th>\r\n            <th>South India</th>\r\n            <th>East India</th>\r\n            <th>West India</th>\r\n          </tr>\r\n          <tr><td>Agra</td><td>Bangalore</td><td>Agartala</td><td>Ahmedabad</td></tr>\r\n          <tr><td>Allahabad</td><td>Chennai</td><td>Aizwal</td><td>Akola</td></tr>\r\n          <tr><td>Bareilly</td><td>Coimbatore</td><td>Asansol</td><td>Aurangabad</td></tr>\r\n          <tr><td>Chandigarh</td><td>Ernakulam</td><td>Bhubaneswar</td><td>Indore</td></tr>\r\n          <tr><td>Dehradun</td><td>Gulbarga</td><td>Berhampur (Ganjam)</td><td>Bhopal</td></tr>\r\n          <tr><td>Gorakhpur</td><td>Hubli</td><td>Dibrugarh</td><td>Jabalpur</td></tr>\r\n          <tr><td>Jaipur</td><td>Hyderabad</td><td>Gangtok</td><td>Mumbai</td></tr>\r\n          <tr><td>Kanpur</td><td>Madurai</td><td>Guwahati</td><td>Nagpur</td></tr>\r\n          <tr><td>Lucknow</td><td>Mysore</td><td>Imphal</td><td>Panaji (Goa)</td></tr>\r\n          <tr><td>Meerut</td><td>Port Blair</td><td>Itanagar</td><td>Pune</td></tr>\r\n          <tr><td>New Delhi</td><td>Tirupati</td><td>Kohima</td><td>Raipur</td></tr>\r\n          <tr><td>Srinagar</td><td>Vishakhapatnam</td><td>Kolkata</td><td>Vadodara</td></tr>\r\n          <tr><td>Varanasi</td><td>Vijayawada</td><td>Patna</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Purnea</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Ranchi</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Sambalpur</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Silchar</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Siliguri</td><td>--</td></tr>\r\n          <tr><td>--</td><td>--</td><td>Shillong</td><td>--</td></tr>\r\n        </tbody></table>\r\n      </div>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> “--” indicates no city mentioned in your list for that specific region row.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Result</h1>\r\n      <p>\r\n        All results related to SBI PO will be available on the official website of SBI. The SBI PO result is released\r\n        after each phase of the exam is completed.\r\n      </p>\r\n\r\n      <h2>Result Stages</h2>\r\n      <ul>\r\n        <li><b>Prelims Result:</b> Determines eligibility for the SBI PO Mains exam.</li>\r\n        <li><b>Mains + Interview:</b> A cumulative score is used to prepare the final merit list.</li>\r\n        <li>\r\n          The merit list is prepared in descending order of marks obtained by candidates. Candidates who make it to\r\n          the merit list are issued the <b>appointment letter</b>.\r\n        </li>\r\n      </ul>\r\n\r\n      <div class=\"note\">\r\n        <b>Final Merit:</b> Based on Mains + Interview performance (as per the process described in your content).\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Cut Off</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:900px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Cut Off</h1>\r\n      <p>\r\n        SBI PO Cut-Off for the year will be declared by the State Bank of India after the results of each phase\r\n        are announced. The cut-off for the <b>Preliminary</b> phase will be released after the prelims result,\r\n        and the cut-off for the <b>Mains</b> exam will be released after the mains result.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        To estimate the expected cut-off, candidates should check previous year cut-offs. Below is the SBI PO Prelims Cut-Off (2024) as provided.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Prelims Cut Off 2024</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Category</th>\r\n          <th>Cut-Off Marks</th>\r\n        </tr>\r\n        <tr><td>General</td><td>61.75</td></tr>\r\n        <tr><td>SC</td><td>55</td></tr>\r\n        <tr><td>ST</td><td>49</td></tr>\r\n        <tr><td>OBC</td><td>60.50</td></tr>\r\n        <tr><td>EWS</td><td>60.25</td></tr>\r\n        <tr><td>VI</td><td>47.50</td></tr>\r\n        <tr><td>HI</td><td>19.75</td></tr>\r\n        <tr><td>LD</td><td>49.75</td></tr>\r\n        <tr><td>D&amp;E</td><td>9.50</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Cut-offs vary each year based on exam difficulty, number of vacancies, and performance of candidates.\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 0, '2026-01-22 12:08:07', '2026-01-22 12:09:49');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(88, 19, 'Eligibility Criteria', '\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Eligibility Criteria &amp; Online Application</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Eligibility Criteria</h1>\r\n      <p>\r\n        A candidate must fulfil the following <b>two criteria</b> to be eligible for the SBI PO Exam:\r\n        <b>Educational Qualification</b> and <b>Age Limit</b>.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Educational Qualification</h2>\r\n      <p>\r\n        The candidate must be a <b>graduate in any discipline</b> from a recognised University or any equivalent\r\n        qualification recognised as such by the Central Government.\r\n      </p>\r\n      <ul>\r\n        <li>\r\n          Candidates in the <b>final year/semester</b> of graduation may apply provisionally. If called for an interview,\r\n          they must produce proof of having passed the graduation examination.\r\n        </li>\r\n        <li>\r\n          Candidates with an <b>Integrated Dual Degree (IDD)</b> certificate must ensure that the date of passing the IDD\r\n          is as mentioned in the notification.\r\n        </li>\r\n        <li>\r\n          Candidates with a <b>Chartered Accountant (CA)</b> certification may also apply.\r\n        </li>\r\n      </ul>\r\n\r\n      <div class=\"note\">\r\n        <b>Tip:</b> Keep graduation mark sheets/degree (or provisional proof for final-year candidates) ready before applying.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Age Limit</h2>\r\n      <p>\r\n        The candidate must be between <b>21 years to 30 years</b>, i.e. candidates must have been born\r\n        <b>not later than 01.04.2005</b> and <b>not earlier than 02.04.1996</b> (both days inclusive).\r\n      </p>\r\n\r\n      <h3>SBI PO Age Relaxation</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Category</th>\r\n          <th>Age Relaxation (in years)</th>\r\n        </tr>\r\n        <tr><td>Other Backward Classes (OBC) (Non-Creamy Layer)</td><td>3 years</td></tr>\r\n        <tr><td>Scheduled Castes / Scheduled Tribes (SC/ST)</td><td>5 years</td></tr>\r\n        <tr>\r\n          <td>Persons with Benchmark Disabilities (PwBD)</td>\r\n          <td>\r\n            PwBD (UR/EWS) - 10 years<br>\r\n            PwBD (OBC) - 13 years<br>\r\n            PwBD (SC/ST) - 15 years\r\n          </td>\r\n        </tr>\r\n        <tr><td>Ex-Servicemen</td><td>5 years</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Age relaxations are applicable as per rules and must be supported with valid certificates.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Online Application</h2>\r\n      <p>\r\n        The online application process for the SBI PO Exam will begin with the release of the official notification PDF.\r\n        Candidates who have completed graduation can apply online by visiting:\r\n        <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Reminder:</b> Always read the official notification carefully before filling the online form.\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 - Application Fee, How to Apply &amp; Selection Process</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ol,ul{margin:6px 0 0 18px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO 2026 Application Fee</h1>\r\n      <p>\r\n        The category-wise fee structure for the SBI PO online application is given below.\r\n        Fee/Intimation charges once paid will <b>NOT</b> be refunded on any account, nor can they be held in reserve\r\n        for any other examination or selection. The application fee must be paid <b>online</b>.\r\n      </p>\r\n\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Category</th>\r\n          <th>Application Fee</th>\r\n        </tr>\r\n        <tr><td>SC/ST/PWD</td><td>Nil</td></tr>\r\n        <tr><td>General and Others</td><td>Rs. 750/- (App. fee including intimation charges)</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Please verify the final fee details in the official notification PDF on the SBI careers page.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>How to Apply for SBI PO Recruitment?</h2>\r\n      <p>\r\n        Candidates willing to appear for SBI PO must submit their online applications at\r\n        <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>\r\n        before the last date to apply.\r\n      </p>\r\n\r\n      <ol>\r\n        <li>\r\n          Visit the official website of SBI:\r\n          <a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a>.\r\n        </li>\r\n        <li>\r\n          Scroll down and click on <b>Careers</b>, which opens:\r\n          <a href=\"https://sbi.co.in/web/careers\" target=\"_blank\" rel=\"noopener\">https://sbi.co.in/web/careers</a>.\r\n        </li>\r\n        <li>Click on <b>Current Openings</b> to view the list of ongoing recruitments.</li>\r\n        <li>\r\n          Click on <b>Recruitment for Probationary Officer</b>, download the notification PDF and read all details.\r\n        </li>\r\n        <li>Click on <b>Apply Online</b> and complete the registration process.</li>\r\n        <li>Enter personal details, educational qualifications, and other information asked in the form.</li>\r\n        <li>Upload documents, signature, and photograph in the permissible size.</li>\r\n        <li>Pay the application fee through online mode.</li>\r\n        <li>Submit the form and save/print it for future reference.</li>\r\n      </ol>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Recruitment Selection Process</h2>\r\n      <p>\r\n        The SBI PO recruitment exam is considered one of the premier public-sector bank exams in India.\r\n        The recruitment process for Probationary Officers at SBI consists of <b>3 stages</b>:\r\n      </p>\r\n\r\n      <ul>\r\n        <li>Preliminary Examination</li>\r\n        <li>Main Examination</li>\r\n        <li>GD/Interview</li>\r\n      </ul>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n', 0, '2026-01-22 12:08:29', '2026-01-22 12:08:29'),
(89, 19, 'Exam Pattern', '\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam Pattern - Prelims</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .muted{color:#444;font-size:14px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Pattern</h1>\r\n      <p>\r\n        State Bank of India conducts the SBI PO Exam in three phases: <b>Online Prelims</b>, <b>Mains</b> and\r\n        <b>Interview</b> to recruit Probationary Officers. To ace the SBI PO recruitment exam, aspirants must be\r\n        well-versed with the latest exam pattern.\r\n      </p>\r\n      <p>\r\n        As the vacancy has been reduced considerably as compared to last year, clearing the exam may be more competitive.\r\n        Prior knowledge of the SBI PO exam pattern is essential to plan an efficient preparation strategy.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Exam Pattern (Overview)</h2>\r\n      <p>\r\n        Along with the SBI PO notification, the bank revised the exam pattern for both Prelims and Mains.\r\n        The total marks for each phase remain the same, but the marks distribution may vary.\r\n      </p>\r\n      <ul>\r\n        <li>Candidate must qualify in all three stages: <b>Prelims, Mains &amp; Interview</b>.</li>\r\n        <li><b>Prelims</b> is qualifying in nature (marks not counted in final merit list).</li>\r\n        <li><b>Mains &amp; Interview</b> marks are considered for the final merit list.</li>\r\n        <li>Cut-off marks for each stage are decided by SBI.</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Prelims Exam Pattern</h2>\r\n      <p>\r\n        The first stage of SBI PO recruitment is the <b>Preliminary Exam</b>. Candidates must qualify this stage\r\n        to get shortlisted for the SBI PO Mains exam.\r\n      </p>\r\n\r\n      <h3>Important Points</h3>\r\n      <ol>\r\n        <li>There are <b>3 sections</b>: English Language, Quantitative Aptitude, and Reasoning Ability.</li>\r\n        <li>A total of <b>100 objective-type questions</b> are asked in prelims.</li>\r\n        <li>Total duration is <b>1 hour</b> (20 minutes for each section).</li>\r\n        <li>Prelims is <b>qualifying</b>; marks are <b>not</b> counted in the final merit list.</li>\r\n        <li>There is <b>no sectional cut-off</b> in prelims.</li>\r\n      </ol>\r\n\r\n      <div class=\"note\">\r\n        <b>Penalty for wrong answer:</b> 0.25 marks will be deducted for each wrong answer.\r\n        No deduction for unattempted questions.\r\n      </div>\r\n\r\n      <h3>SBI PO Prelims Exam Pattern (Revised)</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Name of Tests (Objective)</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>English Language</td><td>40</td><td>40</td><td>20 minutes</td></tr>\r\n        <tr><td>2</td><td>Quantitative Aptitude</td><td>30</td><td>30</td><td>20 minutes</td></tr>\r\n        <tr><td>3</td><td>Reasoning Ability</td><td>30</td><td>30</td><td>20 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>100</th><th>100</th><th>1 hour</th></tr>\r\n      </tbody></table>\r\n\r\n      <h3>Selection Criteria for Main Examination</h3>\r\n      <p class=\"muted\">\r\n        Category-wise merit list will be drawn on the basis of the <b>aggregate marks</b> scored in the Preliminary Exam.\r\n        There will be no sectional cut-off. Candidates numbering approximately <b>10 times</b> the number of vacancies in each category\r\n        will be shortlisted for the Main Examination from the top of the merit list.\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO 2026 Mains Exam Pattern</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .muted{color:#444;font-size:14px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Mains Exam Pattern</h1>\r\n      <p>\r\n        The SBI PO Mains exam consists of <b>Objective</b> and <b>Descriptive</b> sections. The pattern is explained below.\r\n      </p>\r\n\r\n      <h2>Key Highlights</h2>\r\n      <ol>\r\n        <li><b>Duration:</b> Objective test is 3 hours and Descriptive test is 30 minutes.</li>\r\n        <li>\r\n          <b>Objective Sections (4):</b> Reasoning &amp; Computer Aptitude, Data Analysis &amp; Interpretation,\r\n          General/Economy/Banking Awareness, and English Language.\r\n        </li>\r\n        <li><b>Descriptive Paper:</b> Conducted along with the online test with 2 questions.</li>\r\n        <li>\r\n          <b>Negative Marking:</b> 0.25 marks deducted for every wrong answer. No penalty for unattempted questions.\r\n        </li>\r\n        <li>\r\n          <b>Sectional Cut Off:</b> Sectional cut-off marks are applicable in Mains. Candidates must score minimum marks in each section.\r\n        </li>\r\n      </ol>\r\n\r\n      <div class=\"note\">\r\n        <b>Important:</b> The objective test has separate timing for each section.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Mains Exam Pattern (Objective + Descriptive)</h2>\r\n\r\n      <h3>Objective Test</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>S. No.</th>\r\n          <th>Name of Tests (Objective)</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>1</td><td>Reasoning &amp; Computer Aptitude</td><td>40</td><td>60</td><td>50 minutes</td></tr>\r\n        <tr><td>2</td><td>Data Analysis &amp; Interpretation</td><td>30</td><td>60</td><td>45 minutes</td></tr>\r\n        <tr><td>3</td><td>General/ Economy/ Banking Awareness</td><td>60</td><td>60</td><td>45 minutes</td></tr>\r\n        <tr><td>4</td><td>English Language</td><td>40</td><td>20</td><td>40 minutes</td></tr>\r\n        <tr><th colspan=\"2\">Total</th><th>170</th><th>200</th><th>3 hours</th></tr>\r\n      </tbody></table>\r\n\r\n      <h3>Descriptive Test</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Test</th>\r\n          <th>No. of Questions</th>\r\n          <th>Maximum Marks</th>\r\n          <th>Duration</th>\r\n        </tr>\r\n        <tr><td>Descriptive Test (Letter Writing &amp; Essay)</td><td>2</td><td>50</td><td>30 minutes</td></tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Grand Total:</b> 250 marks (Objective: 200 + Descriptive: 50)\r\n      </div>\r\n\r\n      <p class=\"muted\">\r\n        (i) <b>Objective Test:</b> 3 hours duration, 4 sections, 170 questions for 200 marks. Separate timing for each section.<br>\r\n        (ii) <b>Descriptive Test:</b> 30 minutes duration, 2 questions for 50 marks (English Language: Letter Writing &amp; Essay).\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Interview Process &amp; Final Selection</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1050px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    ul,ol{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>Interview Process (GD-PI)</h1>\r\n      <p>\r\n        Candidates who clear both the <b>SBI PO Prelims</b> and <b>SBI PO Mains</b> exams will be called for a\r\n        <b>GD-PI session</b>, where they will face a panel of selectors. The discussion generally includes questions\r\n        related to the candidate’s background/experience, <b>General Knowledge</b>, and the <b>Banking Sector</b>.\r\n      </p>\r\n      <p>\r\n        It is essential to clear the Interview Process to ensure final selection in the SBI PO exam.\r\n        The qualifying marks for this round will be decided by SBI.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Marks for this stage:</b><br>\r\n        Group Discussion / Group Exercise: <b>20 marks</b><br>\r\n        Interview: <b>30 marks</b><br>\r\n        <b>Total:</b> 50 marks\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Final Selection</h2>\r\n      <p>\r\n        After the personal interview stage, SBI prepares a merit list in which the candidate’s score from the\r\n        <b>Mains Exam</b> and the <b>Group Exercise &amp; Interview</b> are considered. Based on the scores obtained\r\n        and the number of available vacancies, the final cut-off marks are declared.\r\n      </p>\r\n      <p>\r\n        Candidates who clear the final cut-off will be issued the <b>Appointment Letter</b> by the State Bank of India\r\n        for the post of Probationary Officer.\r\n      </p>\r\n\r\n      <h3>SBI PO Final Selection (Marks Distribution)</h3>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Test</th>\r\n          <th>Main Exam</th>\r\n          <th>Group Exercise &amp; Interview</th>\r\n          <th>Total</th>\r\n        </tr>\r\n        <tr>\r\n          <td><b>Maximum Marks</b></td>\r\n          <td>250</td>\r\n          <td>50</td>\r\n          <td>300</td>\r\n        </tr>\r\n        <tr>\r\n          <td><b>Normalization Marks</b></td>\r\n          <td>75</td>\r\n          <td>25</td>\r\n          <td>100</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Final merit is prepared after applying normalization and considering the final cut-off decided by SBI.\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n', 0, '2026-01-22 12:08:57', '2026-01-22 12:08:57'),
(90, 19, 'Exam Syllabus', '\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Syllabus &amp; Exam Pattern - Overview</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1100px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    p{margin:8px 0}\r\n    ul{margin:6px 0 0 18px}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    a{color:#0b57d0;text-decoration:none}\r\n    a:hover{text-decoration:underline}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Syllabus</h1>\r\n      <p>\r\n        The SBI PO syllabus is similar to other bank exams. For the preliminary exam, candidates mainly need to prepare\r\n        three sections: <b>Reasoning</b>, <b>Quantitative Aptitude</b>, and <b>English Language</b>.\r\n        Each section includes a wide range of topics.\r\n      </p>\r\n      <p>\r\n        It is recommended that candidates go through previous year papers to understand the topic-wise weightage\r\n        and prepare accordingly.\r\n      </p>\r\n\r\n      <div class=\"note\">\r\n        <b>Prelims:</b> 100 questions from Reasoning Ability, Quantitative Aptitude &amp; English Language.<br>\r\n        <b>Mains:</b> Reasoning &amp; Computer Aptitude, Data Analysis &amp; Interpretation, General/Economy/Banking Awareness,\r\n        English Language + Descriptive Test.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus and Exam Pattern - Overview</h2>\r\n      <table>\r\n        <tbody><tr><th>Recruitment Body</th><td>State Bank of India (SBI)</td></tr>\r\n        <tr><th>Exam Name</th><td>SBI PO</td></tr>\r\n        <tr><th>Posts</th><td>Probationary Officer</td></tr>\r\n        <tr><th>Category</th><td>Syllabus</td></tr>\r\n        <tr><th>Mode of Exam</th><td>Online</td></tr>\r\n        <tr><th>No. of Questions</th><td>Prelims - 100<br>Mains - 155 (MCQs) + 2 (Descriptive)</td></tr>\r\n        <tr><th>Negative Marking</th><td>0.25</td></tr>\r\n        <tr><th>Selection Process</th><td>Prelims<br>Mains<br>Interview</td></tr>\r\n        <tr>\r\n          <th>Official Website</th>\r\n          <td><a href=\"https://www.sbi.co.in\" target=\"_blank\" rel=\"noopener\">www.sbi.co.in</a></td>\r\n        </tr>\r\n      </tbody></table>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Exam Pattern &amp; Prelims Syllabus</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:12px;padding:12px}\r\n    .box h4{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Exam Pattern</h1>\r\n      <p>\r\n        State Bank of India (SBI) conducts <b>two stages</b> of online examination: <b>Preliminary</b> and <b>Mains</b>.\r\n        Only candidates qualifying in both stages will be eligible to appear for the <b>Interview</b> round.\r\n      </p>\r\n      <div class=\"note\">\r\n        <b>Negative Marking:</b> For each incorrect answer in the objective test, <b>0.25 marks</b> will be deducted.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Prelims Exam Pattern</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Subjects</th>\r\n          <th>English Language</th>\r\n          <th>Quantitative Aptitude</th>\r\n          <th>Reasoning Ability</th>\r\n        </tr>\r\n        <tr>\r\n          <th>No. of Questions</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>30</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Marks</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>30</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Duration</th>\r\n          <td>20 minutes</td>\r\n          <td>20 minutes</td>\r\n          <td>20 minutes</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Total Time:</b> 60 minutes (1 hour) &nbsp; | &nbsp; <b>Negative Marking:</b> 0.25 marks\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Mains Exam Pattern</h2>\r\n      <table>\r\n        <tbody><tr>\r\n          <th>Subjects</th>\r\n          <th>Reasoning &amp; Computer Aptitude</th>\r\n          <th>Data Analysis &amp; Interpretation</th>\r\n          <th>General/ Economy/ Banking Awareness</th>\r\n          <th>English Language</th>\r\n          <th>Descriptive Test</th>\r\n        </tr>\r\n        <tr>\r\n          <th>No. of Questions</th>\r\n          <td>40</td>\r\n          <td>30</td>\r\n          <td>60</td>\r\n          <td>40</td>\r\n          <td>--</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Marks</th>\r\n          <td>60</td>\r\n          <td>60</td>\r\n          <td>60</td>\r\n          <td>20</td>\r\n          <td>50</td>\r\n        </tr>\r\n        <tr>\r\n          <th>Duration</th>\r\n          <td>50 minutes</td>\r\n          <td>45 minutes</td>\r\n          <td>45 minutes</td>\r\n          <td>40 minutes</td>\r\n          <td>30 minutes</td>\r\n        </tr>\r\n      </tbody></table>\r\n\r\n      <div class=\"note\">\r\n        <b>Total Time:</b> 180 minutes (3 hours) &nbsp; | &nbsp;\r\n        <b>Negative Marking:</b> 0.25 marks (except Descriptive)\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus for Prelims Exam</h2>\r\n      <p>\r\n        Below are the section-wise topics on which SBI may ask questions in the SBI PO Prelims Exam.\r\n      </p>\r\n\r\n      <div class=\"grid\">\r\n        <div class=\"box\">\r\n          <h4>Quantitative Aptitude</h4>\r\n          <ul>\r\n            <li>Simplification / Approximation</li>\r\n            <li>Profit &amp; Loss</li>\r\n            <li>Mixtures &amp; Alligations</li>\r\n            <li>Permutation, Combination &amp; Probability</li>\r\n            <li>Work &amp; Time</li>\r\n            <li>Sequence &amp; Series</li>\r\n            <li>Simple Interest &amp; Compound Interest</li>\r\n            <li>Surds &amp; Indices</li>\r\n            <li>Mensuration (Cylinder, Cone, Sphere)</li>\r\n            <li>Time &amp; Distance</li>\r\n            <li>Data Interpretation</li>\r\n            <li>Ratio &amp; Proportion</li>\r\n            <li>Number Systems</li>\r\n            <li>Percentage</li>\r\n            <li>Quadratic Equation</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Reasoning</h4>\r\n          <ul>\r\n            <li>Alphanumeric Series</li>\r\n            <li>Directions</li>\r\n            <li>Logical Reasoning</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Ranking &amp; Order</li>\r\n            <li>Alphabet Test</li>\r\n            <li>Seating Arrangement</li>\r\n            <li>Coded Inequalities</li>\r\n            <li>Puzzle</li>\r\n            <li>Syllogism</li>\r\n            <li>Blood Relations</li>\r\n            <li>Coding-Decoding</li>\r\n            <li>Input-Output</li>\r\n            <li>Tabulation</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>English</h4>\r\n          <ul>\r\n            <li>Reading Comprehension</li>\r\n            <li>Fill in the Blanks</li>\r\n            <li>Cloze Test</li>\r\n            <li>Para Jumbles</li>\r\n            <li>Vocabulary</li>\r\n            <li>Puzzles &amp; Sentence Rearrangement</li>\r\n            <li>Paragraph Completion</li>\r\n            <li>Multiple Meaning / Error Spotting</li>\r\n            <li>Word Association</li>\r\n            <li>Sentence Improvement</li>\r\n            <li>Sentence Completion</li>\r\n            <li>Tenses Rules</li>\r\n            <li>Double Fillers</li>\r\n            <li>Word Usage</li>\r\n            <li>Inequalities</li>\r\n            <li>Pair Formation</li>\r\n          </ul>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>SBI PO Mains Syllabus</title>\r\n  <style>\r\n    body{font-family:Arial,Helvetica,sans-serif;line-height:1.6;margin:20px;color:#111}\r\n    .wrap{max-width:1200px}\r\n    .card{border:1px solid #ddd;border-radius:12px;padding:16px;margin:14px 0}\r\n    h1{margin:0 0 10px}\r\n    h2{margin:0 0 8px}\r\n    h3{margin:12px 0 6px}\r\n    p{margin:8px 0}\r\n    table{width:100%;border-collapse:collapse;margin-top:10px}\r\n    th,td{border:1px solid #ddd;padding:10px;text-align:left;vertical-align:top}\r\n    th{background:#f6f6f6}\r\n    ul{margin:6px 0 0 18px}\r\n    .note{background:#fff7e6;border:1px solid #ffe2a8;border-radius:12px;padding:12px;margin-top:10px}\r\n    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;margin-top:10px}\r\n    .box{border:1px solid #e6e6e6;border-radius:12px;padding:12px}\r\n    .box h4{margin:0 0 6px;font-size:16px}\r\n  </style>\r\n\r\n\r\n\r\n  <div class=\"wrap\">\r\n\r\n    <div class=\"card\">\r\n      <h1>SBI PO Mains Syllabus</h1>\r\n      <p>\r\n        The Mains Examination of the SBI PO exam includes 4 major areas:\r\n        <b>Reasoning + Computer Aptitude</b>, <b>English Language</b>,\r\n        <b>Data Analysis &amp; Interpretation</b>, and <b>General/Economy/Banking Awareness</b>.\r\n        The complete subject-wise syllabus is given below.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Syllabus for Main Exam (Subject-wise Topics)</h2>\r\n\r\n      <div class=\"grid\">\r\n\r\n        <div class=\"box\">\r\n          <h4>Data Analysis &amp; Interpretation</h4>\r\n          <ul>\r\n            <li>Tabular Graph</li>\r\n            <li>Line Graph</li>\r\n            <li>Bar Graph</li>\r\n            <li>Charts &amp; Tables</li>\r\n            <li>Missing Case DI</li>\r\n            <li>Radar Graph Caselet</li>\r\n            <li>Probability</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Double Line Up</li>\r\n            <li>Caselet DI</li>\r\n            <li>Permutation and Combination</li>\r\n            <li>Pie Charts</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Reasoning</h4>\r\n          <ul>\r\n            <li>Verbal Reasoning</li>\r\n            <li>Syllogism</li>\r\n            <li>Seating Arrangement &amp; Puzzles</li>\r\n            <li>Double Lineup</li>\r\n            <li>Scheduling</li>\r\n            <li>Input Output</li>\r\n            <li>Blood Relations</li>\r\n            <li>Directions and Distances</li>\r\n            <li>Ordering and Ranking</li>\r\n            <li>Data Sufficiency</li>\r\n            <li>Coding and Decoding</li>\r\n            <li>Code Inequalities</li>\r\n            <li>Course of Action</li>\r\n            <li>Critical Reasoning</li>\r\n            <li>Analytical and Decision Making</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>General/Economy/Banking Awareness</h4>\r\n          <ul>\r\n            <li>Current Affairs</li>\r\n            <li>Financial Awareness</li>\r\n            <li>General Knowledge</li>\r\n            <li>Static Awareness</li>\r\n            <li>Banking Terminologies Knowledge</li>\r\n            <li>Banking Awareness</li>\r\n            <li>Principles of Insurance</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>English Language</h4>\r\n          <ul>\r\n            <li>Reading Comprehension</li>\r\n            <li>Grammar</li>\r\n            <li>Verbal Ability</li>\r\n            <li>Vocabulary</li>\r\n            <li>Sentence Improvement</li>\r\n            <li>Word Association</li>\r\n            <li>Para Jumbles</li>\r\n            <li>Error Spotting</li>\r\n            <li>Cloze Test</li>\r\n            <li>Fill in the Blanks</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div class=\"box\">\r\n          <h4>Computer (Computer Aptitude)</h4>\r\n          <ul>\r\n            <li>Internet</li>\r\n            <li>Memory</li>\r\n            <li>Keyboard Shortcuts</li>\r\n            <li>Computer Abbreviation</li>\r\n            <li>Microsoft Office</li>\r\n            <li>Computer Hardware</li>\r\n            <li>Computer Software</li>\r\n            <li>Computer Fundamentals / Terminologies</li>\r\n            <li>Networking</li>\r\n            <li>Number System</li>\r\n            <li>Operating System</li>\r\n            <li>Basic of Logic Gates</li>\r\n          </ul>\r\n        </div>\r\n\r\n      </div>\r\n\r\n      <div class=\"note\">\r\n        <b>Note:</b> Reasoning and Computer topics are generally asked together as “Reasoning &amp; Computer Aptitude” in Mains.\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>SBI PO Descriptive Test</h2>\r\n      <p>\r\n        The Descriptive Test is of <b>30 minutes</b> duration with <b>2 questions</b> for <b>50 marks</b>.\r\n        It is a Test of English Language and usually includes:\r\n      </p>\r\n      <ul>\r\n        <li>Letter Writing</li>\r\n        <li>Essay Writing</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"card\">\r\n      <h2>Interview &amp; Final Merit List</h2>\r\n      <p>\r\n        Besides the preliminary and mains exams, SBI also conducts an <b>interview process</b> for candidates who qualify\r\n        the first two phases.\r\n      </p>\r\n      <p>\r\n        The final merit list is prepared based on the marks obtained by a candidate in the <b>Mains exam</b> and the\r\n        <b>Interview</b>.\r\n      </p>\r\n    </div>\r\n\r\n  </div>\r\n\r\n\r\n\r\n', 0, '2026-01-22 12:09:24', '2026-01-22 12:09:24');
INSERT INTO `bank_po_exam_tabs` (`id`, `exam_id`, `tab_title`, `tab_content`, `display_order`, `created_at`, `updated_at`) VALUES
(91, 6, 'HOME', '<p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The SSC CGL Exam is conducted every year by the Staff Selection Commission&nbsp;to recruit candidates for Group \"B\" and Group \"C\" posts in various government departments like Income Tax, Customs, CBI, CBDT &amp; CBEC, etc. It is the most demanded national-level government exam for all graduates. For the year ,&nbsp;<span style=\"font-weight: bolder;\">SSC has announced that SSC CGL Notification and Application Forms will be released in March&nbsp; and tier 1 exam will be conducted in May-June .&nbsp;</span></p><h2 id=\"FT3KA6FMIMI5C1SE928XDOT576WVXNO6\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">SSC CGL&nbsp; Notification</h2><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">The detailed notification for the Combined Graduate Level Examination&nbsp; will be released at www.ssc.gov.in for thousands of vacancies.<span style=\"font-weight: bolder;\">&nbsp;</span>The official SSC CGL Notification&nbsp; pdf with all details, including vacancy, selection process, exam pattern, and important dates, will be released at the official portal of the Staff Selection Commission (SSC) and the direct link will also be shared here.</p><h2 id=\"XEXO7PKO0UFTYEVNWTHUMJ3G0D9MN3PN\" style=\"margin-top: 20px; margin-bottom: 10px; line-height: 1.2; font-size: 28px; color: rgb(0, 0, 0); display: inline-block; width: 892px; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">SSC CGL - Exam Summary</h2><p style=\"margin-bottom: 15px; font-size: 16px; line-height: 24px; color: rgba(0, 0, 0, 0.8); text-align: justify; font-family: Lato, sans-serif; background-color: rgb(250, 250, 250);\">CGL stands for the Combined Graduate Level exam, which means that only graduate candidates can apply for the SSC CGL exam. The SSC CGL exam is highly competitive, with more than 20 lakh candidates appearing this year, making it one of the most sought-after government job exams in India. Check further details in the table below-</p><figure class=\"table\" style=\"margin-bottom: 1rem; --bs-table-bg: transparent; --bs-table-striped-color: #212529; --bs-table-striped-bg: rgba(0, 0, 0, 0.05); --bs-table-active-color: #212529; --bs-table-active-bg: rgba(0, 0, 0, 0.1); --bs-table-hover-color: #212529; --bs-table-hover-bg: rgba(0, 0, 0, 0.075); width: 892px; color: rgb(33, 37, 41); border-color: rgb(222, 226, 230); font-family: Lato, sans-serif; font-size: 16px; background-color: rgb(250, 250, 250);\"><table style=\"width: 892px;\"><tbody><tr><td colspan=\"2\" style=\"border-color: rgb(99, 97, 107); padding-right: 5px; padding-left: 5px; background: rgba(49, 43, 71, 0.05); color: rgb(0, 0, 0); line-height: 22px; width: 891.2px;\"><span style=\"font-weight: bolder;\">SSC CGL&nbsp; Exam- Summary</span></td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 218.387px;\">Exam Name</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 672.812px;\">SSC CGL&nbsp;</td></tr><tr><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8); font-size: 14px; line-height: 22px; width: 218.387px;\">Full Form</td><td style=\"border-color: rgb(64, 64, 64); padding-right: 5px; padding-left: 5px; background-co