(1, 'main_content', 'BCA (Bachelor of Computer Applications) – Complete Course Overview', '<h5 class=\"bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; font-size: 1.25rem;\"><p data-start=\"53\" data-end=\"331\">Why Choose BCA?</p><p data-start=\"53\" data-end=\"331\"><b>BCA is one of the most popular undergraduate courses for students who want to build a carrer in the computer and IT industry. The courses provides strong knowledge of programming, software development, and computer applications, helping students enter the technology field early.</b></p><p data-start=\"53\" data-end=\"331\"><br></p></h5><h5 class=\"bluc\" style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; line-height: 1.2; font-size: 1.25rem;\"><b></b></h5><ul>\r\n</ul>', '2026-01-12 08:43:42', '2026-02-05 09:51:07'),
(2, 'hero_intro', 'Best Career Options After BCA', '<p>Explore diverse career paths and opportunities after BCA. Expert guidance, comprehensive resources, and proven success strategies.</p>', '2026-01-12 08:43:42', '2026-01-12 08:43:42'),
(3, 'about_section', 'About BCA Career Guidance', '<p>We provide expert counseling and guidance for BCA graduates to help them choose the right career path. Our experienced mentors have helped thousands of students achieve their career goals in the IT industry.</p>', '2026-01-12 08:43:42', '2026-01-12 08:43:42');

