INSERT INTO `bca_page_tabs` (`id`, `tab_title`, `tab_content`, `display_order`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'Overview', '<p><span>﻿</span>What is BCA?</p><p data-start=\"91\" data-end=\"423\"><strong data-start=\"91\" data-end=\"134\">BCA (Bachelor of Computer Applications)</strong> is a 3-year undergraduate degree program focused on computer science, software development, and information technology. The course is designed for students who want to build careers in software development, IT services, web development, data science, or pursue higher studies such as MCA.</p><p>\r\n</p><p data-start=\"425\" data-end=\"589\">BCA provides strong knowledge in programming languages, database management, networking, and software development, making students industry-ready for the IT sector.</p><p data-start=\"425\" data-end=\"589\">Why Choose BCA?</p><p data-start=\"618\" data-end=\"648\">BCA is ideal for students who:</p><ul data-start=\"649\" data-end=\"842\">\r\n<li data-start=\"649\" data-end=\"693\">\r\n<p data-start=\"651\" data-end=\"693\">Have interest in computers and programming</p>\r\n</li>\r\n<li data-start=\"694\" data-end=\"738\">\r\n<p data-start=\"696\" data-end=\"738\">Want to enter the IT and software industry</p>\r\n</li>\r\n<li data-start=\"739\" data-end=\"793\">\r\n<p data-start=\"741\" data-end=\"793\">Plan to pursue MCA or other postgraduate IT programs</p>\r\n</li>\r\n<li data-start=\"794\" data-end=\"842\">\r\n<p data-start=\"796\" data-end=\"842\">Want career opportunities in technology fields</p>\r\n</li>\r\n</ul><p data-start=\"425\" data-end=\"589\">\r\n\r\n</p><p data-start=\"844\" data-end=\"927\">The demand for skilled IT professionals makes BCA a popular career-oriented course.</p><h2 data-start=\"934\" data-end=\"954\">Course Duration</h2><p data-start=\"844\" data-end=\"927\">\r\n</p><ul data-start=\"955\" data-end=\"1049\">\r\n<li data-start=\"955\" data-end=\"978\">\r\n<p data-start=\"957\" data-end=\"978\">Duration: <strong data-start=\"967\" data-end=\"978\">3 Years</strong></p>\r\n</li>\r\n<li data-start=\"979\" data-end=\"1007\">\r\n<p data-start=\"981\" data-end=\"1007\">Structure: <strong data-start=\"992\" data-end=\"1007\">6 Semesters</strong></p>\r\n</li>\r\n<li data-start=\"1008\" data-end=\"1049\">\r\n<p data-start=\"1010\" data-end=\"1049\">Each semester lasts around <strong data-start=\"1037\" data-end=\"1049\">6 months</strong></p><p data-start=\"1010\" data-end=\"1049\"><strong data-start=\"1037\" data-end=\"1049\"><br></strong><span style=\"color: inherit; font-family: inherit; font-size: 1.75rem;\">Examination Pattern</span></p><p data-start=\"1082\" data-end=\"1163\">Most universities follow a semester system with internal and external evaluation.</p><h3 data-start=\"1165\" data-end=\"1189\">Evaluation Structure</h3><p data-start=\"1190\" data-end=\"1216\"><strong data-start=\"1190\" data-end=\"1216\">1. Internal Assessment</strong></p><ul data-start=\"1217\" data-end=\"1291\">\r\n<li data-start=\"1217\" data-end=\"1230\">\r\n<p data-start=\"1219\" data-end=\"1230\">Class tests</p>\r\n</li>\r\n<li data-start=\"1231\" data-end=\"1244\">\r\n<p data-start=\"1233\" data-end=\"1244\">Assignments</p>\r\n</li>\r\n<li data-start=\"1245\" data-end=\"1260\">\r\n<p data-start=\"1247\" data-end=\"1260\">Presentations</p>\r\n</li>\r\n<li data-start=\"1261\" data-end=\"1273\">\r\n<p data-start=\"1263\" data-end=\"1273\">Attendance</p>\r\n</li>\r\n<li data-start=\"1274\" data-end=\"1291\">\r\n<p data-start=\"1276\" data-end=\"1291\">Lab performance</p>\r\n</li>\r\n</ul><p data-start=\"1293\" data-end=\"1324\"><strong data-start=\"1293\" data-end=\"1324\">2. Semester-End Examination</strong></p><ul data-start=\"1325\" data-end=\"1402\">\r\n<li data-start=\"1325\" data-end=\"1347\">\r\n<p data-start=\"1327\" data-end=\"1347\">Written theory exams</p>\r\n</li>\r\n<li data-start=\"1348\" data-end=\"1369\">\r\n<p data-start=\"1350\" data-end=\"1369\">Practical/lab exams</p>\r\n</li>\r\n<li data-start=\"1370\" data-end=\"1381\">\r\n<p data-start=\"1372\" data-end=\"1381\">Viva voce</p>\r\n</li>\r\n<li data-start=\"1382\" data-end=\"1402\">\r\n<p data-start=\"1384\" data-end=\"1402\">Project evaluation</p>\r\n</li>\r\n</ul><p data-start=\"1404\" data-end=\"1426\">Exams usually include:</p><p data-start=\"1010\" data-end=\"1049\"><strong data-start=\"1037\" data-end=\"1049\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</strong></p><ul data-start=\"1427\" data-end=\"1523\">\r\n<li data-start=\"1427\" data-end=\"1448\">\r\n<p data-start=\"1429\" data-end=\"1448\">Objective questions</p>\r\n</li>\r\n<li data-start=\"1449\" data-end=\"1473\">\r\n<p data-start=\"1451\" data-end=\"1473\">Short-answer questions</p>\r\n</li>\r\n<li data-start=\"1474\" data-end=\"1500\">\r\n<p data-start=\"1476\" data-end=\"1500\">Long descriptive answers</p>\r\n</li>\r\n<li data-start=\"1501\" data-end=\"1523\">\r\n<p data-start=\"1503\" data-end=\"1523\">Programming problems</p><p data-start=\"1503\" data-end=\"1523\"><span style=\"font-size: 18px;\">BCA Syllabus Overview</span></p><p data-start=\"1558\" data-end=\"1637\">The syllabus may vary slightly by university, but core subjects remain similar.</p><h3 data-start=\"1639\" data-end=\"1672\">First Year – Foundation Level</h3><ul data-start=\"1673\" data-end=\"1767\">\r\n<li data-start=\"1673\" data-end=\"1696\">\r\n<p data-start=\"1675\" data-end=\"1696\">Computer Fundamentals</p>\r\n</li>\r\n<li data-start=\"1697\" data-end=\"1715\">\r\n<p data-start=\"1699\" data-end=\"1715\">Programming in C</p>\r\n</li>\r\n<li data-start=\"1716\" data-end=\"1729\">\r\n<p data-start=\"1718\" data-end=\"1729\">Mathematics</p>\r\n</li>\r\n<li data-start=\"1730\" data-end=\"1752\">\r\n<p data-start=\"1732\" data-end=\"1752\">Communication Skills</p>\r\n</li>\r\n<li data-start=\"1753\" data-end=\"1767\">\r\n<p data-start=\"1755\" data-end=\"1767\">Computer Lab</p>\r\n</li>\r\n</ul><h3 data-start=\"1769\" data-end=\"1801\">Second Year – Core Computing</h3><ul data-start=\"1802\" data-end=\"1945\">\r\n<li data-start=\"1802\" data-end=\"1819\">\r\n<p data-start=\"1804\" data-end=\"1819\">Data Structures</p>\r\n</li>\r\n<li data-start=\"1820\" data-end=\"1860\">\r\n<p data-start=\"1822\" data-end=\"1860\">Object-Oriented Programming (C++/Java)</p>\r\n</li>\r\n<li data-start=\"1861\" data-end=\"1889\">\r\n<p data-start=\"1863\" data-end=\"1889\">Database Management System</p>\r\n</li>\r\n<li data-start=\"1890\" data-end=\"1909\">\r\n<p data-start=\"1892\" data-end=\"1909\">Operating Systems</p>\r\n</li>\r\n<li data-start=\"1910\" data-end=\"1928\">\r\n<p data-start=\"1912\" data-end=\"1928\">Web Technologies</p>\r\n</li>\r\n<li data-start=\"1929\" data-end=\"1945\">\r\n<p data-start=\"1931\" data-end=\"1945\">Practical Labs</p>\r\n</li>\r\n</ul><h3 data-start=\"1947\" data-end=\"1989\">Third Year – Advanced &amp; Industry Level</h3><p data-start=\"1503\" data-end=\"1523\"><span style=\"font-size: 18px;\">\r\n\r\n\r\n\r\n\r\n\r\n</span></p><ul data-start=\"1990\" data-end=\"2163\">\r\n<li data-start=\"1990\" data-end=\"2017\">\r\n<p data-start=\"1992\" data-end=\"2017\">Java / Python Programming</p>\r\n</li>\r\n<li data-start=\"2018\" data-end=\"2040\">\r\n<p data-start=\"2020\" data-end=\"2040\">Software Engineering</p>\r\n</li>\r\n<li data-start=\"2041\" data-end=\"2060\">\r\n<p data-start=\"2043\" data-end=\"2060\">Computer Networks</p>\r\n</li>\r\n<li data-start=\"2061\" data-end=\"2099\">\r\n<p data-start=\"2063\" data-end=\"2099\">Web &amp; Mobile Application Development</p>\r\n</li>\r\n<li data-start=\"2100\" data-end=\"2134\">\r\n<p data-start=\"2102\" data-end=\"2134\">Cloud Computing / Data Analytics</p>\r\n</li>\r\n<li data-start=\"2135\" data-end=\"2163\">\r\n<p data-start=\"2137\" data-end=\"2163\">Major Project &amp; Internship</p><p data-start=\"2137\" data-end=\"2163\"><span style=\"font-size: 24px;\">&nbsp;Practical Training &amp; Projects</span></p><p data-start=\"2206\" data-end=\"2240\">BCA emphasizes practical learning:</p><ul data-start=\"2241\" data-end=\"2387\">\r\n<li data-start=\"2241\" data-end=\"2274\">\r\n<p data-start=\"2243\" data-end=\"2274\">Programming labs every semester</p>\r\n</li>\r\n<li data-start=\"2275\" data-end=\"2308\">\r\n<p data-start=\"2277\" data-end=\"2308\">Database &amp; web development labs</p>\r\n</li>\r\n<li data-start=\"2309\" data-end=\"2324\">\r\n<p data-start=\"2311\" data-end=\"2324\">Mini projects</p>\r\n</li>\r\n<li data-start=\"2325\" data-end=\"2351\">\r\n<p data-start=\"2327\" data-end=\"2351\">Final year major project</p>\r\n</li>\r\n<li data-start=\"2352\" data-end=\"2387\">\r\n<p data-start=\"2354\" data-end=\"2387\">Industrial training or internship</p>\r\n</li>\r\n</ul><p data-start=\"2137\" data-end=\"2163\"><span style=\"font-size: 18px;\">\r\n\r\n</span></p><p data-start=\"2389\" data-end=\"2459\">These activities help students gain real-world development experience.</p><p data-start=\"2389\" data-end=\"2459\"><span style=\"font-size: 24px;\">Skills Developed During BCA</span></p><p data-start=\"2500\" data-end=\"2517\">Students develop:</p><p data-start=\"2389\" data-end=\"2459\"><span style=\"font-size: 18px;\">\r\n</span></p><ul data-start=\"2518\" data-end=\"2709\">\r\n<li data-start=\"2518\" data-end=\"2547\">\r\n<p data-start=\"2520\" data-end=\"2547\">Programming &amp; coding skills</p>\r\n</li>\r\n<li data-start=\"2548\" data-end=\"2581\">\r\n<p data-start=\"2550\" data-end=\"2581\">Logical and analytical thinking</p>\r\n</li>\r\n<li data-start=\"2582\" data-end=\"2610\">\r\n<p data-start=\"2584\" data-end=\"2610\">Database management skills</p>\r\n</li>\r\n<li data-start=\"2611\" data-end=\"2644\">\r\n<p data-start=\"2613\" data-end=\"2644\">Web &amp; app development knowledge</p>\r\n</li>\r\n<li data-start=\"2645\" data-end=\"2681\">\r\n<p data-start=\"2647\" data-end=\"2681\">Software development understanding</p>\r\n</li>\r\n<li data-start=\"2682\" data-end=\"2709\">\r\n<p data-start=\"2684\" data-end=\"2709\">Problem-solving abilities</p><p data-start=\"2684\" data-end=\"2709\"><span style=\"font-size: 24px;\">Career Opportunities After BCA</span></p><p data-start=\"2753\" data-end=\"2775\">Graduates can work as:</p><p data-start=\"2684\" data-end=\"2709\">\r\n</p><ul data-start=\"2776\" data-end=\"2947\">\r\n<li data-start=\"2776\" data-end=\"2796\">\r\n<p data-start=\"2778\" data-end=\"2796\">Software Developer</p>\r\n</li>\r\n<li data-start=\"2797\" data-end=\"2812\">\r\n<p data-start=\"2799\" data-end=\"2812\">Web Developer</p>\r\n</li>\r\n<li data-start=\"2813\" data-end=\"2829\">\r\n<p data-start=\"2815\" data-end=\"2829\">System Analyst</p>\r\n</li>\r\n<li data-start=\"2830\" data-end=\"2854\">\r\n<p data-start=\"2832\" data-end=\"2854\">Database Administrator</p>\r\n</li>\r\n<li data-start=\"2855\" data-end=\"2878\">\r\n<p data-start=\"2857\" data-end=\"2878\">Network Administrator</p>\r\n</li>\r\n<li data-start=\"2879\" data-end=\"2902\">\r\n<p data-start=\"2881\" data-end=\"2902\">IT Support Specialist</p>\r\n</li>\r\n<li data-start=\"2903\" data-end=\"2918\">\r\n<p data-start=\"2905\" data-end=\"2918\">App Developer</p>\r\n</li>\r\n<li data-start=\"2919\" data-end=\"2947\">\r\n<p data-start=\"2921\" data-end=\"2947\">Data Analyst (entry level)</p><p data-start=\"2921\" data-end=\"2947\"><span style=\"font-size: 24px;\">Higher Study Options After BCA</span></p><p data-start=\"2991\" data-end=\"3030\">Many students continue studies through:</p><p data-start=\"2921\" data-end=\"2947\">\r\n</p><ul data-start=\"3031\" data-end=\"3184\">\r\n<li data-start=\"3031\" data-end=\"3070\">\r\n<p data-start=\"3033\" data-end=\"3070\">MCA (Master of Computer Applications)</p>\r\n</li>\r\n<li data-start=\"3071\" data-end=\"3095\">\r\n<p data-start=\"3073\" data-end=\"3095\">MBA (IT or Management)</p>\r\n</li>\r\n<li data-start=\"3096\" data-end=\"3125\">\r\n<p data-start=\"3098\" data-end=\"3125\">M.Sc. IT / Computer Science</p>\r\n</li>\r\n<li data-start=\"3126\" data-end=\"3154\">\r\n<p data-start=\"3128\" data-end=\"3154\">Data Science or AI courses</p>\r\n</li>\r\n<li data-start=\"3155\" data-end=\"3184\">\r\n<p data-start=\"3157\" data-end=\"3184\">Professional certifications</p><p data-start=\"3157\" data-end=\"3184\"><span style=\"font-size: 24px;\">Who Should Join BCA?</span></p><p data-start=\"3218\" data-end=\"3251\">BCA is suitable for students who:</p><p data-start=\"3157\" data-end=\"3184\">\r\n</p><ul data-start=\"3252\" data-end=\"3396\">\r\n<li data-start=\"3252\" data-end=\"3282\">\r\n<p data-start=\"3254\" data-end=\"3282\">Enjoy working with computers</p>\r\n</li>\r\n<li data-start=\"3283\" data-end=\"3313\">\r\n<p data-start=\"3285\" data-end=\"3313\">Want a career in IT/software</p>\r\n</li>\r\n<li data-start=\"3314\" data-end=\"3356\">\r\n<p data-start=\"3316\" data-end=\"3356\">Are interested in coding and development</p>\r\n</li>\r\n<li data-start=\"3357\" data-end=\"3396\">\r\n<p data-start=\"3359\" data-end=\"3396\">Want early entry into the IT industry</p><p data-start=\"3359\" data-end=\"3396\"><span style=\"font-size: 24px;\">Conclusion</span></p><p data-start=\"3359\" data-end=\"3396\">BCA is one of the best undergraduate courses for students aiming to build careers in the IT and software industry. With strong practical exposure, programming knowledge, and project experience, BCA students gain skills needed for modern technology careers.</p></li></ul></li></ul>\r\n</li>\r\n</ul></li></ul></li></ul></li></ul></li></ul>', 0, 1, '2026-01-12 08:45:30', '2026-02-05 09:44:33'),
(2, 'INFOMATH PROGRAM', '<p><span style=\"background-color: rgb(255, 255, 255);\"><span style=\"font-weight: bolder; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">In terms of coaching, you should find the best coaching centre which can cover the modules of BCA.</span><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">&nbsp;INFOMATHS based coaching centre which offers you a plethora of learning solutions so that you can crack entrance exam. The innovative learning system of this coaching centre allows learners to gain knowledge and bca information which is relevant in the modern times. All the portions are step by step covered by the mentors in the classes. The centre has received national award for its contribution towards national coaching. Mock tests are carried out to check the proficiency level of students and according to the result, the next step of preparation is carried out. Queries are always welcomed by the faculty members of INFOMATHS, but, these are kept for doubts’ session.</span><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">In this session, queries related to bca subject information are addressed and concepts of various sphere gets simplified for the learners. Interactive learning atmosphere of this coaching centre helps students to grasp new syllabus of BCA in a simpler yet effective way. Learners can explore their dimensions by following the guiding path by mentors. All bachelor in computer application details are covered in the coaching sessions of New Parameter. The syllabus prepared by experts appointed by this coaching centre matches the revised guidelines of BCA course offered by colleges or universities. Course guidelines are verified by a panel of scholars before starting the session so that students are offered the best. Even though eligibility for bca admission demands 45-55% marks, but, the mentors of INFOMATHS believe in making learners very competent by helping them score higher grades. The constant guidance and learning atmosphere engages students to an extent further improving their skills. Every subject demands a specialist and this is where the need of appointing the best teacher arises. New Parameter has reflected over this point and appointed experienced computer applications’ mentors who are all set to prepare students for bachelor of computer application. These mentors have theoretical and practical knowledge of computer applications. They can impart the best education of computer education on the basis of their experience</span><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">As a part of the BCA course, engineering, computer architecture, web technology and languages such as java, C, C++ and HTML are some of the portions of bca subject information. The preparation of this course is vast yet covered in a short span to give students’ a glimpse of all the 6 semesters of bca course.&nbsp;</span></span></p>', 0, 1, '2026-02-05 09:54:50', '2026-02-05 09:54:50'),
(3, 'BCA Syllabus', '<p><span style=\"font-size: 24px;\">Semester-wise syllabus for BCA</span></p><h3 data-start=\"318\" data-end=\"352\"><strong data-start=\"322\" data-end=\"352\">Semester I – Core Subjects</strong></h3><p>\r\n</p><ol data-start=\"353\" data-end=\"518\">\r\n<li data-start=\"353\" data-end=\"378\">\r\n<p data-start=\"356\" data-end=\"378\">English (Compulsory)</p>\r\n</li>\r\n<li data-start=\"379\" data-end=\"423\">\r\n<p data-start=\"382\" data-end=\"423\">Fundamentals of Mathematical Statistics</p>\r\n</li>\r\n<li data-start=\"424\" data-end=\"473\">\r\n<p data-start=\"427\" data-end=\"473\">Computer Fundamentals and Computing Software</p>\r\n</li>\r\n<li data-start=\"474\" data-end=\"518\">\r\n<p data-start=\"477\" data-end=\"518\">Problem Solving Through C (Programming)</p><h3 data-start=\"663\" data-end=\"698\"><strong data-start=\"667\" data-end=\"698\">Semester II – Core Subjects</strong></h3><p data-start=\"477\" data-end=\"518\">\r\n</p><ol data-start=\"699\" data-end=\"907\">\r\n<li data-start=\"699\" data-end=\"733\">\r\n<p data-start=\"702\" data-end=\"733\">English (Compulsory – Part B)</p>\r\n</li>\r\n<li data-start=\"734\" data-end=\"760\">\r\n<p data-start=\"737\" data-end=\"760\">Computer Organization</p>\r\n</li>\r\n<li data-start=\"761\" data-end=\"797\">\r\n<p data-start=\"764\" data-end=\"797\">Fundamentals of Web Programming</p>\r\n</li>\r\n<li data-start=\"798\" data-end=\"840\">\r\n<p data-start=\"801\" data-end=\"840\">Object Oriented Programming using C++</p>\r\n</li>\r\n<li data-start=\"841\" data-end=\"907\">\r\n<p data-start=\"844\" data-end=\"907\">Lab Courses based on Web Programming and OOP (C++ practicals)</p><h3 data-start=\"1068\" data-end=\"1104\"><strong data-start=\"1072\" data-end=\"1104\">Semester III – Core Subjects</strong></h3><p data-start=\"844\" data-end=\"907\">\r\n</p><ol data-start=\"1105\" data-end=\"1267\">\r\n<li data-start=\"1105\" data-end=\"1140\">\r\n<p data-start=\"1108\" data-end=\"1140\">Data Structures and Algorithms</p>\r\n</li>\r\n<li data-start=\"1141\" data-end=\"1180\">\r\n<p data-start=\"1144\" data-end=\"1180\">Database Management Systems (DBMS)</p>\r\n</li>\r\n<li data-start=\"1181\" data-end=\"1203\">\r\n<p data-start=\"1184\" data-end=\"1203\">Operating Systems</p>\r\n</li>\r\n<li data-start=\"1204\" data-end=\"1241\">\r\n<p data-start=\"1207\" data-end=\"1241\">Discrete Mathematical Structures</p>\r\n</li>\r\n<li data-start=\"1242\" data-end=\"1267\">\r\n<p data-start=\"1245\" data-end=\"1267\">DBMS Lab / Practical</p><h3 data-start=\"1406\" data-end=\"1441\"><strong data-start=\"1410\" data-end=\"1441\">Semester IV – Core Subjects</strong></h3><p data-start=\"1245\" data-end=\"1267\">\r\n</p><ol data-start=\"1442\" data-end=\"1655\">\r\n<li data-start=\"1442\" data-end=\"1467\">\r\n<p data-start=\"1445\" data-end=\"1467\">Software Engineering</p>\r\n</li>\r\n<li data-start=\"1468\" data-end=\"1490\">\r\n<p data-start=\"1471\" data-end=\"1490\">Computer Networks</p>\r\n</li>\r\n<li data-start=\"1491\" data-end=\"1552\">\r\n<p data-start=\"1494\" data-end=\"1552\">Web Application Development (typically PHP/Advanced Web)</p>\r\n</li>\r\n<li data-start=\"1553\" data-end=\"1610\">\r\n<p data-start=\"1556\" data-end=\"1610\">Computer Graphics &amp; Multimedia (or related elective)</p>\r\n</li>\r\n<li data-start=\"1611\" data-end=\"1655\">\r\n<p data-start=\"1614\" data-end=\"1655\">Project / Mini Project (practical work)</p><h3 data-start=\"1803\" data-end=\"1837\"><strong data-start=\"1807\" data-end=\"1837\">Semester V – Core Subjects</strong></h3><p data-start=\"1614\" data-end=\"1655\">\r\n</p><ol data-start=\"1838\" data-end=\"2061\">\r\n<li data-start=\"1838\" data-end=\"1859\">\r\n<p data-start=\"1841\" data-end=\"1859\">Java Programming</p>\r\n</li>\r\n<li data-start=\"1860\" data-end=\"1935\">\r\n<p data-start=\"1863\" data-end=\"1935\">Advanced Software Development (Frameworks / Mobile Apps / Python etc.)</p>\r\n</li>\r\n<li data-start=\"1936\" data-end=\"1978\">\r\n<p data-start=\"1939\" data-end=\"1978\">Computer Networks (Advanced Concepts)</p>\r\n</li>\r\n<li data-start=\"1979\" data-end=\"2019\">\r\n<p data-start=\"1982\" data-end=\"2019\">Elective / Skill Enhancement Course</p>\r\n</li>\r\n<li data-start=\"2020\" data-end=\"2061\">\r\n<p data-start=\"2023\" data-end=\"2061\">Project Work / Practical Assignments</p><h3 data-start=\"2228\" data-end=\"2263\"><strong data-start=\"2232\" data-end=\"2263\">Semester VI – Core Subjects</strong></h3><p data-start=\"2023\" data-end=\"2061\">\r\n</p><ol data-start=\"2264\" data-end=\"2457\">\r\n<li data-start=\"2264\" data-end=\"2297\">\r\n<p data-start=\"2267\" data-end=\"2297\">E-Commerce / Cloud Computing</p>\r\n</li>\r\n<li data-start=\"2298\" data-end=\"2356\">\r\n<p data-start=\"2301\" data-end=\"2356\">Application Development (e.g., VB or Python Projects)</p>\r\n</li>\r\n<li data-start=\"2357\" data-end=\"2387\">\r\n<p data-start=\"2360\" data-end=\"2387\">Major Project and Seminar</p>\r\n</li>\r\n<li data-start=\"2388\" data-end=\"2431\">\r\n<p data-start=\"2391\" data-end=\"2431\">Elective or Advanced Computing Subject</p>\r\n</li>\r\n<li data-start=\"2432\" data-end=\"2457\">\r\n<p data-start=\"2435\" data-end=\"2457\">Practical / Lab Work</p><h3 data-start=\"2602\" data-end=\"2636\"><strong data-start=\"2606\" data-end=\"2636\">Practical / Lab Components</strong></h3><p data-start=\"2637\" data-end=\"2675\">Across semesters students will attend:</p><p data-start=\"2435\" data-end=\"2457\">\r\n\r\n</p><ul data-start=\"2676\" data-end=\"2803\">\r\n<li data-start=\"2676\" data-end=\"2709\">\r\n<p data-start=\"2678\" data-end=\"2709\">Programming labs (C, C++, Java)</p>\r\n</li>\r\n<li data-start=\"2710\" data-end=\"2732\">\r\n<p data-start=\"2712\" data-end=\"2732\">Web Development labs</p>\r\n</li>\r\n<li data-start=\"2733\" data-end=\"2756\">\r\n<p data-start=\"2735\" data-end=\"2756\">Database systems labs</p>\r\n</li>\r\n<li data-start=\"2757\" data-end=\"2803\">\r\n<p data-start=\"2759\" data-end=\"2803\">Mini and Major Projects (Semester IV onward)</p></li></ul><p data-start=\"2435\" data-end=\"2457\"><br></p></li></ol></li></ol></li></ol></li></ol></li></ol></li></ol>\r\n<table border=\"1\" cellpadding=\"10\" cellspacing=\"0\" width=\"100%\" style=\"border-collapse: collapse; font-family: Arial, sans-serif;\">\r\n    <thead style=\"background-color:#f2f2f2;\">\r\n        <tr>\r\n            <th>Semester</th>\r\n            <th>Subjects / Papers</th>\r\n        </tr>\r\n    </thead>\r\n    <tbody>\r\n        <tr>\r\n            <td>Semester I</td>\r\n            <td>\r\n                English (Compulsory), Fundamentals of Mathematical Statistics,\r\n                Computer Fundamentals &amp; Computing Software,\r\n                Programming in C, C Programming Lab\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td>Semester II</td>\r\n            <td>\r\n                English (Compulsory Part-B), Computer Organization,\r\n                Fundamentals of Web Programming,\r\n                Object Oriented Programming using C++,\r\n                Web &amp; C++ Lab\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td>Semester III</td>\r\n            <td>\r\n                Data Structures &amp; Algorithms,\r\n                Database Management System (DBMS),\r\n                Operating Systems,\r\n                Discrete Mathematical Structures,\r\n                DBMS &amp; Data Structure Lab\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td>Semester IV</td>\r\n            <td>\r\n                Software Engineering,\r\n                Computer Networks,\r\n                Web Application Development,\r\n                Computer Graphics / Multimedia,\r\n                Mini Project &amp; Practical\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td>Semester V</td>\r\n            <td>\r\n                Java Programming,\r\n                Advanced Programming / Application Development,\r\n                Advanced Networking Concepts,\r\n                Elective Subject,\r\n                Practical &amp; Project Work\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td>Semester VI</td>\r\n            <td>\r\n                E-Commerce / Cloud Computing,\r\n                Application Development Project,\r\n                Major Project,\r\n                Seminar &amp; Viva,\r\n                Practical / Elective\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n', 0, 1, '2026-02-05 10:05:54', '2026-02-05 10:07:31');

