(1, 'main_content', 'Career Options After BSC', '<h2>Welcome to Career BSC Guidance</h2>\r\n<p>Bachelor of Science (BSC) opens up numerous career opportunities across various scientific fields. Our comprehensive guidance program helps you navigate through various career paths and make informed decisions about your future.</p><ul>\r\n</ul>', '2026-01-12 09:09:28', '2026-01-12 09:20:13'),
(2, 'hero_intro', 'Best Career Options After BSC', '<p>Explore diverse career paths and opportunities after BSC. Expert guidance, comprehensive resources, and proven success strategies.</p>', '2026-01-12 09:09:28', '2026-01-12 09:09:28'),
(3, 'about_section', 'About BSC Career Guidance', '<p>We provide expert counseling and guidance for BSC graduates to help them choose the right career path. Our experienced mentors have helped thousands of students achieve their career goals in scientific fields.</p>', '2026-01-12 09:09:28', '2026-01-12 09:09:28');

