INSERT INTO `bsc_page_tabs` (`id`, `tab_title`, `tab_content`, `display_order`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'Overview', '<p><b><span style=\"font-size: 18px;\">BSc (Bachelor of Science) – Course Overview</span></b></p><p data-start=\"45\" data-end=\"370\">BSc (Bachelor of Science) is a 3-year undergraduate degree program designed for students interested in science and technology fields. The course provides strong theoretical and practical knowledge in scientific subjects and prepares students for careers in research, technology, education, and industry or for higher studies.</p><p data-start=\"372\" data-end=\"633\">The BSc program offers various subject combinations, allowing students to specialize in areas such as Mathematics, Physics, Chemistry, Computer Science, Information Technology, Biotechnology, and other science disciplines depending on the college or university.</p><p data-start=\"635\" data-end=\"866\"><span style=\"font-size: 18px;\"><b>Course Duration</b></span><br data-start=\"650\" data-end=\"653\">\r\nThe BSc course duration is 3 years divided into 6 semesters, with each semester lasting approximately six months. Some universities may follow an annual examination system, but most now follow the semester system.</p><p data-start=\"868\" data-end=\"977\"><span style=\"font-size: 18px;\"><b>Examination Pattern</b></span><br data-start=\"887\" data-end=\"890\">\r\nEvaluation is generally divided into internal assessment and semester-end examinations.</p><p data-start=\"979\" data-end=\"1178\">Internal assessment includes assignments, class tests, practical performance, presentations, and attendance. Semester-end exams include written theory exams and practical examinations with viva voce.</p><p data-start=\"1180\" data-end=\"1299\">Students are also evaluated through laboratory work and project assignments, depending on their subject specialization.</p><p data-start=\"1301\" data-end=\"1403\"><b><span style=\"font-size: 18px;\">BSc Syllabus Overview</span></b><br data-start=\"1322\" data-end=\"1325\">\r\nThe syllabus varies according to specialization, but general subjects include:</p><p data-start=\"1405\" data-end=\"1574\"><b>First Year</b><br data-start=\"1415\" data-end=\"1418\">\r\nFoundation subjects related to chosen stream such as Mathematics, Physics, Chemistry, or Computer Science along with communication or environmental studies.</p><p data-start=\"1576\" data-end=\"1680\"><b>Second Year</b><br data-start=\"1587\" data-end=\"1590\">\r\nCore subjects of specialization with practical lab work and advanced theoretical concepts.</p><p data-start=\"1682\" data-end=\"1826\"><b>Third Year</b><br data-start=\"1692\" data-end=\"1695\">\r\nAdvanced topics, practical experiments, research-based learning, and sometimes project work or internship depending on the program.</p><p data-start=\"1828\" data-end=\"2034\"><b>Practical and Laboratory Work</b><br data-start=\"1857\" data-end=\"1860\">\r\nBSc courses emphasize practical knowledge through laboratory experiments, field work, and projects. Practical learning helps students understand real scientific applications.</p><p data-start=\"2036\" data-end=\"2208\"><b>Skills Developed During BSc</b><br data-start=\"2063\" data-end=\"2066\">\r\nStudents develop analytical thinking, problem-solving skills, technical knowledge, laboratory skills, research ability, and logical reasoning.</p><p data-start=\"2210\" data-end=\"2481\"><span style=\"font-size: 18px;\"><b>Career Opportunities After BSc</b></span><br data-start=\"2240\" data-end=\"2243\">\r\nGraduates can work in fields such as research laboratories, IT companies, healthcare sector, pharmaceutical companies, education, data analysis, environmental science, and technical services. Job roles depend on the specialization chosen.</p><p data-start=\"2483\" data-end=\"2703\"><b><span style=\"font-size: 18px;\">Higher Study Options After BSc</span></b><br data-start=\"2513\" data-end=\"2516\">\r\nMany students pursue higher education such as MSc, MCA, MBA, professional certifications, or research programs. Specialized postgraduate studies often lead to better career opportunities.</p><p data-start=\"2705\" data-end=\"2906\"><span style=\"font-size: 18px;\"><b>Who Should Choose BSc</b></span><br data-start=\"2726\" data-end=\"2729\">\r\nBSc is suitable for students interested in science, research, technology, and analytical fields. It is ideal for students planning careers in scientific or technical industries.</p><p data-start=\"2908\" data-end=\"3128\"><b style=\"box-sizing: border-box; margin: 0px; padding: 0px; font-weight: 500; color: rgb(0, 0, 0); font-family: sans-serif; font-size: 24px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Conclusion</b><span style=\"font-size: 24px;\"><b></b></span><br data-start=\"2918\" data-end=\"2921\">\r\nBSc is a strong foundation course for students aiming to build careers in science and technology. With a combination of theory and practical learning, it opens multiple career and higher study opportunities.</p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p>', 0, 1, '2026-01-12 09:23:36', '2026-02-05 10:27:20'),
(2, 'INFOMATH PROGRAM', '<p><span style=\"background-color: rgb(255, 255, 255);\"><span style=\"font-weight: bolder; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">INFOMATHS based coaching centre which offers you a plethora of learning solutions so that you can crack entrance exam.</span><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">&nbsp;The innovative learning system of this coaching centre allows learners to gain knowledge and BSc information which is relevant in the modern times. All the portions are step by step covered by the mentors in the classes. The centre has received national award for its contribution towards national coaching. Mock tests are carried out to check the proficiency level of students and according to the result, the next step of preparation is carried out. Queries are always welcomed by the faculty members of INFOMATHS, but, these are kept for doubts\' session. In this session, queries related to BSc subject information are addressed and concepts of various sphere gets simplified for the learners. Interactive learning atmosphere of this coaching centre helps students to grasp new syllabus of BSc in a simpler yet effective way. Learners can explore their dimensions by following the guiding path by mentors. All bachelor in computer application details are covered in the coaching sessions of New Parameter. The syllabus prepared by experts appointed by this coaching centre matches the revised guidelines of BSc course offered by colleges or universities. Course guidelines are verified by a panel of scholars before starting the session so that students are offered the best. Even though eligibility for BSc admission demands 45-55% marks, but, the mentors of INFOMATHS believe in making learners very competent by helping them score higher grades.</span><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><br style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">The constant guidance and learning atmosphere engages students to an extent further improving their skills. Every subject demands a specialist and this is where the need of appointing the best teacher arises. New Parameter has reflected over this point and appointed experienced computer applications\' mentors who are all set to prepare students for bachelor of computer application. These mentors have theoretical and practical knowledge of computer applications. They can impart the best education of computer education on the basis of their experience. As a part of the BSc course, engineering, computer architecture, web technology and languages such as&nbsp;</span><span style=\"font-weight: bolder; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">java, C, C++ and HTML are some of the portions of BSc subject information.</span><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">&nbsp;The preparation of this course is vast yet covered in a short span to give students\' a glimpse of all the 6 semesters of BSc course.</span></span></p>', 0, 1, '2026-02-05 10:16:42', '2026-02-05 10:16:42'),
(3, 'BSc Syllabus', '<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-(--header-height)\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"e9901be6-c4ec-4b89-bfca-809ac56ad7e0\" data-testid=\"conversation-turn-21\" data-scroll-anchor=\"false\" data-turn=\"user\"></article><article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"request-69832276-13dc-8323-972d-6750f56c1dde-7\" data-testid=\"conversation-turn-22\" data-scroll-anchor=\"true\" data-turn=\"assistant\"><div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col grow\"><div data-message-author-role=\"assistant\" data-message-id=\"fd5bd483-248a-43ea-aa23-5a187da65b12\" dir=\"auto\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-model-slug=\"gpt-5-2\"><div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\"><div class=\"markdown prose dark:prose-invert w-full wrap-break-word dark markdown-new-styling\"><p data-start=\"0\" data-end=\"57\"><b><span style=\"font-size: 18px;\">BSc Detailed Syllabus (Semester-Wise) – Panjab University</span></b></p><p data-start=\"59\" data-end=\"288\">Below is a detailed semester-wise syllabus structure generally followed in BSc programs under Panjab University for Non-Medical / Computer Science streams. Exact combinations may vary by college, but core subjects remain similar.</p><p data-start=\"290\" data-end=\"393\"><b><span style=\"font-size: 18px;\">Semester I</span></b><br data-start=\"300\" data-end=\"303\">\r\nStudents study foundation subjects introducing basic scientific and mathematical concepts.</p><p data-start=\"395\" data-end=\"701\">Subjects include:<br>\r\nEnglish (Compulsory)<br data-start=\"433\" data-end=\"436\">\r\nPunjabi / Hindi (Compulsory)<br data-start=\"464\" data-end=\"467\">\r\nMathematics–I (Algebra, Trigonometry, Calculus Basics)<br data-start=\"521\" data-end=\"524\">\r\nPhysics–I (Mechanics, Waves, Properties of Matter)<br data-start=\"574\" data-end=\"577\">\r\nChemistry–I (Atomic Structure, Chemical Bonding, Basic Physical Chemistry)<br data-start=\"651\" data-end=\"654\">\r\nPhysics Practical Lab<br data-start=\"675\" data-end=\"678\">\r\nChemistry Practical Lab</p><p data-start=\"703\" data-end=\"787\"><span style=\"font-size: 18px;\"><b>Semester II</b></span><br data-start=\"714\" data-end=\"717\">\r\nThis semester continues core science subjects with practical learning.</p><p data-start=\"789\" data-end=\"1073\">Subjects include:<br>\r\nEnglish / Communication Skills<br data-start=\"837\" data-end=\"840\">\r\nPunjabi / Hindi<br data-start=\"855\" data-end=\"858\">\r\nMathematics–II (Differential Calculus, Vector Algebra)<br data-start=\"912\" data-end=\"915\">\r\nPhysics–II (Electricity, Magnetism, Optics Basics)<br data-start=\"965\" data-end=\"968\">\r\nChemistry–II (Organic Chemistry Basics, Thermodynamics)<br data-start=\"1023\" data-end=\"1026\">\r\nPhysics Practical Lab<br data-start=\"1047\" data-end=\"1050\">\r\nChemistry Practical Lab</p><p data-start=\"1075\" data-end=\"1160\"><span style=\"font-size: 18px;\"><b>Semester III</b></span><br data-start=\"1087\" data-end=\"1090\">\r\nStudents begin advanced concepts and optional specialization subjects.</p><p data-start=\"1162\" data-end=\"1432\">Subjects include:<br>\r\nMathematics–III (Integral Calculus, Differential Equations)<br data-start=\"1239\" data-end=\"1242\">\r\nPhysics–III (Modern Physics, Electronics Basics)<br data-start=\"1290\" data-end=\"1293\">\r\nChemistry–III or Computer Science–I<br data-start=\"1328\" data-end=\"1331\">\r\nData Structures / Programming Concepts (if CS chosen)<br data-start=\"1384\" data-end=\"1387\">\r\nPractical Labs according to selected subjects</p><p data-start=\"1434\" data-end=\"1515\"><b><span style=\"font-size: 18px;\">Semester IV</span></b><br data-start=\"1445\" data-end=\"1448\">\r\nFocus shifts toward application-based learning and advanced topics.</p><p data-start=\"1517\" data-end=\"1773\">Subjects include:<br>\r\nMathematics–IV (Advanced Calculus, Numerical Methods)<br data-start=\"1588\" data-end=\"1591\">\r\nPhysics–IV (Quantum Physics, Solid State Physics)<br data-start=\"1640\" data-end=\"1643\">\r\nChemistry–IV or Computer Science–II<br data-start=\"1678\" data-end=\"1681\">\r\nDatabase Management Systems / Programming Labs (for CS stream)<br data-start=\"1743\" data-end=\"1746\">\r\nSubject-wise Practical Labs</p><p data-start=\"1775\" data-end=\"1843\"><b><span style=\"font-size: 18px;\">Semester V</span></b><br data-start=\"1785\" data-end=\"1788\">\r\nStudents move into specialization and applied subjects.</p><p data-start=\"1845\" data-end=\"2044\">Subjects include:<br>\r\nAdvanced Mathematics / Computer Science Papers<br data-start=\"1909\" data-end=\"1912\">\r\nOperating Systems / Programming Languages (CS Stream)<br data-start=\"1965\" data-end=\"1968\">\r\nElective Subject according to stream<br data-start=\"2004\" data-end=\"2007\">\r\nPractical Labs and Minor Project Work</p><p data-start=\"2046\" data-end=\"2122\"><b><span style=\"font-size: 18px;\">Semester VI</span></b><br data-start=\"2057\" data-end=\"2060\">\r\nFinal semester focuses on advanced knowledge and project work.</p><p data-start=\"2124\" data-end=\"2300\">Subjects include:<br>\r\nAdvanced Specialization Papers<br data-start=\"2172\" data-end=\"2175\">\r\nComputer Networks / Advanced Programming (CS Stream)<br data-start=\"2227\" data-end=\"2230\">\r\nElective Subject<br data-start=\"2246\" data-end=\"2249\">\r\nMajor Project Work<br data-start=\"2267\" data-end=\"2270\">\r\nPractical Examination and Viva</p><p data-start=\"0\" data-end=\"57\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p data-start=\"2302\" data-end=\"2512\"><b><span style=\"font-size: 18px;\">Practical Components Throughout Course</span></b><br data-start=\"2340\" data-end=\"2343\">\r\nEach semester includes laboratory work and internal practical evaluation. Students perform experiments, programming tasks, and project work depending on chosen subjects.</p></div></div></div></div></div></div></article>', 0, 1, '2026-02-05 10:21:40', '2026-02-05 10:21:40');

