(27, 'PU / Clerical', 'PU / Clerical', 'Government Job Preparation', 'All-round preparation for various government clerical positions with mock interviews.', 'assets/img/home_1/course_thumb_6.jpg', 1, '2025-11-27 03:25:55', '2025-11-27 03:25:55'),
(28, 'IIT - JAM', 'IIT - JAM', 'IIT-JAM Mathematics', 'Advanced mathematics preparation for IIT-JAM exam with problem-solving techniques.', 'assets/img/home_1/course_thumb_1.jpg', 1, '2025-11-27 03:25:55', '2025-11-27 03:25:55'),
