(30, 'IIT - JAM', 'IIT - JAM', 'UGC-NET Preparation', 'Dual preparation for IIT-JAM and UGC-NET with research methodology.', 'assets/img/home_1/course_thumb_3.jpg', 1, '2025-11-27 03:25:55', '2025-11-27 03:25:55'),
(31, 'BCA - BSC', 'BCA - BSC', 'BCA  Fundamentals', 'Programming basics for BCA students including C, C++, and Java.', 'assets/img/home_1/course_thumb_4.jpg', 1, '2025-11-27 03:25:55', '2026-02-24 05:59:30'),
