(2, 'ABOUT INFOMATHS', 'At INFOMATHS, we believe success comes from strong fundamentals, disciplined preparation, and the right mentorship. Our structured curriculum, experienced faculty, and exam-focused approach\r\nensure that every student is guided with clarity and confidence.', 'assets/img/bg/hero_bg_1772111161.jpeg', 'assets/img/hero/hero_img01.png', 'Contact Now', 'contact', 'Contact Us', 'contact.html', 'active', 2, '2025-11-10 12:13:30', '2026-02-26 13:06:01'),
(3, 'Welcome to INFOMATHS', 'Since 1999, INFOMATHS has been a trusted name in Entrance Exams preparation. Our focused mentorship, strategic test series, and deep concept training ensure you are always ahead of the\r\ncompetition.', 'assets/img/bg/hero_bg_1772094366.png', NULL, 'View Faculty', 'faculty.php', 'Apply Now', 'contact', 'active', 1, '2025-11-11 05:41:25', '2026-02-26 13:04:00');

