INSERT INTO `iit_jam_content` (`id`, `section_key`, `title`, `content_value`, `display_order`, `is_active`, `created_at`) VALUES
(1, 'hero_intro', 'Master Your IIT JAM Mathematics Journey', 'Join the league of toppers with India\'s most trusted coaching institute. Expert guidance, comprehensive study material, and proven results since 1999.', 0, 1, '2026-01-09 05:29:30'),
(2, 'about_iit_jam', 'Master Your IIT JAM Mathematics Journey', 'IIT JAM (Joint Admission Test for Masters) is a gateway to prestigious MSc and Integrated PhD programs in top institutions like IITs and IISc. It specifically tests your understanding in subjects like Mathematics, Biotechnology, and Physics. INFOMATHS INDIA provides rigorous coaching with a focus on concept clarity, problem-solving, and previous years\' analysis to help you secure a top rank in IIT JAM Mathematics.', 0, 1, '2026-01-09 05:29:30'),
(3, 'syllabus_header', 'Explore Syllabus of Top IIT JAM Entrance Exams', '', 0, 1, '2026-01-09 05:29:30'),
(4, 'courses_header', 'Check our Courses for IIT JAM', 'Prepare for the most sought-after MSc entrance exams with our specialized coaching programs. We cover a wide range of entrance exams including IIT JAM, TIFR, and NBHM, ensuring you have the best preparation to succeed.', 0, 1, '2026-01-09 05:29:30'),
(5, 'main_content', 'IIT JAM Mathematics (MA)', '<header>\r\n    <h1><span style=\"font-size: 24px;\">IIT JAM Mathematics (MA)</span></h1>\r\n    <p>Complete Guide: Overview, Pattern, Syllabus &amp; Preparation</p>\r\n</header>\r\n\r\n<div class=\"container\">\r\n\r\n<div class=\"section\">\r\n<h2><span style=\"font-size: 24px;\">About IIT JAM Mathematics</span></h2>\r\n<p>\r\nIIT JAM (Joint Admission Test for Masters) is a national-level entrance\r\nexam conducted by IITs for admission into M.Sc. and integrated postgraduate\r\nprograms. The Mathematics (MA) paper is designed for students seeking higher\r\nstudies in mathematics at IITs and IISc.</p></div></div>', 0, 1, '2026-01-09 06:04:11');

