INSERT INTO `iit_jam_page_tabs` (`id`, `tab_title`, `tab_content`, `display_order`, `is_active`, `created_at`) VALUES
(5, 'INFOMATH PROGRAMS', '<p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 24px; background-color: rgb(255, 255, 255);\"><b>Regular Classroom Program</b></span></p><p><span style=\"background-color: rgb(255, 255, 255);\"><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\">Regular Classroom Program for IIT JAM MATHS These are the full length programs for the IIT JAM MATHS Aspirants which are hunting down classroom preparing programs for their exams. These classes are flowed to such an extent that it continues running over the time period of 4-6 month, when classes are coordinated 5-6 days in seven days contributing 4-6 hours step by step. The program is laid out in such a path, to the point that each and every hopeful can understand the topics of subject and gets identical opportunity to learn not like the other coaching institute which overburden the mind of student with extensive instructive modules and due to this they get puzzled with the course. There is a novel method to follow in the Infomaths and that framework is to perceive the student as per their understanding level and help them to crack the examination as per their understanding. We all know that the understanding level of the large number of students isn\'t same and students feel the frenzy in requesting their various issues from time to time so we isolate them as per their understanding level and make segregate bunches for them under the program named as Basic Building Measures (BBM) which has two fragments 1. BBM – Tests: When Student goes to the classes, after 2-3 classes on each point we offer them these tests which is called BBM Test and as demonstrated by the outcome of these tests we isolate them according to their outcome and give them extra thought so not just topper student and also normal student would clear their exams. 2. BBM – Classes: After the BBM Test happen seclude groups of students are made and therefore their examinations do in view of their understanding level. With the objective that student got select and organization would get best result. So it is a win-win situation both for student and our Academy. Infomaths is acclaimed among the student in view of this exceptional approach which is followed in our establishment and other coaching are not enthused about knowing the student and guide them as per their understanding level with the objective that he/she takes the most preferred benefit from our coaching.</span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 18px;\"><b><span style=\"font-size: 24px;\">&nbsp;Weekend Classroom Program</span>&nbsp;</b></span></p><p>JAM MATHS Weekend Classroom Program This program is proposed for the working student and the student who are not prepared to join the reliable classroom program due to any reason. The time period of classes will be 10 to 12 hours on Saturday and Sunday. Student can get notes from the regular classroom student or note down their own particular to keep the pace with others and in this way they have the ability to crack the exams while doing their jobs or go to the colleges or universities. In this manner, this program is useful for them and that student said it is a boon for them in light of the way that as a result of this program they can fulfill their dreams of clearing JRF without leaving their occupations or school classes. This Program is productive for those students who are living near to our coaching centresdue to the fact that they can without being in any kind of pressure join the classes on weekends and prepared to satisfy their fantasy of getting JRF and LS.<span style=\"color: rgb(0, 0, 0); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">JAM MATHS Weekend Classroom Program This program is proposed for the working student and the student who are not prepared to join the reliable classroom program due to any reason. The time period of classes will be 10 to 12 hours on Saturday and Sunday. Student can get notes from the regular classroom student or note down their own particular to keep the pace with others and in this way they have the ability to crack the exams while doing their jobs or go to the colleges or universities. In this manner, this program is useful for them and that student said it is a boon for them in light of the way that as a result of this program they can fulfill their dreams of clearing JRF without leaving their occupations or school classes. This Program is productive for those students who are living near to our coaching centresdue to the fact that they can without being in any kind of pressure join the classes on weekends and prepared to satisfy their fantasy of getting JRF and LS.</span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important;\"><span style=\"font-size: 24px; background-color: rgb(255, 255, 255);\"><b style=\"\">&nbsp;Online Video Lecture&nbsp;</b></span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important;\"><span style=\"background-color: rgb(255, 255, 255);\">JAM MATHS Online Video Lecture Our Distance Learning Program is designed to keep the classroom mood alive, so that students will not be felt boring while watching the lecture on the Video. Since our Video Lectures are directly recorded from regular classroom session not from Studio which will be the main reason that our Video Lectures are alive not like other institutional Video Lectures. Our Video Lectures are Mobile and Desktop compatible, so that you can start learning whenever you want. Students can opt for Video Lectures if they are not able to come to attend our regular classroom session. All the concepts of IIT JAM [MATHS] are completely described in our Video Lectures and you can practice questions on behalf of concepts which are described in our Video Lectures. Our Video Lectures are backed with support for email and Skype ID. You can query your Question or doubts on the Email ID: infomaths32@gmail.com Highlights Of Our Video Lecture Our Video Lectures are Classroom Recorded High Definition Quality Videos High Quality voice Ask your doubts on Email Skype and on Phone Videos are made by Industry Expert.</span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important;\"><span style=\"font-size: 24px; background-color: rgb(255, 255, 255);\"><b>&nbsp;Study Material&nbsp;</b></span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important;\"><span style=\"background-color: rgb(255, 255, 255);\">IIT JAM MATHS Study Material There are many students who are unable to join the regular classroom program for that kind of students we have another option, i.e. Study Material which are designed by our expert panel, they do it in such a way that the student who read it can understand each and every concept which are going to cover in the exams and practice pool of examples and questions so they can easily handle the problems in the exam on that topic in an easy manner. Our panel updates it regularly so that you have an exact understanding of current pattern of the exam and you do not need any kind of book for any topic other than our study material. If you are booking worm then our study material is enough for you to crack the IIT JAM Stats Exam with good rank. Advantage Of Our Study Material The booklet will cover all the necessary topics Design by Industry expert Study Material will be dispatched in single time Pool of Questions Based on the current exam pattern Written in such a manner so that students can easily understand.</span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important;\"><span style=\"font-size: 24px; background-color: rgb(255, 255, 255);\"><b>Test series&nbsp;</b></span></span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important; background-color: rgb(255, 255, 255);\">Infomaths also has test series for IIT Jam Statistics aspirants which are designed by industry leaders. They designed the test series in such a way that you not only practice questions with our test series, but we also assist you, “how to crack the exam”. Our test series is available online so that you have the freedom to conduct the test as per your own comfort and timings. Our 360 degree analysis which is performed online on the basis of your performance will assist you in the preparation of the competitive exams and scale your performance among the competitive students all across the nation. The result of each exam will be declared on the next day of the exam (in the morning session) and will be available for next two days on your panel with full analysis of exams and your performance in the exams. Our online test series are not identical to regular student but it is merged with test series, which are acquired by our regular students of our academy. In this way you can compete with the most serious and generic aspirants which are lacking in other test series available in the market. Hence, students have the facility to check their knowledge among the most competitive environment before the actual exam. Highlights Of Our Test Series Standard Quality Questions Questions are placed as per the weight age of the question in the exam Availability of question on each concept Practicing these questions can help you in understanding the whole concept. Topic or concept wise test and Full length test available. Get Answer and solution post test Analysis of your performance Availability of similar pattern as per the exam Attempt the exam as per your norms.</span></p><p><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; float: none; display: inline !important; background-color: rgb(255, 255, 255);\"><br></span><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px; background-color: rgb(255, 255, 255);\"></span><span style=\"font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 16px;\"></span></p>', 4, 1, '2026-02-03 10:45:23');

