INSERT INTO `mca_entrance_content` (`id`, `content_key`, `title`, `content_value`, `updated_at`) VALUES
(1, 'entrance_info', 'ENTRANCE INFORMATION', '<p>The <strong data-start=\"50\" data-end=\"71\">MCA Entrance Exam</strong> is a competitive test for admission into <strong data-start=\"113\" data-end=\"154\">Master of Computer Applications (MCA)</strong> programs in top colleges and universities in India. Popular MCA entrance exams include <span style=\"background-color: rgb(255, 255, 255);\"><a href=\"https://infomaths.makes360.org/exam-details.php?exam=nimcet-2026\" target=\"_blank\"><font color=\"#0000ff\"><b>NIMCET</b></font></a>&nbsp;</span><strong data-start=\"254\" data-end=\"288\">CUET PG (MCA/Computer Science)</strong>, <strong data-start=\"290\" data-end=\"319\"><a href=\"https://infomaths.makes360.org/exam-details.php?exam=vitmee\" target=\"_blank\"><font color=\"#0000ff\" style=\"background-color: rgb(255, 255, 255);\">VITMEE</font></a> (VIT MCA Entrance)</strong>, and <strong data-start=\"325\" data-end=\"335\"><font color=\"#0000ff\"><a href=\"https://infomaths.makes360.org/exam-details.php?exam=pu-cet-pg\" target=\"_blank\" style=\"\"><font color=\"#0000ff\" style=\"background-color: rgb(255, 255, 255);\">PU MCA</font></a>,</font> IPU CET, <a href=\"https://infomaths.makes360.org/exam-details.php?exam=mah-mca-cet\" target=\"_blank\"><font color=\"#0000ff\">MAH MCA CET</font></a>, WB JECA, TANCET, TS ICET, AP ICET, PGCET, OJEE, CEE(KMCA)</strong><strong data-start=\"325\" data-end=\"335\">&nbsp;</strong>. These exams generally evaluate your skills in <strong data-start=\"383\" data-end=\"420\">Mathematics/Quantitative Aptitude</strong>, <strong data-start=\"422\" data-end=\"443\">Logical Reasoning</strong>, <strong data-start=\"445\" data-end=\"470\">Computer Fundamentals</strong>, and sometimes <strong data-start=\"486\" data-end=\"512\">English/Verbal Ability</strong>.</p>', '2026-02-02 06:36:25'),
(2, 'mca_syllabus', 'MCA Syllabus', '<p data-start=\"898\" data-end=\"919\">Most MCA exams cover:</p>\r\n<ul data-start=\"920\" data-end=\"1320\">\r\n<li data-start=\"920\" data-end=\"1027\">\r\n<p data-start=\"922\" data-end=\"1027\"><strong data-start=\"922\" data-end=\"932\">Maths:</strong> Algebra, Probability, Permutation &amp; Combination, Calculus, Trigonometry, Coordinate Geometry etc.</p>\r\n</li>\r\n<li data-start=\"1028\" data-end=\"1118\">\r\n<p data-start=\"1030\" data-end=\"1118\"><strong data-start=\"1030\" data-end=\"1044\">Reasoning:</strong> Series, Coding-Decoding, Puzzles, Direction, Blood Relations, Syllogism etc.</p>\r\n</li>\r\n<li data-start=\"1119\" data-end=\"1246\">\r\n<p data-start=\"1121\" data-end=\"1246\"><strong data-start=\"1121\" data-end=\"1134\">Computer:</strong> Programming Basics, DBMS, Operating System, Computer Networks, Data Structures (basic), Computer Fundamentals etc.</p>\r\n</li>\r\n<li data-start=\"1247\" data-end=\"1320\">\r\n<p data-start=\"1249\" data-end=\"1320\"><strong data-start=\"1249\" data-end=\"1277\">English (if applicable):</strong> Grammar, Vocabulary, Reading Comprehension etc.</p><p data-start=\"1249\" data-end=\"1320\">The exam pattern differs by conducting authority, but success mainly depends on <strong data-start=\"1437\" data-end=\"1456\">concept clarity</strong>, <strong data-start=\"1458\" data-end=\"1467\">speed</strong>, and <strong data-start=\"1473\" data-end=\"1485\">accuracy</strong>. Build a strong foundation in <b>MCA Entrance Exam</b> with all the subjects with <b>infomaths</b> <b>10 stage classroom masterplan for MCA Entrance Exam </b>, <b>practice <span data-start=\"1558\" data-end=\"1582\">topic-wise questions (level 1,2,3)</span></b>,<b> topic wise tests(T1,T2,T3)</b>,<b>solve <span data-start=\"1590\" data-end=\"1625\">MCA previous year papers (PYQs)(Level 1,2,3)</span></b>and 100+<strong data-start=\"1644\" data-end=\"1662\">MCA mock tests</strong> to improve performance and rank.</p></li></ul>', '2026-01-24 10:01:44');

