(1, 'home', 'Info Maths Online - Premier Maths Coaching & Educational Platform', 'Join Info Maths Online for expert maths coaching and educational resources. Comprehensive study materials, experienced faculty, and proven results for competitive exams.', 'maths coaching, online maths, competitive exams, IIT JEE maths, educational platform, Info Maths Online', 'Info Maths Online - Premier Maths Coaching Platform', 'Expert maths coaching and educational resources with proven success track record.', 'https://infomathsonline.com/assets/img/og-home.jpg', 'https://infomathsonline.com/', 'index,follow', '2025-11-10 03:59:44'),
(2, 'about', 'About Info Maths Online - Leading Maths Coaching Institute', 'Learn about Info Maths Online, a premier coaching institute specializing in mathematics education for competitive examinations and academic excellence.', 'about us, maths coaching institute, faculty, mission, vision, Info Maths Online', 'About Info Maths Online - Excellence in Maths Education', 'Discover our journey, expert faculty, and commitment to excellence in mathematics education.', 'https://infomathsonline.com/assets/img/og-about.jpg', 'https://infomathsonline.com/about.html', 'index,follow', '2025-11-10 03:59:44'),
(3, 'courses', 'Maths Courses - Online Maths Coaching & Competitive Exam Preparation', 'Comprehensive maths courses for competitive exams and academic excellence. Classroom and online coaching with expert faculty at Info Maths Online.', 'maths courses, online maths coaching, competitive exam preparation, classroom coaching, Info Maths Online', 'Maths Courses - Online Coaching & Exam Preparation', 'Complete maths preparation for competitive exams with expert guidance and comprehensive study materials.', 'https://infomathsonline.com/assets/img/og-courses.jpg', 'https://infomathsonline.com/courses.html', 'index,follow', '2025-11-10 03:59:44'),
(4, 'contact', 'Contact Info Maths Online - Get in Touch for Maths Coaching', 'Contact Info Maths Online for admissions, course information, and maths coaching queries. Multiple locations, easy admission process.', 'contact us, admissions, course inquiry, maths coaching, locations, phone, email, Info Maths Online', 'Contact Info Maths Online - Admissions & Inquiries', 'Get in touch for maths course information, admissions, and all your queries about maths coaching.', 'https://infomathsonline.com/assets/img/og-contact.jpg', 'https://infomathsonline.com/contact.html', 'index,follow', '2025-11-10 03:59:44');

