INSERT INTO `testimonials` (`id`, `name`, `content`, `designation`, `created_at`, `image_path`) VALUES
(1, 'NEERAJ TAYAL(MCA 2018-19 BATCH)', 'I have spent 2 years in INFOMATHS which are worth that I have achieved today in my life. Being or BCA study, I was very keen to get into MCA but not sure about the direction that would led me to valuable career. INFOMATHS their faculty and their study material helped me in achieving 7-M_CET, IP, KIIT, NIT, VIT ...', 'MAHCET-7 TH , IP, KIIT, VIT, NIT ALLAHABAD', '2025-11-12 02:01:27', '6913eb7a6fc35.jpeg'),
(2, 'PAYAL JAIN (MCA 2016-17 BATCH)', 'Infomaths is the best institute if you are focusing of MCA. The faculty of Infomaths is really helpful, motivating and is there always to help and guide. I am really thankful to Infomaths for where I am today. Grover sir is the best teacher for Maths. I highly recommend Infomaths. ...', 'PUNE UNIV,IP,IIT BHU-3RD', '2025-11-12 02:07:49', '6913ebf58cdda.jpeg'),
(3, 'RAHUL GUPTA (MCA 2018-19 BATCH)', 'I Rahul Gupta have been a student at Infomaths for 2 years. I attended 2 years regular batch. (i) I owe my results to my parents, teachers and faculty at Infomaths. (ii) The love and support at Infomaths has always been great. (iii) Just keep working hard, work smart, follow your teachers. Keep track of your targets. ...', 'NIT SURATHKAL,IP,HCU,DU,VIT,JNU', '2025-11-12 02:09:06', '6913ec4223aa6.jpeg'),
(4, 'ANANYA', 'The teaching methodology at Infomaths is top-notch. The faculty members are not only knowledgeable but also incredibly approachable. I personally thank Grover sir he break down complex concepts into easy-to-understand modules, making the learning process smooth and efficient. Their emphasis on conceptual clarity and regular practice through mock tests and assignments played a crucial role in my pr ...', 'MAHCET - 100%IL NIT-WARANGAL, VIT-56', '2025-11-12 02:10:55', '6913ecaf6da37.jpg');

